-- Dumping data for table `products`
--

LOCK TABLES `products` WRITE;
/*!40000 ALTER TABLE `products` DISABLE KEYS */;
INSERT INTO `products` VALUES ('064yxb','Quần Bơi Nam Speedo Solid Volley 16 Inch','QUẦN BƠI NAM SPEEDO SOLID VOLLEY 16 INCH\r\nQuần Bơi Nam Speedo Solid Volley 16 Inch sỡ hữu thiết kế hiện đại. Chất liệu ứng dụng công nghệ Speedo 4Way Flex co giãn 4 chiều, cho phép mọi chuyển động trở nên tự nhiên, kết hợp lớp lót tăng cường sự nâng đỡ, giúp bạn tự tin và an toàn trong mỗi lần bơi.\r\n\r\nTHÔNG SỐ\r\nCông nghệ Speedo 4Way Flex vải co giãn bốn chiều, linh hoạt tối ưu theo từng chuyển động.\r\nKhóa cài nút chắc chắn, thuận tiện mặc và tháo ra nhanh chóng.\r\nLót trong Hydro Square Leg hỗ trợ nâng đỡ, bảo vệ và tạo cảm giác thoải mái khi bơi.','37u1i1','h2v6o2','active','2026-01-29 19:36:18','2026-03-16 23:03:38',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('0ab4g6','Giày bóng chuyền Beyono Sky III','','m65tw5','82c21b','active','2025-07-18 08:05:56','2026-03-16 23:03:39',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('0bv62v','Vợt cầu lông Lining Halbertec Motor Pro','Halbertec Motor Pro là phiên bản cải tiến của Halbertec Motor, được thiết kế dành cho các tay vợt trình độ khá, bán chuyên và chuyên nghiệp, những người đòi hỏi độ chính xác cao và cảm giác tinh tế trong từng pha cầu.','50r71o','3371b3','active','2025-02-02 05:54:44','2026-03-18 23:38:21',10,'2026-03-01 00:00:00','2026-12-31 23:59:00'),('0g5mkt','Áo Đá Bóng Nam Nike Chelsea F.C. Academy Pro Dri-Fit Total 90 Pre-Match','ÁO ĐÁ BÓNG NAM NIKE CHELSEA F.C. ACADEMY PRO DRI-FIT TOTAL 90 PRE-MATCH\r\nSau khi đã nắm vững những điều cơ bản, hãy nâng tầm kỹ năng của bạn với Áo Đá Bóng Nam Nike Chelsea F.C. Academy Pro Dri-Fit Total 90 Pre-Match đẳng cấp này. Thiết kế ôm gọn người kết hợp cùng công nghệ thấm hút mồ hôi giúp bạn luôn mát mẻ, tự tin dù thi đấu dưới áp lực cao. Lấy cảm hứng từ bộ sưu tập Total 90 lừng danh những năm 2000, sản phẩm mang lại nét phá cách với các đường cong độc đáo, thiết kế bất đối xứng cùng chất liệu pha trộn, thổi bùng sức sống mới cho cả thế hệ cầu thủ và người hâm mộ hôm nay.\r\n\r\nTHÔNG SỐ\r\nChất liệu 100% polyester nhẹ, bền, co giãn tốt.\r\nThiết kế ôm body giúp tôn dáng, vận động linh hoạt.\r\nCông nghệ thấm hút mồ hôi giữ cơ thể luôn khô ráo khi vận động mạnh.\r\nGiặt máy tiện lợi, tiết kiệm thời gian chăm sóc sản phẩm.','sd2dby','962d78','active','2025-10-09 19:55:12','2026-03-16 23:03:40',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('0pywzz','Quần Yếm Đạp Xe Men Elite Bib Cargo Short','Men Elite Bib Cargo Short – Quần yếm đạp xe êm ái, thoáng khí cho mọi chuyến ride\r\nMen Elite Bib Cargo Short là quần yếm đạp xe cao cấp, thiết kế cho Road, Gravel và Tour dài ngày. Với chất liệu co giãn, nhẹ, bền bỉ và đệm công thái học, giúp đạp xe thoải mái, hiệu suất cao, giảm mỏi hông và đùi ngay cả khi đạp nhiều giờ.\r\n\r\n \r\n\r\nĐặc điểm nổi bật\r\nĐai yếm liền mảnh lưới thoáng khí, ôm vừa vai, giảm áp lực.\r\nVải co giãn đa chiều giữ form lâu dài, nhẹ và bền bỉ.\r\nĐệm lót công thái học, hỗ trợ ride dài êm ái.\r\n2 túi hông tiện dụng đựng gel, điện thoại, đồ cá nhân.\r\nChi tiết phản quang sau chân tăng an toàn khi ánh sáng yếu.','z6x5ni','czsd09','active','2025-01-30 17:44:51','2026-03-16 23:03:41',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('0th8uo','Banh Bóng Rổ Spalding Vba Team Hanoi Buffaloes Outdoor','BANH BÓNG RỔ UNISEX SPALDING VBA TEAM HANOI BUFFALOES OUTDOOR\r\nTHÔNG SỐ\r\nChất liệu: Tổng hợp\r\nBề mặt cao su bền bỉ\r\nLý tưởng khi chơi ngoài trời','wwayj1','q18zwp','active','2025-01-03 18:24:02','2026-03-16 23:03:41',5,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('0txnzw','Giày Chạy Bộ Unisex Mizuno Wave Rebellion Pro 2','GIÀY CHẠY BỘ UNISEX MIZUNO WAVE REBELLION PRO 2\r\nLập kỷ lục chạy marathon dưới 2.5 giờ và đạt được thành tích cá nhân tốt nhất Giày Chạy Bộ Unisex Mizuno Wave Rebellion Pro 2! Giày được trang bị nhiều tính năng giúp tăng tốc độ. Trong đó có SMOOTH SPEED ASSIST - giúp bạn đạt được dáng chạy lý tưởng. Đế G3 mang lại độ bám tuyệt vời với trọng lượng nhẹ. MIZUNO ENERZY LITE ở phần dưới đế giữa hỗ trợ chạy nhanh, trong khi MIZUNO ENERZY LITE+ ở phần trên đế giữa tăng cường độ mềm mại và trọng lượng nhẹ.\r\n\r\nTHÔNG SỐ\r\nSMOOTH SPEED ASSIST: Hỗ trợ người chạy duy trì dáng chạy lý tưởng theo quan điểm của Mizuno, từ lúc bắt đầu cho đến khi về đích.\r\nMIZUNO ENERZY LITE: Vật liệu mềm mại này cung cấp khả năng hoàn trả năng lượng cao, được sử dụng ở phần dưới đế giữa để hỗ trợ chạy tốc độ.\r\nMIZUNO ENERZY LITE+: So với MIZUNO ENERZY LITE, vật liệu này theo đuổi độ mềm mại tốt hơn và trọng lượng nhẹ hơn, được sử dụng ở phần trên của đế giữa để hỗ trợ chạy tốc độ.\r\nMIZUNO WAVE: Tăng cường độ ổn định khi chạy tốc độ mà không làm giảm đi sự êm ái. Tấm WAVE PLATE kéo dài đến phần trước bàn chân cũng giúp tối ưu hóa hiệu quả của SMOOTH SPEED ASSIST.\r\nG3 sole: Đế ngoài nhẹ và có độ bám cao hỗ trợ cho việc chạy tốc độ.','lskyuc','69f937','active','2025-06-05 02:21:40','2026-03-16 23:03:40',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('0xls9k','Phao Kẹp Chân Người Lớn Speedo Elite Pullbuoy','PHAO KẸP CHÂN NGƯỜI LỚN SPEEDO ELITE PULLBUOY AU BLUE / ORANGE \r\nĐược thiết kế để cô lập phần trên cơ thể, phao kẹp chân tăng thêm độ nổi giữa hai chân của bạn để bạn có thể tinh chỉnh lực kéo cánh tay của mình và cải thiện kỹ thuật quạt tay. Chiếc phao khiến phần chân / thân dưới trở nên nhẹ hơn, giúp bạn có thể tập trung lực vào cánh tay và vai để luyện tập tốt hơn. \r\n\r\nTHÔNG SỐ\r\nLý tưởng để học các bài tập mới và tập luyện kỹ thuật bơi\r\nĐược sử dụng để cô lập các cơ ở phần trên cơ thể của bạn\r\nTăng sức mạnh của cánh tay và vai\r\nChất liệu: EVA','3myvj5','h2v6o2','active','2025-02-23 03:44:09','2026-03-16 23:03:43',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('13j9fn','Banh Bóng Đá Puma Futsal 3 Ms','','rm0g8a','a8073f','active','2024-12-07 06:12:34','2026-03-16 23:03:43',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('15xhtg','Áo Đạp Xe Tay Dài Women Elite Long Sleeve','Áo đạp xe tay dài Nữ Fastr Women Elite – Mát hơn, nhẹ hơn, thoải mái suốt ngày dài\r\nFastr Women Elite Long Sleeve là áo jersey dài tay dành cho nữ, thiết kế cho road, gravel và touring với khả năng thoáng khí, co giãn vượt trội và cảm giác thoải mái khi đạp đường dài. Nhờ chất liệu thấm hút nhanh và thân áo dài hơn, sản phẩm giúp bạn tự tin chinh phục mọi cung đường trong nhiều điều kiện thời tiết.\r\n\r\n \r\n\r\nĐặc điểm nổi bật\r\nChất liệu co giãn cao giúp tản nhiệt, thoát ẩm nhanh, giữ cơ thể khô thoáng.\r\nThiết kế dài tay bảo vệ da, phù hợp đi nắng & gió.\r\nThân áo dài hơn cho cảm giác thoải mái khi đạp đường dài.\r\nKhóa kéo YKK lock-zip chắc chắn, không tuột khi vận động mạnh.\r\n3 túi sau mở rộng + chống xệ giữ đồ ổn định, an toàn khi đạp.\r\nChi tiết phản quang tăng an toàn khi chạy sáng sớm hoặc chiều tối.','4c7anp','czsd09','active','2024-11-10 16:50:05','2026-03-16 23:03:37',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('18g85q','Giày bóng chuyền Beyono Limit V2','','m65tw5','82c21b','active','2025-05-25 04:27:07','2026-03-16 23:03:34',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('1edssv','Vợt Tennis Wilson Clash 100L V3 Desert','Vợt Tennis Wilson Clash 100L V3 Desert \r\n\r\nđánh dấu giai đoạn phát triển mới của dòng Ultra, kết hợp thiết kế táo bạo với hiệu năng mang tính thay đổi cuộc chơi. Với cấu trúc được cải tiến và hình học khung vợt được tinh chỉnh, phiên bản này mang đến trải nghiệm thi đấu hoàn toàn mới so với các thế hệ tiền nhiệm.\r\n\r\n \r\n\r\nCông nghệ SI3D Comfort Power (được cấp bằng sáng chế) tối ưu độ linh hoạt và độ ổn định để mang lại sức mạnh tối đa cùng sự êm ái, giúp mọi điểm tiếp xúc trên mặt vợt đều có cảm giác như điểm ngọt (sweet spot).\r\n\r\nHit Stabilizer cải thiện độ ổn định khi đánh lệch tâm bằng cách tăng quán tính của vợt mà không làm thay đổi điểm cân bằng hoặc thêm trọng lượng, tạo nên phiên bản Clash “dễ chơi” và trợ lực tốt nhất từ trước đến nay.\r\n\r\nHình học khung được tinh chỉnh và làm mượt tại các vùng uốn cong chính, bổ sung thêm độ mềm mại và khả năng trợ lực (forgiveness).\r\n\r\nHệ thống Click & Go Bumper giúp thay thế dễ dàng, nhanh chóng và tiện lợi.\r\n\r\nLogo Clash dập nổi mang tính biểu tượng, được tinh chỉnh để tạo diện mạo cân đối và hiện đại hơn.\r\n\r\nAgiplast sử dụng bumper, grommet và nắp chuôi có nguồn gốc thực vật, góp phần giảm tác động đến môi trường.\r\n\r\nPhối màu Graphite Black thể hiện rõ tinh thần hiệu năng và sự thoải mái.\r\n\r\nUltra 100L V5 là lựa chọn lý tưởng cho những tay vợt muốn nâng tầm hiệu suất với sự cân bằng hoàn hảo giữa power, spin và độ ổn định.\r\n\r\nMặt vợt: 100 in² / 645 cm²\r\n\r\nĐộ dày khung: 24.0 FB\r\n\r\nChiều dài: 27 in / 68 cm\r\n\r\nTrọng lượng chưa căng dây: 280g \r\n\r\nMật độ dây: 16 × 19\r\n\r\nCỡ cán: Cán số 2 \r\n\r\nĐiểm cân bằng (chưa căng dây): \r\n\r\nNhẹ đầu 2 điểm \r\n\r\nĐộ dày khung vợt: 22 mm','p0d6db','p3c68s','active','2025-11-21 09:33:09','2026-03-16 23:03:43',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('1f945u','Áo Thun Nam Under Armour Fire Ice','ÁO THUN NAM UNDER ARMOUR FIRE ICE\r\nHơn cả một chiếc áo thun họa tiết, Áo Thun Nam Under Armour Fire Ice man đến cho bạn sự thoải mái suốt ngày dài - nhờ chất liệu pha cotton mềm mại\r\n\r\nTHÔNG SỐ\r\nChất liệu vải pha cotton mềm mại, mang đến sự thoải mái suốt cả ngày\r\nCổ áo được bo viền\r\n60% Cotton/40% Polyester','3pxej5','1791f2','active','2025-12-25 01:54:27','2026-03-16 23:03:42',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('1qhlow','Quần Bơi Bé Trai Nike Swim Tossed Block 7 Inch Volley','QUẦN BƠI BÉ TRAI NIKE SWIM TOSSED BLOCK 7 INCH VOLLEY\r\nHãy để bé trai tự tin vui chơi dưới nước với Quần Bơi Bé Trai Nike Swim Tossed Block 7 Inch Volley. Thiết kế trẻ trung cùng họa tiết Nike nổi bật không chỉ mang đến phong cách thời thượng mà còn giúp bé thoải mái vận động. Chất liệu chống nước cao cấp, kết hợp lớp lót thân thiện môi trường, mang lại trải nghiệm bơi lội an toàn và dễ chịu cho bé trong suốt mùa hè.\r\n\r\nTHÔNG SỐ\r\nVải thân quần 100% polyester bền nhẹ, nhanh khô.\r\nLớp lót bên trong kết hợp 50% polyester tái chế, thân thiện môi trường.\r\nChất liệu chống nước giúp bé thỏa thích vùng vẫy mà không lo ướt át khó chịu.\r\nĐộ dài 7 inch che phủ an toàn, giúp bé thoải mái vận động.\r\nHọa tiết Nike toàn thân nổi bật, sành điệu và cá tính.','37u1i1','962d78','active','2024-10-28 02:45:07','2026-03-16 23:03:41',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('1yyqwg','Áo Đá Bóng Nam Puma Manchester City Fc Replica Sân Khách 25/26','ÁO ĐÁ BÓNG NAM PUMA MANCHESTER CITY FC REPLICA SÂN KHÁCH 25/26\r\nTái hiện tinh thần huyền thoại của màn lội ngược dòng năm 1999, Áo Đá Bóng Nam Puma Manchester City FC Replica Sân Khách 25/26 sở hữu thiết kế đen toàn tập mạnh mẽ và cá tính. Chất liệu cao cấp kết hợp công nghệ dryCELL giúp thấm hút mồ hôi hiệu quả, mang lại cảm giác mát mẻ và thoải mái khi thi đấu hay cổ vũ. Một lựa chọn lý tưởng để thể hiện niềm tự hào cùng đội bóng yêu thích.\r\n\r\nTHÔNG SỐ\r\nChất liệu: 80% polyester, 10% cotton, 7% nylon, 3% spandex\r\nKhô nhanh: Công nghệ dryCELL giúp thấm hút mồ hôi, giữ cơ thể luôn khô thoáng\r\nChống gió: Thiết kế phù hợp với thời tiết se lạnh, giữ ấm khi vận động ngoài trời\r\nChống tĩnh điện: Giảm tình trạng bám dính do tĩnh điện, cho cảm giác dễ chịu khi mặc\r\nThoáng khí: Chất liệu có khả năng lưu thông không khí, mang lại cảm giác mát mẻ','sd2dby','a8073f','active','2025-08-09 15:35:52','2026-03-16 23:03:40',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('1zl7ec','Áo Thun Nam Nike Stride Dri-Fit Adv','ÁO THUN NAM NIKE STRIDE DRI-FIT ADV\r\nDựa trên những phản hồi từ các vận động viên như bạn, chúng tôi đã tối ưu hóa các tính năng để làm mới bộ sưu tập Stride essentials. Chiếc áo nhẹ nhàng này được thiết kế đặc biệt để giảm cọ xát và cải thiện khả năng thoáng khí, giúp bạn duy trì sự tập trung mà không lo lắng về sự khó chịu do chất liệu mang lại.\r\n\r\nTHÔNG SỐ\r\nTay áo raglan giúp giảm ma sát dưới cánh tay và tạo sự linh hoạt trong chuyển động.\r\nThiết kế rộng rãi, độ dài đủ để che phủ hoàn hảo, an tâm trong mọi chuyển động\r\nCông nghệ Nike Dri-FIT ADV kết hợp vải thấm hút tốt giúp bạn luôn khô ráo và thoải mái.\r\nHọa tiết phản quang trên tay áo.\r\nLogo Swoosh phản quang ở bên trái ngực.\r\nChất liệu: 100% polyester.\r\nCó thể giặt máy.\r\nMã sản phẩm: HV5204-010','cxo8ft','962d78','active','2025-09-27 12:04:07','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('2gpi54','Joola Pro Barrier Flex Short (3 Pack)','Mô hình rào chắn JOOLA Pro Barrier Flex Short là giải pháp tuyệt vời để tùy chỉnh sân pickleball của bạn và mang lại hiệu suất tối ưu.\r\n\r\nRào chắn giúp giữ cho trận đấu không bị gián đoạn bằng cách ngăn chặn bóng lăn sang sân bên cạnh.\r\n\r\nVới thiết kế gồm đế nhựa và lớp phủ vải, việc lắp ráp rất dễ dàng.\r\n\r\nBộ sản phẩm ba rào chắn này không chỉ chức năng mà còn tạo vẻ chuyên nghiệp với logo JOOLA nổi bật.\r\n\r\nKích thước mỗi rào chắn là dài 4,6 feet và cao 1,64 feet.','gfwht4','0lifzq','active','2025-09-21 21:24:14','2026-03-16 23:03:43',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('2h5f1k','Kính Bơi Cận Thị Người Lớn Speedo Vanquisher 3.0 Optical','KÍNH BƠI CẬN THỊ NGƯỜI LỚN SPEEDO VANQUISHER 3.0 OPTICAL\r\nKính Bơi Cận Thị Người Lớn Speedo Vanquisher 3.0 Optical là lựa chọn số một cho cả luyện tập và thi đấu, nay đã có cho các mức độ cận từ 0 đến 8 độ. Kiểu dáng khí động học giúp bạn bứt phá trên đường đua - với tầm nhìn rộng hơn 14% so với phiên bản trước. Dây đeo cải tiến chắc chắn, không xô lệch. Công nghệ viền đệm mới mang lại sự êm ái tối đa, phù hợp cho cả luyện tập dài hạn lẫn những cuộc thi lớn. Cầu nối mũi điều chỉnh tiện lợi, phù hợp với mọi khuôn mặt. Kính Vanquisher 3.0 chuẩn thi đấu được công nhận bởi World Aquatics.\r\n\r\nTHÔNG SỐ\r\nỐng kính cận thị đa dạng độ, đáp ứng mọi nhu cầu thị lực\r\nThiết kế ống kính 360° cho góc nhìn rộng hơn 14%\r\nKiểu dáng khí động học giảm lực cản tối ưu khi bơi\r\nViền đệm êm ái, ôm khít không gây khó chịu dài lâu\r\nCầu nối mũi trượt và khóa dễ dàng điều chỉnh trên mọi khuôn mặt\r\nChống mờ hiệu quả, luôn đảm bảo tầm nhìn rõ nét\r\nChống tia UV 100%, bảo vệ mắt khỏi tác hại của ánh nắng\r\nKhông chứa latex, an toàn cho làn da nhạy cảm\r\nKhông chứa PVC, thân thiện với sức khỏe\r\nĐược World Aquatics phê duyệt cho thi đấu chuyên nghiệp','7iai8b',NULL,'active','2025-09-09 14:32:08','2026-03-16 23:03:36',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('31xa1f','Mũ Lưỡi Trai Nam Under Armour Iso-Chill Launch Snapback','MŨ LƯỠI TRAI NAM UNDER ARMOUR ISO-CHILL LAUNCH SNAPBACK\r\nUnder Armour Iso-Chill Launch Snapback không chỉ đơn thuần là một chiếc mũ che nắng – mà là trang bị không thể thiếu của dân chạy bộ. Mũ sử dụng chất liệu dệt siêu nhẹ và bền, kết hợp với panel lưới thoáng khí dạng trucker giúp lưu thông không khí tối đa. Bên trong là băng đô Iso-Chill, công nghệ làm mát độc quyền giúp tản nhiệt nhanh, mang lại cảm giác mát lạnh ngay khi đội. Phần lưỡi trai foam phẳng giữ phom cứng cáp, hiện đại. Mũ có khóa snapback dễ điều chỉnh và các chi tiết phản quang, lý tưởng cho các buổi chạy sáng sớm hoặc chiều tối. Một chiếc mũ runner nào cũng nên sở hữu!\r\n\r\nTHÔNG SỐ\r\nVải dệt siêu nhẹ, bền chắc phù hợp chạy bộ\r\nLưới trucker bên hông tăng cường độ thoáng khí\r\nLưỡi trai foam phẳng giữ phom tốt, tạo kiểu dáng hiện đại\r\nBăng đô Iso-Chill tản nhiệt nhanh, cho cảm giác mát lạnh\r\nKhóa gài snapback điều chỉnh dễ dàng, vừa vặn\r\nChi tiết phản quang tăng khả năng nhận diện khi thiếu sáng\r\nChất liệu: 100% Polyester','j5up22','1791f2','active','2025-02-27 16:01:14','2026-03-16 23:03:43',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('3cjwpi','Vợt Pickleball JOOLA Perseus Pro V Ben Johns Blaze 16Mm','VỢT PICKLEBALL JOOLA PERSEUS PRO V BEN JOHNS BLAZE 16MM\r\nKhám phá Vợt Pickleball JOOLA Perseus Pro V Ben Johns Blaze 16Mm – lựa chọn hàng đầu với thiết kế bo tròn góc và mặt vợt kéo dài, giúp duy trì điểm ngọt hoàn hảo và mở rộng tầm với, dễ dàng kiểm soát những cú đánh sâu hoặc vát góc ngay sát lưới mà không cần di chuyển thêm. Đây là cây vợt lý tưởng cho những ai yêu thích phong cách tấn công, mong muốn giữ độ ổn định trong các pha bóng tốc độ cao và cũng chính là cây vợt được vận động viên Ben Johns tin dùng. Thiết kế Blaze Red năng động, hai tuỳ chọn lõi dày 16mm (nặng 230g) hoặc 14mm (nặng 224g), đáp ứng mọi chiến thuật thi đấu trên sân.\r\n\r\nTHÔNG SỐ\r\nMặt vợt sợi carbon nhám cho độ xoáy bóng vượt trội và kiểm soát chính xác.\r\nTuỳ chọn lõi 16mm hoặc 14mm gia tăng sức mạnh và sự ổn định từng cú đánh.\r\nĐạt chuẩn UPA-A và USAP, sử dụng thi đấu chuyên nghiệp.\r\nThiết kế cán dài 5.5 inch, vòng báng 4.125 hoặc 4.250 inch phù hợp nhiều cỡ tay.\r\nKích thước mặt vợt chuẩn chuyên nghiệp: dài 16.5 inch, rộng 7.5 inch dễ kiểm soát.\r\nSử dụng công nghệ Feel-Tec êm ái, giảm chấn rung hiệu quả.','lsg423','0lifzq','active','2025-09-24 10:02:56','2026-03-16 23:03:43',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('3jh2if','Vớ Dài Beyono Sock','','y5tp3j','82c21b','active','2025-02-17 03:13:26','2026-03-16 23:03:36',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('3xn42w','Giày Bóng Rổ Nam Nike Jordan Cmft Era','GIÀY BÓNG RỔ NAM NIKE JORDAN CMFT ERA\r\nKhám phá Giày Bóng Rổ Nam Nike Jordan Cmft Era – thiết kế thời thượng lấy cảm hứng từ những huyền thoại AJ1 và AJ6, mang tới vẻ ngoài năng động và phong cách. Đôi giày này giúp bạn tự tin sải bước từ sáng tới tối mà vẫn luôn cảm thấy dễ chịu nhờ chất liệu thoáng khí và đệm êm ái.\r\n\r\nTHÔNG SỐ\r\nBề mặt phối da thật và da tổng hợp tăng độ bền và giữ form chuẩn lâu dài.\r\nVải dệt thoáng khí, trọng lượng nhẹ\r\nĐệm mút êm nhẹ dưới chân mang đến cảm giác êm ái từng bước di chuyển.\r\nĐế ngoài cao su bám chắc, tăng độ ma sát bền bỉ trên mọi địa hình.\r\nDễ dàng xỏ vào với tab kéo phía gót giày tiện lợi.\r\nLỗ thoáng khí bên hông giúp đôi chân luôn khô thoáng.','xijocy','962d78','active','2024-10-29 23:17:26','2026-03-16 23:03:39',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('4dgot8','Giày Bóng Rổ Unisex Under Armour Curry 11 \'Mouthguard\'','GIÀY BÓNG RỔ UNISEX UNDER ARMOUR CURRY 11 \'MOUTHGUARD\'\r\nGiày Bóng Rổ Unisex Under Armour Curry 11 \'Mouthguard\' là sự lựa chọn hoàn hảo cho các bạn trẻ yêu thích bóng rổ, mong muốn cải thiện kỹ năng và chinh phục những thử thách trên sân đấu. Sở hữu công nghệ tiên tiến, thiết kế ấn tượng, sản phẩm xứng đáng trở thành người bạn đồng hành đáng tin cậy, cùng bạn bứt phá mọi giới hạn và chạm tới đỉnh cao phong độ.\r\nTHÔNG SỐ\r\nCông nghệ UA IntelliKnit: Thoáng khí, ôm vừa vặn, co giãn đa chiều\r\nĐế giữa UA Flow: Êm ái, siêu nhẹ, độ bám sân tuyệt vời\r\nLót giày được định hình sẵn: Thoải mái, giảm chấn thương\r\nKhung bàn chân Pebax®: Linh hoạt, hỗ trợ di chuyển\r\nLõi nhựa TPU được tích hợp bên trong giữa thân giày: Cố định vòm, đảm bảo ổn định\r\nMũ giày dệt kim: Ôm sát, an toàn\r\nĐế ngoài UA Flow: Bền bỉ, cảm nhận sân đấu tốt','xijocy','1791f2','active','2025-12-31 09:59:00','2026-03-16 23:03:37',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('4ea7pn','Banh Bóng Rổ Spalding Trend & Marble Series','BANH BÓNG RỔ UNISEX SPALDING TREND & MARBLE SERIES\r\n\r\nĐược tạo ra cho những người chơi muốn tạo nên sân chơi riêng của mình. Ngoài lớp vỏ bền ngoài trời và các logo dập nổi, không có hai quả bóng nào trong bộ sưu tập giống nhau.\r\n\r\nTHÔNG SỐ\r\n\r\nĐược thiết kế để chơi ngoài trời\r\nChất liệu: vỏ cao su bền','wwayj1','q18zwp','active','2025-10-14 08:32:59','2026-03-16 23:03:42',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('4eouqs','Quần Bó Thể Thao Nữ Adidas Own The Run','QUẦN BÓ THỂ THAO NỮ ADIDAS OWN THE RUN\r\nChiếc quần legging chạy bộ trơn láng và ôm body đến từ adidas này giúp bạn luôn khô ráo và tập trung trên từng cây số. Công nghệ AEROREADY kiểm soát ẩm, cùng chất vải Adiflex cho cảm giác mát lạnh trên da kể cả khi bạn tăng tốc. Cạp cao đảm bảo độ ôm chắc chắn, tránh tình trạng xô lệch gây xao lãng. Đựng chìa khóa, thẻ và điện thoại vào các túi hai bên và tự tin sải bước. Sản phẩm này làm từ tối thiểu 70% chất liệu tái chế. Bằng cách tái sử dụng các chất liệu đã được tạo ra, chúng tôi góp phần giảm thiểu lãng phí và hạn chế phụ thuộc vào các nguồn tài nguyên hữu hạn, cũng như giảm phát thải từ các sản phẩm mà chúng tôi sản xuất.\r\n\r\nTHÔNG SỐ\r\nDáng tight fit\r\nCạp chun có dây rút\r\n85% polyester (tái chế), 15% elastane\r\nChất vải Adiflex trơn láng sử dụng công nghệ LYCRA® ADAPTIV™\r\nAEROREADY\r\nCạp cao\r\nCác chi tiết phản quang\r\nCác túi hai bên','m40hn6','4e177a','active','2025-12-26 05:04:14','2026-03-16 23:03:36',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('4joycl','Giày Bóng Rổ Unisex Under Armour Curry 2','GIÀY BÓNG RỔ UNISEX UNDER ARMOUR CURRY 2: HUYỀN THOẠI TRỞ LẠI\r\nChinh phục sân đấu với Giày Bóng Rổ Unisex Under Armour Curry 2! Đôi giày Curry 2 đã trở lại với phiên bản tái phát hành đặc biệt, số lượng giới hạn! Sản phẩm được trang bị đệm chống sốc, mũ giày UA Speedform ôm sát chân - Tăng cường sức mạnh cho từng bước di chuyển.\r\n\r\nTHÔNG SỐ\r\nPhần trên nhẹ và thoáng khí, tạo cảm giác di chuyển nhanh hơn\r\nKẹp gót bên ngoài để tăng độ ôm sát\r\nĐế giữa Charged Cushioning® sử dụng foam ép nén - phản hồi nhanh, tạo những cú bật bùng nổ\r\nCác thanh gót giữa bàn chân cung cấp sự ổn định chắc chắn\r\nĐế ngoài bền bỉ với hoa văn xương cá - bám sàn, chống trượt','xijocy','1791f2','active','2025-10-15 23:52:15','2026-03-16 23:03:39',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('4u9tx2','Vợt cầu lông Yonex Astrox 70','Yonex Astrox 70 là một cây vợt nhẹ với trọng lượng 83g ở mức 4U, điểm cân bằng ở khoảng 295mm cùng thân vợt dẻo sẽ dành cho các lông thủ ưa thích lối chơi công thủ toàn diện.','50r71o','7d1050','active','2024-10-07 04:23:18','2026-03-16 23:03:41',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('4wl756','Giày cầu lông Yonex Cascade Drive 3 Đen Xám','Yonex Cascade Drive 3 Đen xám mang lại sự mạnh mẽ, sang trọng và dễ phối đồ, thích hợp với những người chơi muốn vẻ ngoài lịch lãm và chuyên nghiệp. Với bảng màu này, Cascade Drive 3 vừa đáp ứng nhu cầu thẩm mỹ vừa thể hiện cá tính riêng của từng người chơi.','ayirn2','7d1050','active','2024-10-17 17:01:21','2026-03-16 23:03:41',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('5310kk','Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Puma Ultra 6 Play Tt','GIÀY ĐÁ BÓNG SÂN CỎ NHÂN TẠO NAM PUMA ULTRA 6 PLAY TT\r\nBứt phá tốc độ cùng Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Puma Ultra 6 Play Tt! Phần thân giày chất liệu lưới kỹ thuật hiện đại, nhẹ và thoáng khí. Khung hỗ trợ siêu nhẹ giúp tăng độ ổn định khi di chuyển nhanh, đế thấp đa đinh bám vững trên mặt sân cỏ nhân tạo lẫn sân tự nhiên cứng. Tự tin thể hiện lối chơi máu lửa trên mọi mặt sân!\r\n\r\nTHÔNG SỐ\r\nThân giày chứa ít nhất 50% vật liệu tái chế, đế ngoài chứa ít nhất 10% vật liệu tái chế\r\nKhung hỗ trợ dập nổi tăng độ ổn định cho phần thân trên siêu nhẹ\r\nMũi giày bo tròn\r\nKiểu buộc dây truyền thống\r\nĐế phẳng, không gót\r\nLót trong nhẹ, tháo rời, tích hợp công nghệ NanoGrip giảm trượt\r\nĐế ngoài thấp, đa đinh chuyên dụng\r\nPhù hợp sân cỏ nhân tạo (2G) và sân tự nhiên cứng\r\nThân giày nhẹ, linh hoạt\r\nLót trong: 100% vải dệt\r\nĐế ngoài: 100% cao su\r\nThân giày: 97,65% chất liệu tổng hợp, 2,35% vải dệt\r\nLớp lót: 100% vải dệt','eqj3j1','a8073f','active','2025-08-25 00:24:37','2026-03-16 23:03:35',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('57871p','Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Mizuno Morelia Neo Iv Pro As','GIÀY ĐÁ BÓNG SÂN CỎ NHÂN TẠO NAM MIZUNO MORELIA NEO IV PRO AS\r\nTrải nghiệm sự thoải mái nhẹ nhàng và linh hoạt vượt trội với Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Mizuno Morelia Neo Iv Pro As. Phần thân trên bằng da Kangooru (K-Leather) cao cấp kết hợp lót giày ZERO GLIDE giúp tăng độ bám vượt trội so với lót thông thường, mang lại cảm giác chắc chắn và tự tin. Đế mới với lớp đệm toàn bộ chiều dài, hiết kế tối ưu hóa độ bám và độ bền mà vẫn giữ được cảm giác chân thật tự nhiên, giúp các cầu thủ thỏa sức thể hiện trên sân cỏ.\r\n\r\nTHÔNG SỐ\r\nThân giày sử dụng da chuột túi K-Leather cao cấp, mềm mại và bền bỉ.\r\nHệ thống xỏ dây mới giúp giảm nếp gấp, ôm sát bàn chân khi di chuyển.\r\nĐế giày mới tăng cường khả năng bám và chống mài mòn hiệu quả.\r\nLót giày ZERO GLIDE cho độ bám tốt hơn gấp 1,5 lần so với lót thông thường.\r\nHơn 90% vật liệu da tổng hợp và lót giày làm từ chất liệu tái chế thân thiện môi trường.\r\nĐệm giữa MIZUNO ENERZY (FOAM) mang lại sự êm ái và hoàn trả năng lượng vượt trội.\r\nLót trong MIZUNO ENERZY XP tăng cảm giác thoải mái suốt quá trình vận động.\r\nTrọng lượng: 255g','eqj3j1','69f937','active','2025-05-13 03:04:26','2026-03-16 23:03:35',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('5fa1gd','Quần Ngắn Thể Thao Nam Nike Academy Dri-Fit','QUẦN NGẮN THỂ THAO NAM NIKE ACADEMY DRI-FIT\r\nThoải mái và phong cách với Quần Ngắn Thể Thao Nam Nike Academy Dri-Fit! Công nghệ thấm hút mồ hôi cùng các mảng lưới thoáng khí giúp bạn luôn mát mẻ, tự tin vận động hết mình trong mọi buổi tập luyện.\r\n\r\nTHÔNG SỐ\r\nMảng lưới hai bên và lai quần tăng cường thoáng khí, hạn chế tích tụ nhiệt.\r\nTúi có khóa kéo lót lưới an toàn đựng vật dụng nhỏ khi vận động.\r\nLưng thun kết hợp dây rút dễ dàng điều chỉnh, vừa vặn mọi dáng người.\r\nChất liệu 100% polyester bền đẹp, khô nhanh, dễ giặt.\r\nDáng slim-fit tôn dáng, phù hợp nhiều phong cách luyện tập.','yrgs2k','962d78','active','2025-07-24 11:11:29','2026-03-16 23:03:41',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('5lk02l','Găng Tay Adidas Predator Training Goalkeeper','GĂNG TAY ADIDAS PREDATOR TRAINING GOALKEEPER\r\nGăng Tay Adidas Predator Training Goalkeeper giúp bạn làm chủ sân đấu với hiệu suất tối đa. Được thiết kế để mang lại sự vừa vặn với thiết kế cổ tay co giãn giúp duy trì sự ổn định để bạn thêm tự tin xử lý bóng. Lòng bàn tay Soft Grip bằng latex có phần đệm giúp tăng cường độ bám và độ bền trong mọi điều kiện thời tiết.\r\n\r\nTHÔNG SỐ\r\nĐảm bảo sự vừa vặn thoải mái\r\nLòng bàn tay có đệm mút latex Soft Grip\r\nThiết kế cổ tay co giãn, tăng cường sự ổn định và thoải mái','u8jlr1','4e177a','active','2025-12-26 21:27:03','2026-03-16 23:03:34',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('5n6gkl','Áo Thun Nam Nike Jordan Sport Dri-Fit','ÁO THUN NAM NIKE JORDAN SPORT DRI-FIT\r\nChiếc Áo Thun Nam Nike Jordan Sport Dri-Fit chính là sự lựa chọn hoàn hảo cho các hoạt động hằng ngày hoặc những buổi luyện tập thể thao nhẹ nhàng. Nhờ ứng dụng công nghệ hút ẩm tiên tiến, sản phẩm giúp bạn luôn khô thoáng, thoải mái và tự tin dù thời tiết có nóng bức.\r\n\r\nTHÔNG SỐ\r\nCông nghệ Nike Dri-FIT giúp hút mồ hôi và đẩy nhanh quá trình bay hơi, giữ cơ thể luôn khô ráo.\r\nChất liệu cotton dày vừa, mềm mại, tạo cảm giác dễ chịu và tự nhiên khi mặc.\r\n100% cotton tự nhiên phù hợp cho làn da nhạy cảm.\r\nDễ dàng giặt máy, tiết kiệm thời gian chăm sóc.','3pxej5','962d78','active','2024-11-28 23:19:15','2026-03-16 23:03:39',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('5x7pcr','Giày bóng chuyền Asics NETBURNER BALLISTIC FF 4','Giày trong nhà NETBURNER BALLISTIC™ FF 4 được thiết kế nhằm tăng tốc độ và độ linh hoạt cho các chuyển động đa hướng.\r\n\r\nCông nghệ SPEEDTRUSS™ được tối ưu cho khả năng tăng tốc nhanh, giúp bạn di chuyển nhanh hơn trên sân.\r\n\r\nThiết kế PRECISION SOLE™ ứng dụng công nghệ mô phỏng 3D để tạo nên họa tiết đế ngoài, đạt được sự cân bằng tối ưu giữa độ linh hoạt và độ bám trong khi vẫn giữ trọng lượng giày nhẹ. Những đặc tính này được kết hợp cùng các rãnh uốn X GUIDANCE™ nhằm tăng thêm độ linh hoạt khi thực hiện các chuyển động đa hướng.​\r\n\r\nCuối cùng, đế giữa FLYTEFOAM™ được kết hợp với độ chênh gót 15mm, giúp tăng cường sự thoải mái và hỗ trợ các chuyển động nhanh hơn.','m65tw5','3aa1e6','active','2025-10-05 14:30:54','2026-03-16 23:03:40',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('60v27o','Giày bóng chuyền Asics SKY ELITE FF 3','Giày trong nhà SKY ELITE™ FF 3 giúp bạn thực hiện những cú nhảy đầy uy lực, đưa cả phong độ thi đấu lẫn tinh thần của bạn vươn lên tầm cao mới.​\r\n\r\nĐể hỗ trợ những pha bật nhảy cao hơn, đôi giày được trang bị công nghệ RISETRUSS™ giúp tạo lực đẩy mạnh mẽ khi rời mặt sàn.​\r\n\r\nĐế giữa cũng được nâng cấp với lớp đệm FF BLAST™ PLUS, mang lại khả năng giảm chấn tiên tiến và độ bật tràn đầy năng lượng hơn khi thực hiện các động tác nhảy.​\r\n\r\nCuối cùng, cấu trúc thân giày được thiết kế với khả năng hỗ trợ tốt hơn, mang lại cảm giác khóa chặt bàn chân, độ ôm cải thiện và tối ưu hiệu quả truyền lực.','m65tw5','3aa1e6','active','2024-12-08 22:22:34','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('63r1z1','Mũ Bảo Hiểm Xe Đua Syntax MIPS','ón Bảo Hiểm Giro Syntax Mips – Thoải Mái Trên Mọi Cung Đường\r\nHiệu suất bền bỉ – Phong cách tinh tế – Bảo vệ tối ưu.\r\nGiro Syntax Mips mang đến sự thoải mái vượt trội cho những hành trình dài, kết hợp thiết kế châu Âu thanh lịch với độ bao phủ sâu hơn để bạn yên tâm chinh phục cả đường thành phố lẫn địa hình phức tạp.\r\n\r\n \r\n\r\nĐặc điểm nổi bật\r\nThiết kế mỏng, nhẹ và chắc chắn: Cấu trúc In-Mold kết hợp vỏ ngoài polycarbonate với lớp lót EPS giúp tăng độ bền và tối ưu khả năng thông gió.\r\n\r\nHệ thống điều chỉnh Roc Loc 5 Air Mips®: Tùy chỉnh vừa vặn dễ dàng, giữ nón luôn ổn định và thoải mái. Công nghệ Mips® hỗ trợ bảo vệ khỏi các lực xoay khi xảy ra va chạm lệch góc.\r\n\r\nThoáng khí vượt trội: 25 lỗ thông gió kết hợp kênh dẫn khí bên trong giúp luồng không khí luôn lưu thông, giữ đầu bạn mát mẻ suốt hành trình.\r\n\r\nĐệm Ionic+™ kháng khuẩn: Hạn chế mùi hôi, giữ nón luôn sạch sẽ và dễ chịu.\r\n\r\nDây đeo siêu nhẹ với khóa Slimline™: Đơn giản, gọn gàng và dễ điều chỉnh.','3uzxgn','56fus5','active','2025-05-21 10:59:21','2026-03-16 23:03:39',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('67n8vj','Quần Ngắn Thể Thao Nữ Adidas Tennis Climacool 2In1 Match','QUẦN NGẮN THỂ THAO NỮ ADIDAS TENNIS CLIMACOOL 2IN1 MATCH\r\nQuần Ngắn Thể Thao Nữ Adidas Tennis Climacool 2In1 Match là sự kết hợp hoàn hảo giữa phong cách năng động và công nghệ hiện đại, mang đến cảm giác thoải mái tối đa. Với thiết kế xẻ nhẹ nhàng và lớp quần lót liền bên trong, trợ mọi chuyển động tự nhiên. Lưng cao co giãn ôm trọn vòng eo, tôn dáng cơ thể. Công nghệ adidas Climacool với sợi vải siêu nhanh khô giữ bề mặt da luôn mát mẻ, khô ráo - nâng cao khả năng tập trung kể cả khi vận động cường độ cao. Biểu tượng Performance logo đặc trưng của adidas tạo điểm nhấn đẳng cấp, làm nổi bật phong cách thể thao hiện đại cho bạn.\r\n\r\nTHÔNG SỐ\r\nPhom dáng vừa vặn, dễ dàng vận động trên sân.\r\nLưng quần co giãn toàn phần, thoải mái ôm eo.\r\nChất liệu dệt trơn 86% polyester tái chế, 14% elastane\r\nQuần lót trong liền mạch tăng cường sự tự tin khi di chuyển.\r\nỨng dụng công nghệ CLIMACOOL giúp da luôn khô thoáng mát mẻ.\r\nNhấn nhá logo Performance tạo điểm nhấn thời trang nổi bật.','2sx26h','4e177a','active','2024-12-22 11:53:10','2026-03-16 23:03:42',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('68yza7','Phao Tay Trẻ Em Speedo','PHAO TAY TRẺ EM SPEEDO\r\n\r\nPhao tay Speedo là sản phẩm hỗ trợ bơi lội thiết kế dành riêng cho trẻ em, được làm từ chất liệu PVC an toàn, sản xuất theo tiêu chuẩn an toàn của Úc và châu Âu. Với thiết kế tay băng tay cuộn, van an toàn chắc chắn, chịu được tải trọng lên tới 50kg bảo đảm an toàn cho những nhà thám hiểm nhí đam mê bơi lội, yêu thích các cuộc phiêu lưu dưới nước. Sản phẩm dành cho trẻ em từ 2-12 tuổi.\r\n\r\nTHÔNG SỐ\r\n\r\nKích thước: 0-2 tuổi (lên tới 15kg), 2-6 tuổi (lên tới 25kg) 6-12 tuổi (lên tới 50kg), tuổi trên 12+ (trên 50kg)\r\nPVC chất lượng cao với van an toàn\r\nTrẻ em phải được giám sát khi sử dụng sản phẩm này\r\nSản xuất theo tiêu chuẩn an toàn của Úc và châu Âu\r\nChất liệu: TPU','3myvj5','h2v6o2','active','2025-01-01 11:24:42','2026-03-16 23:03:40',5,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('6eorps','Giày cầu lông Lining AYTV021-3','Lining AYTV021-3 là sản phẩm nằm trong phân khúc giá tầm trung mới được ra mắt bởi nhà Lining. Với kiểu dáng bắt mắt, công nghệ hiện đại cùng vật liệu cao cấp, Lining AYTV021-3 hứa hẹn là người bạn đồng hành đáng tin cậy dành cho mọi lông thủ phong trào.','ayirn2','7d1050','active','2024-10-09 18:19:27','2026-03-16 23:03:34',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('6k3x91','Túi đựng giày cầu lông Yonex','','a08ffr','7d1050','active','2026-02-10 09:56:07','2026-03-16 23:03:39',5,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('6lmw24','Vợt Pickleball JOOLA Scorpeus Pro V Anna 16Mm','VỢT PICKLEBALL JOOLA SCORPEUS PRO V ANNA 16MM\r\nScorpeus Pro V – cây vợt hoàn hảo cho những ai yêu thích lối chơi phòng ngự chắc chắn. Với thiết kế bản rộng nhất cùng hình dáng dễ kiểm soát, Scorpeus Pro V giúp mỗi cú đánh đều ổn định ngay cả khi bạn chưa chuẩn xác về thời gian hay điểm tiếp xúc.\r\n\r\nChiều dài ngắn hơn các dòng Pro V khác mang lại sự vững vàng vượt trội trong các pha bóng tốc độ gần lưới. Đây là lựa chọn lý tưởng cho các trận đấu đôi khi cần che chắn ít sân nhưng phải chiến thắng nhiều pha điểm tại khu vực lưới.\r\n\r\nCông nghệ KineticFrame độc quyền ở phần cổ vợt giúp giảm rung, kiểm soát bóng tốt hơn và đảm bảo những tay vợt mềm vẫn luôn làm chủ cuộc chơi dưới áp lực.\r\n\r\nTHÔNG SỐ\r\nBề mặt carbon fiber nhám tăng khả năng tạo xoáy và kiểm soát bóng tối đa.\r\nLõi vợt dày 16mm/14mm giúp giảm chấn tốt và tăng độ ổn định cho từng cú đánh.\r\nĐạt chứng nhận UPA-A và USAP, phù hợp thi đấu chuyên nghiệp.\r\nThiết kế chuẩn, phù hợp với nhiều phong cách thi đấu.\r\nChiều dài vợt 40,6cm đảm bảo kiểm soát linh hoạt mọi vị trí trên sân.\r\nBản rộng 20,3cm mở rộng điểm ngọt, hỗ trợ đa dạng kỹ thuật phòng ngự.\r\nTay cầm Feel-Tec êm ái, chống trơn trượt khi thi đấu liên tục.\r\nTay cầm dài 13,3cm phù hợp nhiều cỡ tay, thoải mái khi sử dụng.\r\nChu vi tay cầm 10,8cm/10,5cm; cầm chắc chắn và vừa vặn cho đa số người chơi.','lsg423','0lifzq','active','2025-06-08 04:19:48','2026-03-16 23:03:40',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('6m6sww','Vợt cầu lông Lining Bladex Assassin','Lining Bladex Assassin là mẫu vợt tầm trung mới ra mắt năm 2026, thuộc dòng Bladex của Lining – biểu trưng cho tốc độ phản xạ và sự linh hoạt trong lối chơi hiện đại','50r71o','3371b3','active','2025-09-24 21:19:49','2026-03-16 23:03:43',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('6u7s3n','Quần Ngắn Thể Thao Nam Nike Dri-Fit Dna 8 Inch','QUẦN NGẮN THỂ THAO NAM NIKE DRI-FIT DNA 8 INCH\r\nKhi thời khắc quyết định đến và bạn cần tạo dấu ấn cho riêng mình trên sân bóng, hãy chọn những chiếc quần short giúp bạn tự tin tỏa sáng! Quần Ngắn Thể Thao Nam Nike Dri-Fit Dna 8 Inch được thiết kế với chất liệu hiện đại, nhẹ nhàng nhưng bền chắc, giúp thấm hút mồ hôi hiệu quả để bạn luôn khô thoáng và tập trung trong từng pha lên bóng. Dù ở trong sân hay ngoài phố, bạn có thể yên tâm giữ đồ dùng cá nhân nhờ túi kéo khóa tiện lợi. Hãy luôn trong tâm thế sẵn sàng như một nhà vô địch!\r\n\r\nTHÔNG SỐ\r\nThiết kế chuyên biệt cho bóng rổ, hỗ trợ vận động tối đa trên sân.\r\nĐộ dài ống (từ đáy quần đến gấu quần): 21cm\r\nKhông lót, tăng sự linh hoạt và thoải mái.\r\nVải siêu nhẹ, mặt lưới thoáng khí, thấm hút mồ hôi vượt trội giúp luôn khô ráo.\r\nHai túi bên và một túi kéo đa năng đựng vừa điện thoại hoặc đồ cá nhân.\r\nThắt lưng co giãn kèm dây rút, ôm vừa vặn mọi vóc dáng.\r\nĐường xẻ bên tăng khả năng di chuyển linh hoạt.\r\nLogo Swoosh thêu nổi bật thể hiện phong cách thể thao.\r\nChất liệu 100% polyester bền đẹp','j1jpkb','962d78','active','2025-08-22 10:47:05','2026-03-16 23:03:37',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('6z5iey','Áo Thun Nam Under Armour Heavyweight Verbiage','ÁO THUN NAM UNDER ARMOUR HEAVYWEIGHT VERBIAGE\r\n\"Mọi sản phẩm mang tên tôi đều phải tốt —nó phải giúp bạn chơi tốt hơn\" - Stephen Curry, huyền thoại bóng rổ NBA. Mang tinh thần ấy,\r\n\r\nTHÔNG SỐ\r\nChất liệu vải pha cotton dày dặn, mềm mại mang lại sự thoải mái suốt cả ngày.\r\nCổ áo bo gân.\r\n60% Cotton/40% Polyester.','3pxej5','1791f2','active','2025-08-17 17:25:05','2026-03-16 23:03:40',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('7522k1','Giáp Bảo Vệ Ống Chân Puma King','GIÁP BẢO VỆ ỐNG CHÂN PUMA KING\r\nCác pha tranh chấp bóng nảy lửa luôn tiềm ẩn nguy cơ chấn thương. Giáp Bảo Vệ Ống Chân Puma King chính là người bạn đồng hành đáng tin cậy, giúp bạn an tâm thi đấu hết mình mà không phải lo lắng về những cú va chạm bất ngờ.\r\n\r\nTHÔNG SỐ\r\nVật liệu EVA nén từ PUMA giúp mang lại hiệu suất nhẹ nhàng\r\nVỏ bảo vệ được làm từ polypropylene hấp thụ va đập\r\nHình dạng được thiết kế công thái học\r\nCấu trúc vỏ cứng linh hoạt từ polyethylene\r\nBề mặt nén giúp vừa vặn an toàn\r\nLớp đệm: 100% ethylenvinylacetat','1wyf0i','a8073f','active','2024-09-30 22:21:25','2026-03-16 23:03:39',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('76ewem','Quần Bơi Nam Nike Swim Breaker 7 Inch Volley','QUẦN BƠI NAM NIKE SWIM BREAKER 7 INCH VOLLEY\r\nThể hiện phong cách năng động với quần short cổ điển, thiết kế lý tưởng để thư giãn bên hồ bơi hoặc xuống phố mỗi ngày. Sản phẩm được làm từ chất liệu polyester mềm mại, tích hợp lớp lót bên trong giúp bạn luôn khô ráo, thoải mái suốt cả ngày hè oi ả.\r\n\r\nTHÔNG SỐ\r\nChất liệu polyester nhẹ, mau khô, lý tưởng cho ngày hè.\r\nLưng thun co giãn, dây rút dễ dàng điều chỉnh vừa vặn.\r\nThành phần 100% polyester, bền đẹp theo thời gian.','37u1i1','962d78','active','2025-12-12 08:29:55','2026-03-16 23:03:36',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('76toyi','Áo Đá Bóng Nam Adidas Arsenal Sân Khách 24/25','\r\nÁO ĐÁ BÓNG NAM ADIDAS ARSENAL 24/25 AWAY\r\nThể hiện niềm tự hào với đội fan đa dạng của Arsenal. Mang đậm ảnh hưởng đặc trưng từ Tây Phi của Labrum London, chiếc áo đấu adidas này nằm trong bộ sưu tập hợp tác với thương hiệu thời trang Anh này. Họa tiết graphic và các chi tiết tinh xảo kết hợp cùng màu sắc lá cờ Pan-Africa tạo nên thiết kế bắt mắt. Huy hiệu đội bóng đẳng cấp và công nghệ AEROREADY kiểm soát ẩm giúp chiếc áo này trở thành lựa chọn hoàn hảo cho những người hâm mộ trung thành. Sản phẩm này làm từ 100% chất liệu tái chế. Bằng cách tái sử dụng các chất liệu đã được tạo ra, chúng tôi góp phần giảm thiểu lãng phí và hạn chế phụ thuộc vào các nguồn tài nguyên hữu hạn, cũng như giảm phát thải từ các sản phẩm mà chúng tôi sản xuất.\r\n\r\nTHÔNG SỐ\r\nKiểu dáng ôm vừa vặn (Slim Fit)\r\nCổ chữ V bằng vải dệt kim phẳng\r\n100% polyester (tái chế)\r\nAEROREADY\r\nHuy hiệu Arsenal thêu nổi','sd2dby','4e177a','active','2025-06-27 12:44:29','2026-03-16 23:03:41',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('77thks','Ống cầu lông nhựa Yonex Mavis 10','Thông tin ống cầu nhựa Yonex Mavis 10\r\nSản phẩm ống cầu Yonex nhựa Mavis 10 là loại cầu nhựa chuyên dùng cho các trận cầu ngoài trời, với độ bền bỉ và thời gian sử dụng lâu dài rất được các tay vợt ưa chuộng.\r\n\r\nPhần đế vẫn được làm bằng vật liệu gỗ như các quả cầu thông thường nhưng phần lông cầu thay vì sử dụng lông thú thì đã được thay thế bằng nhựa cao cấp, có độ đàn hồi và độ bền cao, cho tốc độ bay trung bình.\r\n\r\nVì vậy, trọng lượng của cầu Yonex Mavis 10 thường lớn hơn, nặng hơn, chống chọi tốt trước các tác động như gió thổi khi chơi cầu ngoài trời, giữ cho đường cầu ổn định và chuẩn xác nhất với ý đồ người chơi.\r\n\r\nVới hai màu vàng và trắng, mỗi ống cầu lông sẽ bao gồm 6 quả cầu lông, giúp dễ dàng thay thế khi chơi. Tới từ thương hiệu thể thao Yonex hàng đầu thế giới, với công nghệ sản xuất tới từ Nhật Bản, bạn có thể yên tâm về chất lượng và độ bền của sản phẩm, rất đáng để đầu tư đó nhé!','28hdkh','7d1050','active','2025-03-20 02:04:41','2026-03-16 23:03:41',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('7ajhmc','Giày Bóng Rổ Unisex Under Armour Lockdown 7 Mid Top','GIÀY BÓNG RỔ UNISEX UNDER ARMOUR LOCKDOWN 7 MID TOP\r\nGiày Bóng Rổ Unisex Under Armour Lockdown 7 Mid Top mang phong cách thể thao cực chất, siêu nhẹ, bền bỉ và ôm chân thoải mái. Đế ngoài họa tiết xương cá tăng tối đa khả năng bám sân, giúp bạn kiểm soát mọi chuyển động. Đệm EVA nhẹ êm tạo cảm giác nhạy bén, tự tin khi thi đấu.\r\n\r\nTHÔNG SỐ\r\nThân giày bằng lưới thoáng khí, phối da và lớp màng hỗ trợ tăng độ bền\r\nĐệm giữa EVA nhẹ, phản hồi tốt\r\nĐế ngoài cao su solid với họa tiết xương cá, bám sân tối đa, kiểm soát linh hoạt\r\nDây buộc tiêu chuẩn\r\nForm regular fit (dáng vừa vặn)','xijocy','1791f2','active','2025-09-12 01:17:19','2026-03-16 23:03:34',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('7kq7wy','Áo Đá Bóng Nam Adidas Real Madrid Sân Thứ Ba 21/22','ÁO THI ĐẤU CÓ KHẢ NĂNG HÚT ẨM TỐT.\r\nLà điểm xuất phát của chiến thắng. Họa tiết la bàn và dòng chữ phía sau cổ áo làm nổi bật chi tiết này. Adidas cho ra mắt phiên bản áo thi đấu dành cho người hâm mộ, được thiết kế dựa trên chiếc áo đấu mà đội bóng mặc khi chinh chiến trong các giải đấu. Chất liệu vải mềm mại và công nghệ hút ẩm AEROREADY mang đến cảm giác thoải mái như ở nhà.\r\n\r\nTHÔNG SỐ\r\nDáng regular fit\r\nCổ áo bo viền\r\nChất liệu vải doubleknit 100% tái chế\r\nCông nghệ hút ẩm\r\nHuy hiệu Real Madrid dệt thêu\r\nChất liệu Primegreen','sd2dby','4e177a','active','2025-06-26 10:15:43','2026-03-16 23:03:40',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('7nd2uq','Vợt cầu lông Lining Bladex 900 Pink','Lining Bladex 900 Pink là cây vợt cầu lông mới được nhà Lining cho ra mắt thời gian gần đây. Cây vợt đã bổ sung vào series Lining Bladex một siêu phẩm tấn công vượt trội giúp người chơi bộc phát tối đa sức mạnh trên sân cầu.','50r71o','3371b3','active','2025-12-06 19:51:23','2026-03-16 23:03:41',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('7sikl6','Giày Bóng Rổ Unisex Under Armour Flotro Big Bang','GIÀY BÓNG RỔ UNISEX UNDER ARMOUR FLOTRO BIG BANG\r\nGiày Bóng Rổ Unisex Under Armour Flotro Big Bang lấy cảm hứng từ chiếc áo đấu \"City Edition\" của Stephen Curry với màu đen và vàng đặc trưng, cùng sự gợi nhớ về cảnh đồi núi và biển hiệu Cable Car nổi tiếng của San Francisco. Thiết kế đặc sắc, kết hợp cùng công nghệ UA Flow mang đến độ bám tuyệt vời, giúp bạn tự tin thể hiện sức mạnh và phong cách trên sân bóng.\r\n\r\nTHÔNG SỐ\r\nChất liệu lưới nhẹ, thoáng khí với lớp phim TPU tăng cường hỗ trợ, ổn định và độ bền\r\nCổ giày mềm mại mang lại sự thoải mái và cố định gót chân\r\nLót giày bằng bọt êm ái mang lại cảm giác thoải mái tuyệt vời\r\nThanh Pebax® bên trong giúp ổn định phần giữa bàn chân\r\nCông nghệ đệm UA Flow siêu nhẹ, đàn hồi và cung cấp độ bám tuyệt vời\r\nĐế ngoài UA Flow bền bỉ, cải thiện cảm giác mặt sân, giúp di chuyển linh hoạt trong những pha cắt bóng và dừng nhanh hơn bao giờ hết\r\nTrọng lượng: 11.9 oz\r\nKiểu dây buộc tiêu chuẩn','xijocy','1791f2','active','2026-01-23 01:23:30','2026-03-16 23:03:41',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('7sq8iz','Ống cầu Lining AYQN 024-3','Giới thiệu ống cầu Lining AYQN 024-3\r\nỐng cầu Lining AYQN 024-3 là một trong những dòng sản phẩm phụ kiện cầu lông cao cấp đến từ thương hiệu thể thao nổi tiếng Lining – thương hiệu nổi tiếng của Trung Quốc được nhiều vận động viên chuyên nghiệp tin dùng. Sản phẩm được thiết kế hướng đến người chơi có nhu cầu tập luyện và thi đấu với yêu cầu cao về độ ổn định, độ bền và khả năng bay chuẩn xác. AYQN 024-3 không chỉ gây ấn tượng bởi chất lượng cầu đồng đều, mà còn bởi tính ổn định và khả năng chịu lực cực tốt trong điều kiện thi đấu thực tế.','28hdkh','3371b3','active','2025-11-26 20:12:42','2026-03-16 23:03:43',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('7wg8mt','Giày Tennis Nữ Asics Gel-Renma 2','GIÀY TENNIS NỮ ASICS GEL-RENMA 2\r\nGiày Tennis Nữ Asics Gel-Renma 2 là lựa chọn lý tưởng cho các tay vợt muốn nâng tầm hiệu suất trên sân cứng. Đôi giày này mang lại sự ổn định, linh hoạt tuyệt vời, giúp bạn tự tin di chuyển đa hướng. Với công nghệ TRUSSTIC™ ở đế giữa, đôi chân bạn luôn vững vàng và hạn chế tối đa việc vặn xoắn quá mức. Đế ngoài được mở rộng, tạo độ cân bằng và chuyển động mượt mà hơn. Phần thân giày sử dụng chất liệu lưới mềm phủ film không chỉ nhẹ, mềm mại mà còn linh hoạt, đem lại cảm giác thoải mái ngay cả khi chơi lâu. Đặc biệt, đế ngoài thiết kế các rãnh thông minh tăng khả năng linh hoạt và giúp bước chân luôn tự nhiên.\r\n\r\nTHÔNG SỐ\r\nThân giày lưới mềm phủ film không đường may giúp thoáng khí, linh hoạt vượt trội\r\nLớp da tổng hợp ở giữa thân giày tăng độ ổn định khi di chuyển ngang\r\nCông nghệ TRUSSTIC™ nâng cao sự vững chắc, giảm tình trạng xoắn giày\r\nĐệm GEL® phía trước giảm sốc, êm ái và bảo vệ bàn chân tối ưu\r\nĐế ngoài mở rộng và thiết kế quấn giúp tăng độ ổn định\r\nRãnh trên đế ngoài hỗ trợ di chuyển linh hoạt, chuyển hướng êm mượt\r\nLót giày nhuộm bằng công nghệ thân thiện môi trường, giảm đến 33% lượng nước và 45% khí thải carbon','uicjou','3aa1e6','active','2024-10-10 15:58:34','2026-03-16 23:03:38',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('7xmqg7','Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Mizuno Alpha Iii Elite As','GIÀY ĐÁ BÓNG SÂN CỎ NHÂN TẠO NAM MIZUNO ALPHA III ELITE AS\r\nĐược thiết kế dành riêng cho mẫu cầu thủ tốc độ, Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Mizuno Alpha Iii Elite As mang đến khả năng bứt tốc vượt trội cùng cảm giác ôm chân hoàn hảo. Phom giày Engineered Fit Last NEO kết hợp chất liệu vải dệt kim cao cấp với lưỡi gà liền mạch - đem lại sự êm ái và linh hoạt. Công nghệ khâu tỉ mỉ của Mizuno giúp giày vừa khít, hỗ trợ tối đa từng bước di chuyển. Đế giày với đinh tam giác tối ưu hóa lực đẩy về phía trước, cùng lớp đệm gót MIZUNO ENERZY hấp thụ lực và hoàn trả năng lượng vượt trội. Lót giày sử dụng MIZUNO ENERZY xp SOCKLINER siêu nhẹ, mềm mại và bật nảy, giúp bạn bùng nổ mọi khi ra sân.\r\n\r\nTHÔNG SỐ\r\nThân giày dệt kim tích hợp lưỡi gà ôm sát chân, mềm mại và linh hoạt vượt trội.\r\nĐệm giữa toàn bộ chiều dài Mizuno ENERZY hấp thụ lực và hoàn trả năng lượng hiệu quả.\r\nLót giày Mizuno ENERZY XP siêu nhẹ, tăng cường độ êm và độ bật.\r\nĐế ngoài thiết kế chuyên biệt, bám sân chắc chắn và tăng độ bền trên bề mặt cỏ nhân tạo.\r\nLý tưởng cho cầu thủ thiên về tốc độ, ưa chuộng giày nhẹ, linh hoạt với chất liệu dệt kim hiện đại.\r\nHơn 90% vật liệu tái chế sử dụng ở chi tiết lót giày và dây giày, thân thiện với môi trường.','eqj3j1','69f937','active','2025-05-21 06:07:18','2026-03-16 23:03:36',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('83coc0','Giày Bóng Rổ Unisex Under Armour D. Fox 2 Nm1','GIÀY BÓNG RỔ UNISEX UNDER ARMOUR D. FOX 2 NM1\r\nGiày Bóng Rổ Unisex Under Armour D. Fox 2 Nm1: Tốc độ bùng nổ và phản xạ cực bén giúp bạn đột phá như De\'Aaron Fox. Thiết kế thể thao năng động tối ưu cho các pha di chuyển nhanh và linh hoạt trên sân.\r\n\r\nTHÔNG SỐ\r\nPhần upper kết hợp vải dệt và màng siêu nhẹ, đảm bảo thoáng khí và hỗ trợ tối đa tốc độ\r\nDây cài mẫu đặc biệt, chi tiết cao cấp, cố định chắc chắn\r\nKhung gót TPU bên ngoài nhẹ, ôm sát hỗ trợ, điểm nhấn đặc trưng D. Fox\r\nLót giày TPE-blend giữ độ đàn hồi và bền lâu, hoàn trả năng lượng tối ưu\r\nBộ đệm Charged Cushioning® bên trong kết hợp đế ngoài UA Flow chống mài mòn, tạo cảm giác êm ái vượt trội\r\nĐế ngoài UA Flow siêu bền, cho cảm giác mặt sân tốt, tăng khả năng bứt tốc và đổi hướng\r\nForm: Regular\r\nKiểu dây: Cột tiêu chuẩn','xijocy','1791f2','active','2024-12-16 01:00:11','2026-03-16 23:03:39',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('877x7e','Mũ Bảo Hiểm Xe Đua Aries Spherical','Giro Aries Spherical – Mũ bảo hiểm siêu nhẹ, bảo vệ tối ưu\r\nGiro Aries Spherical là lựa chọn hàng đầu cho các tay đua đường trường muốn kết hợp giữa trọng lượng nhẹ, thông gió tối ưu và an toàn vượt trội. Công nghệ Spherical kết hợp MIPS® mang lại cảm giác “như không đội mũ” mà vẫn bảo vệ tối đa.\r\nTính năng nổi bật\r\nThiết kế siêu nhẹ – Chỉ 275g (size M), giảm áp lực lên cổ và vai.\r\nCông nghệ Spherical + MIPS – Phân tán lực va chạm, bảo vệ não tối ưu.\r\nLớp mút Nanobead EPS mật độ kép – Hấp thụ lực tác động hiệu quả, vẫn nhẹ.\r\n24 khe gió Wind Tunnel – Thông gió tối ưu, giữ đầu luôn mát mẻ.\r\nĐệm trán DryCore & lót Ionic+ – Thấm hút mồ hôi, kháng khuẩn và khô thoáng.\r\nHệ thống Roc Loc 5+ Air – Điều chỉnh dễ dàng, ôm vừa và ổn định.\r\nKhay gắn kính tích hợp – Tiện lợi khi cần tháo hoặc gắn kính nhanh.','3uzxgn','56fus5','active','2026-02-21 16:26:27','2026-03-16 23:03:40',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('87901e','Áo Đá Bóng Nam Adidas Sân Khách Real Madrid 25/26 Away','ÁO ĐÁ BÓNG NAM ADIDAS SÂN KHÁCH REAL MADRID 25/26\r\nLấy cảm hứng từ diện mạo mới của sân vận động Santiago Bernabéu, áo đấu sân khách Real Madrid 25/26 mang đến thiết kế hiện đại với họa tiết moiré tinh xảo và các chi tiết ánh kim bạc nổi bật. Sự kết hợp giữa thẩm mỹ kiến trúc và DNA bóng đá hoàng gia tạo nên một diện mạo cuốn hút, giàu cảm xúc. Công nghệ AEROREADY giúp kiểm soát mồ hôi hiệu quả, mang lại cảm giác khô thoáng cho người hâm mộ dù đồng hành cùng đội bóng trên mọi hành trình.\r\n\r\nTHÔNG SỐ\r\nDáng slim fit\r\nCổ tròn (crewneck)\r\nChất liệu 100% polyester tái chế\r\nCông nghệ AEROREADY thoáng khí, hút ẩm tốt\r\nHuy hiệu Real Madrid thêu nổi','sd2dby','4e177a','active','2025-11-12 19:49:47','2026-03-16 23:03:35',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('89kljt','Áo Ba Lỗ Nữ Mizuno Impulse Core Rb','ÁO BA LỖ NỮ MIZUNO IMPULSE CORE RB\r\nÁo Ba Lỗ Nữ Mizuno Impulse Core RB là sự kết hợp hoàn hảo giữa hiệu suất và phong cách, lý tưởng cho nữ vận động viên hiện đại. Được chế tạo từ vải thấm hút ẩm, chiếc áo đảm bảo bạn luôn mát mẻ và thoải mái trong các buổi tập luyện cường độ cao hoặc các hoạt động thể thao nhẹ nhàng. Thiết kế racerback cải thiện khả năng vận động, phù hợp cho nhiều bài tập khác nhau, từ chạy bộ đến yoga. Kiểu dáng ôm sát của áo tôn lên vóc dáng của bạn, trong khi cấu trúc nhẹ nhàng mang đến cảm giác thoải mái tuyệt đối, giúp bạn hoàn toàn tập trung vào mục tiêu luyện tập của mình. Chiếc áo ba lỗ đa năng này là sự lựa chọn phong cách và chức năng cho bất kỳ tủ đồ thể thao nào.\r\nTHÔNG SỐ\r\nĐược phát triển cho các buổi luyện tập và sử dụng trong nhiều môn thể thao\r\nChất vải cực mềm mại tăng cường sự thoải mái trong suốt bài tập\r\nCông nghệ DryLite mang đến sự thoải mái và khô thoáng tối ưu cho hiệu suất vận động tốt nhất\r\nChi tiết phản quang cải thiện khả năng nhận diện trong điều kiện ánh sáng yếu\r\nSản phẩm được làm từ ít nhất 50% sợi polyester tái chế','cxo8ft','69f937','active','2024-10-11 17:16:34','2026-03-16 23:03:38',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('8g0v6n','Giày Tennis Nữ Nike Court Lite 4','GIÀY TENNIS NỮ NIKE COURT LITE 4\r\nLướt nhẹ trên sân với Giày Tennis Nữ Nike Court Lite 4 – lựa chọn lý tưởng cho những pha bóng bứt phá. Thiết kế thể thao năng động, chắc chắn, linh hoạt giúp bạn di chuyển tự tin trước mọi thách thức. Lớp lưới thoáng khí kết hợp công nghệ hỗ trợ gót và mũi tăng độ bền, đồng hành cùng bạn trong từng ván đấu đầy kịch tính.\r\n\r\nTHÔNG SỐ\r\nĐế cao su tăng cường ở mũi và đầu ngón chân giúp hạn chế mài mòn, tăng độ bền\r\nCao su chịu mài mòn ở phía trước tạo độ bám và bền bỉ\r\nGờ tổng hợp hỗ trợ bên giúp giữ chắc gót chân\r\nThân giày lưới tăng khả năng thoáng khí, êm ái\r\nCổ giày mềm và gót lót đệm cho cảm giác thoải mái quanh mắt cá','uicjou','962d78','active','2025-10-12 10:15:23','2026-03-16 23:03:37',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('8kpz7l','Bóng chuyền MIKASA V330W','Loại bóng giành cho các giải phong trào theo tiêu chuẩn của FIVB (Liên đoàn bóng chuyền thế giới)\r\n\r\nThiết kế 18 múi độc đáo.\r\n\r\nLớp giả da bọc có chật liệu tổng hợp duy nhất.\r\n\r\nLớp sợi nylon được quấn bên trong, xung quanh bóng để gia cố cấu trúc của bóng','26j3e6','ea945m','active','2025-01-16 19:52:03','2026-03-16 23:03:40',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('8l3yl6','Áo Đá Bóng Sân Nhà Nam Chelsea Fc 2025/26','ÁO ĐÁ BÓNG SÂN NHÀ NAM NIKE CHELSEA FC 2025/26\r\nHòa mình vào bề dày lịch sử của đội bóng và nhịp sống sôi động của London với Áo Đá Bóng Sân Nhà Nam Nike Chelsea Fc 2025/26! Phiên bản nổi bật với màu xanh truyền thống cùng họa tiết tinh tế, lấy cảm hứng từ kiến trúc đặc trưng của thành phố. Là lựa chọn hoàn hảo cho người hâm mộ muốn thể hiện tình yêu với The Blues, chiếc áo không chỉ thời trang mà còn mang lại cảm giác thoải mái suốt cả ngày.\r\n\r\nTHÔNG SỐ\r\nThiết kế replica hiện đại, dễ dàng phối đồ mọi lúc mọi nơi\r\nLogo Chelsea dệt vải cao cấp, bền đẹp theo thời gian\r\nChất liệu 100% polyester, nhẹ và thoáng khí\r\nCông nghệ Nike Dri-FIT giúp thấm hút mồ hôi, luôn khô ráo khi vận động\r\nLấy cảm hứng từ áo đấu của các cầu thủ chuyên nghiệp Chelsea','sd2dby','962d78','active','2025-10-08 01:39:18','2026-03-16 23:03:41',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('8o3q08','Áo Ba Lỗ Nữ Adidas Ultimate Airchill Engineered','ÁO BA LỖ NỮ ADIDAS ULTIMATE AIRCHILL ENGINEERED\r\nAirchill Engineered này và tập trung chinh phục vạch đích. Kết cấu kỹ thuật hỗ trợ chuyển động mượt mà cùng công nghệ Heat.rdy giúp bạn luôn mát mẻ ở mọi tuyến chạy. Viền cổ tròn cho độ ôm thoải mái không chút phân tâm kết hợp thiết kế phản quang toàn phần giúp bạn nổi bật cả trong điều kiện thiếu sáng. Sản phẩm này làm từ 100% chất liệu tái chế, góp phần giảm thiểu lãng phí và hạn chế phụ thuộc vào các nguồn tài nguyên hữu hạn, cũng như giảm phát thải từ các sản phẩm mà adidas sản xuất.\r\n\r\nTHÔNG SỐ\r\nKiểu dáng vừa vặn, thoải mái (Regular fit)\r\nCổ tròn\r\n100% polyester (tái chế)\r\nAIRCHILL\r\nHEAT.RDY\r\nPhản quang 360 độ','cxo8ft','4e177a','active','2025-05-21 01:06:49','2026-03-16 23:03:37',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('8rqij0','Áo Thun Nam Nike Jordan Aj1','ÁO THUN NAM NIKE JORDAN AJ1\r\nLấy cảm hứng từ lần ra mắt đầu tiên của AJ1, chiếc áo thun cotton mềm mại này là sự tôn vinh tuyệt vời dành cho đôi giày được mệnh danh là \"cỗ máy chống trọng lực\" huyền thoại. Đem lại phong cách trẻ trung, năng động và đậm chất thể thao, chiếc áo sẽ giúp bạn nổi bật giữa đám đông.\r\n\r\nTHÔNG SỐ\r\nChất liệu 100% cotton cao cấp, thấm hút mồ hôi hiệu quả, tạo cảm giác thoải mái suốt ngày dài.\r\nDễ dàng giặt máy, bền màu và giữ form tốt qua nhiều lần sử dụng.\r\nThiết kế trẻ trung, tôn vinh biểu tượng AJ1 huyền thoại, dễ phối đồ cho mọi phong cách.','3pxej5','962d78','active','2024-11-22 10:44:39','2026-03-16 23:03:42',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('8xk0mr','Áo Thun Tay Dài Nam Under Armour Heavyweight Verbiage','ÁO THUN TAY DÀI NAM UNDER ARMOUR HEAVYWEIGHT VERBIAGE\r\n\"Mọi sản phẩm có tên tôi đều phải tốt—phải giúp bạn chơi tốt hơn và là một phần trong sứ mệnh thay đổi cuộc chơi của chúng tôi.\" – Stephen Curry, một trong những cầu thủ bóng rổ xuất sắc nhất lịch sử NBA. Áo Thun Tay Dài Nam Under Armour Heavyweight Verbiage - sản phẩm hợp tác mang tên Curry, có chất liệu vải pha cotton mềm mại, mang đến trải nghiệm dễ chịu suốt ngày dài.\r\n\r\nTHÔNG SỐ\r\nVải pha cotton dày dạn và mềm mại mang đến sự thoải mái suốt cả ngày.\r\nCổ sọc gân\r\n60% Cotton/40% Polyester','3pxej5','1791f2','active','2024-11-25 06:35:34','2026-03-16 23:03:41',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('905brb',' Giày Thể Thao Bóng Chuyền BEYONO STORM- LOW-CUT','','m65tw5','82c21b','active','2025-01-27 09:02:50','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('90p2z8','Giày Đá Bóng Dành Cho Mọi Loại Sân Nam Nike Zm Superfly 10 Acad Fg/Mg','GIÀY ĐÁ BÓNG DÀNH CHO MỌI LOẠI SÂN NAM NIKE ZM SUPERFLY 10 ACAD FG/MG\r\nBạn đang tìm kiếm một đôi giày đá bóng giúp bạn dễ dàng tăng tốc trên sân cỏ? Giày Đá Bóng Dành Cho Mọi Loại Sân Nam Nike Zm Superfly 10 Acad Fg/Mg sẽ là lựa chọn hoàn hảo cho bạn. Đôi giày hỗ trợ bạn tăng tốc tối đa và xuyên thủng hàng phòng ngự, làm chủ tốc độ trên suốt trận đấu.\r\n\r\nTHÔNG SỐ\r\nPhần trên được làm từ NikeSkin với các chi tiết chevron giúp kiểm soát bóng và mang lại cảm giác như lớp da thứ hai.\r\nMẫu gai đế sóng có các đinh dọc theo chiều dọc cung cấp độ bám phù hợp. Các gai chevron và blade được cải tiến để giúp bạn dừng lại khi thực hiện các cú cắt nhanh.\r\nCổ Dynamic Fit bao quanh mắt cá chân với chất liệu vải mềm, co giãn, mang lại cảm giác chắc chắn.','eqj3j1','962d78','active','2025-04-23 21:02:26','2026-03-16 23:03:38',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('937vmo','Giày Tennis Nam Adidas Gamecourt 2','GIÀY TENNIS NAM ADIDAS GAMECOURT 2\r\nGiày Tennis Nam Adidas Gamecourt 2 là lựa chọn lý tưởng dành cho những ai yêu thích phong cách năng động và hiệu suất vượt trội. Được sản xuất theo công nghệ Cold Cement tiên tiến, GameCourt 2 mang lại sự nhẹ nhàng, bền bỉ và linh hoạt trên mọi loại mặt sân. Dù bạn đang cải thiện cú đánh hay bứt tốc về phía lưới, giày luôn hỗ trợ tối ưu cho từng chuyển động, để mỗi trận đấu trở nên dễ dàng hơn bao giờ hết. Đừng bỏ lỡ sự kết hợp hoàn hảo giữa chất lượng và niềm đam mê tennis từ adidas dành cho bạn!\r\n\r\nTHÔNG SỐ\r\nForm giày ôm vừa vặn, mang lại cảm giác chắc chắn và thoải mái.\r\nDây buộc linh hoạt, dễ dàng điều chỉnh độ ôm tùy ý.\r\nThân giày kết hợp vải lưới và chất liệu tổng hợp, tăng độ bền và thoáng khí.\r\nLót trong vải mềm mại, nâng niu từng bước chân khi di chuyển.\r\nĐế ngoài cao su bền chắc, bám sân tối ưu, hỗ trợ di chuyển linh hoạt.','uicjou','4e177a','active','2025-05-02 10:49:22','2026-03-16 23:03:37',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('9kd6n3','Áo Thun Nam Under Armour Heavyweight Alien','ÁO THUN NAM UNDER ARMOUR HEAVYWEIGHT ALIEN\r\n\"Mọi sản phẩm mang tên tôi đều phải tốt - phải giúp bạn chơi tốt hơn và thay đổi cuộc chơi theo hướng tích cực\" - Stephen Curry, một trong những cầu thủ xuất sắc nhất lịch sử NBA. Mang tinh thần ấy, Áo Thun Nam Under Armour Heavyweight Alien sở hữu chất liệu pha cotton chất lượng - dày dặn, mềm mại và thoải mái suốt ngày dài.\r\n\r\nTHÔNG SỐ\r\nChất liệu vải pha cotton dày dặn, mềm mại, mang lại sự thoải mái suốt cả ngày.\r\nCổ áo đã được xử lý chắc chắn.\r\n60% cotton/40% polyester.','3pxej5','1791f2','active','2025-01-28 20:44:58','2026-03-16 23:03:40',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('9ysq4w','Kính Mát Không Gọng Moab XC','Kính Mát Nguyên Gọng TIFOSI Moab XC\r\nKính Moab XC sở hữu thiết kế tròng liền mạch - không gọng, mang lại tầm nhìn rộng mở và khí động học tối ưu, giúp bạn tập trung tuyệt đối vào từng bước chạy, cú đạp hay pha xử lý trên sân. Cấu trúc siêu nhẹ cùng càng kính mảnh giảm thiểu phân tâm, cho cảm giác gần như “không đeo”. Bao gồm tròng rời (Tròng Trong) giúp linh hoạt thích ứng với mọi điều kiện ánh sáng, từ sáng sớm đến nắng gắt. Đệm mũi và gọng tai có thể điều chỉnh, ôm chắc và thoải mái suốt thời gian vận động cường độ cao. Đặc biệt, Moab XC bảo vệ mắt hiệu quả khi chơi pickleball — hạn chế chói nắng, bụi và va chạm bất ngờ, giữ tầm nhìn sắc nét trong từng pha bóng tốc độ. Tối giản trong thiết kế. Tối đa trong hiệu suất.','6b4vag','8s9w7a','active','2025-12-11 13:18:43','2026-03-16 23:03:42',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('a36glc','Áo Đá Bóng Nam Adidas Manchester United Authentic','ÁO ĐÁ BÓNG NAM ADIDAS MANCHESTER UNITED AUTHENTIC\r\nPhong cách băng giá của Manchester United trở lại đầy mới mẻ trong mẫu áo đấu lấy cảm hứng từ thiết kế “bông tuyết” đầu những năm 90. Phiên bản lần này nổi bật với sắc tím và ánh kim hiện đại, tôn bật logo Quỷ Đỏ với hiệu ứng ánh bạc ấn tượng. Công nghệ AEROREADY thấm hút mồ hôi giúp fan luôn khô thoáng và sẵn sàng cổ vũ đến phút cuối cùng.\r\n\r\nTHÔNG SỐ\r\nLấy cảm hứng từ mẫu áo \"bông tuyết\" adidas đầu những năm 1990 của Man United\r\nThiết kế mới lạ với điểm nhấn màu tím và lilac\r\nLogo “Quỷ đỏ” phủ ánh kim loại, nổi bật hơn\r\nCông nghệ AEROREADY hỗ trợ thấm hút mồ hôi\r\nChất liệu mềm mại, thoải mái suốt ngày dài\r\nThiết kế dành riêng cho người hâm mộ tập trung vào trận đấu','sd2dby','4e177a','active','2025-06-27 22:39:38','2026-03-16 23:03:34',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('a7qhwh','Giày Bóng Rổ Nam Nike Kd18 Ep','GIÀY BÓNG RỔ NAM NIKE KD18 EP\r\nSức bền là \"vũ khí\" lợi hại nhất của KD. Anh luôn tràn đầy đam mê và năng lượng ở mọi thời điểm trên sân. Giày Bóng Rổ Nam Nike Kd18 Ep kết hợp bộ đệm Air Zoom và Nike Air phản hồi nhanh cực đỉnh. Thân giày được tạo lỗ thoáng khí khắp nơi, giúp nhẹ hơn và cho cảm giác mát mẻ, thoải mái, dù vận động cả ngày. Đế ngoài cao su siêu bền, hỗ trợ bám sân mạnh mẽ, phù hợp cả khi chơi ngoài trời.\r\n\r\nTHÔNG SỐ\r\nBộ đệm Air Zoom lớn ở mũi chân cho cảm giác bùng nổ, nhanh nhạy khi di chuyển đột ngột.\r\nĐệm Cushlon thế hệ mới mang lại cảm giác êm ái, dễ chịu xuyên suốt trận đấu.\r\nLớp dưới thân giày tích hợp đệm Nike Air ở gót, tăng thêm đàn hồi cho mỗi bước chạy.\r\nTấm nhựa cứng định hình dưới lòng bàn chân uốn theo chuyển động, kết hợp cùng Air Zoom ở mũi giúp bứt tốc vượt trội, đồng thời tăng độ ổn định, chắc chắn.\r\nKhung nhựa cứng phủ bên ngoài ôm giữ bàn chân, tăng sức chống đỡ và hỗ trợ hai bên vững vàng.','xijocy','962d78','active','2025-04-20 03:13:12','2026-03-16 23:03:36',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('acju5m','Joola Pickleball Ball Caddy','Sử dụng JOOLA Pickleball Ball Caddy để tập luyện. Dù bạn đang chơi hay huấn luyện, caddy này sẽ nâng cao hiệu quả ngày chơi của bạn, cả trong nhà lẫn ngoài trời.\r\n\r\nCaddy có sức chứa lên tới 100 quả bóng pickleball, giúp giảm bớt thời gian nhặt bóng và tăng thời gian chơi.\r\n\r\nBốn bánh xe giúp bạn di chuyển dễ dàng quanh sân, trong khi tính năng khóa đảm bảo caddy không bị di chuyển khi đang sử dụng.\r\n\r\nKhung có thể gập lại và nhẹ cân, giúp bạn dễ dàng mang theo đến sân tập.\r\n\r\nThích hợp cho việc sử dụng cá nhân hoặc làm quà tặng cho những ai yêu thích pickleball.','gfwht4','0lifzq','active','2025-10-18 05:42:57','2026-03-16 23:03:43',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ajhxm5','Vợt cầu lông Yonex Arcsaber 7 Pro','Vợt cầu lông Yonex Arcsaber 7 Pro được ra mắt ngày 19 tháng 8 năm 2022 được sản xuất tại Nhật Bản, đây là bản kế thừa của Arcsaber 7. Với công nghệ và vật liệu mới nhất Arcsaber 7 Pro có phần khung vợt cứng, giúp tăng độ chính xác và nhất quán khi đánh. Thiết kế khung giữa được xây dựng mềm mại, linh hoạt hơn tăng khả năng kiểm soát cầu.','50r71o','7d1050','active','2025-01-29 12:06:02','2026-03-16 23:03:42',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('amh4nh','Mũ Lưỡi Trai Nike Dri-Fit Adv Fly','MŨ LƯỠI TRAI NIKE DRI-FIT ADV FLY\r\nMũ Lưỡi Trai Nike Dri-Fit Adv Fly là lựa chọn hoàn hảo cho các buổi chạy, tập luyện, dạo phố,... Chất liệu cao cấp hút mồ hôi và các bề mặt AeroAdapt bên hông giữ cho bạn luôn mát mẻ, khô thoáng. Dây rút co giãn với nút xoay dễ điều chỉnh. Sản phẩm có thiết kế gọn gàng, dễ phối hợp trang phục.\r\n\r\nTHÔNG SỐ\r\nChất liệu: Polyester, Nylon\r\nCông nghệ Nike Dri-FIT ADV kết hợp chất liệu hút ẩm với kỹ thuật và tính năng tiên tiến - giúp bạn luôn khô ráo và thoải mái.\r\nCông nghệ Nike AeroBill thoáng khí\r\nCông nghệ Nike AeroAdapt với hệ thống các bề mặt thông gió - tăng thêm sự mát mẻ\r\nDây rút co giãn với nút xoay dễ điều chỉnh cho vừa vặn phù hợp.\r\nCác bề mặt dệt 4 chiều cung cấp sự vừa vặn dễ chịu và thoải mái.','j5up22','962d78','active','2024-10-04 14:56:54','2026-03-16 23:03:36',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('amof79','Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Adidas F50 Club','GIÀY ĐÁ BÓNG SÂN CỎ NHÂN TẠO NAM ADIDAS F50 CLUB\r\nKhám phá Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Adidas F50 Club – lựa chọn hoàn hảo giúp bạn tự tin thể hiện tốc độ và kỹ năng trên sân cỏ nhân tạo. Thiết kế năng động với chất liệu Fiberskin bền nhẹ và lưỡi gà thoáng khí mang đến sự êm ái, ôm chân vượt trội suốt trận đấu. Đế cao su đặc biệt giúp bám sân tối ưu, giữ vững từng bước di chuyển và bứt phá trên mọi đường bóng.\r\n\r\nTHÔNG SỐ\r\nThiết kế vừa vặn, thoải mái cho mọi cử động linh hoạt\r\nDây giày chắc chắn cố định bàn chân, tăng khả năng kiểm soát\r\nThân giày Fiberskin in họa tiết Sprintgrid siêu nhẹ và bền chắc\r\nLót giày vải mềm mại, êm chân suốt quá trình vận động\r\nĐế cao su chuyên dụng giúp bám sân cỏ nhân tạo hiệu quả, hỗ trợ tối đa tốc độ','eqj3j1','4e177a','active','2025-02-12 11:35:33','2026-03-16 23:03:36',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ao5ekr','Vợt cầu lông Lining Halbertec 1000','Sự ra đời của Halbertec 1000 đánh dấu một bước đi chiến lược của thương hiệu, hướng đến người chơi tìm kiếm sự chính xác và tinh tế vượt trội.','50r71o','3371b3','active','2025-12-17 18:12:04','2026-03-16 23:03:42',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ar7awo','Áo Đá Bóng Nam Adidas Arsenal Sân Thứ Ba 24/25','ÁO ĐÁ BÓNG NAM ADIDAS ARSENAL 24/25 THIRD\r\nPhiên bản mới mẻ của di sản bóng đá. Nổi bật với sắc tím lilac và xanh aqua, chiếc áo đấu thứ ba Arsenal này kết hợp huy hiệu pháo thủ táo bạo với logo Ba Lá adidas iconic. Kết quả là? Một thiết kế rực rỡ tô điểm sắc màu cho phòng thay đồ, khán đài đội khách và tiệc ăn mừng sau trận đấu. Mỗi khi diện chiếc áo này, chất vải interlock mềm mại và công nghệ AEROREADY kiểm soát ẩm đảm bảo bạn luôn sẵn sàng cho tất cả. Sản phẩm này làm từ 100% chất liệu tái chế. Bằng cách tái sử dụng các chất liệu đã được tạo ra, chúng tôi góp phần giảm thiểu lãng phí và hạn chế phụ thuộc vào các nguồn tài nguyên hữu hạn, cũng như giảm phát thải từ các sản phẩm mà chúng tôi sản xuất.\r\n\r\nTHÔNG SỐ\r\nKiểu dáng ôm vừa vặn (Slim Fit)\r\nCổ tròn bo gân\r\n100% polyester (tái chế)\r\nAEROREADY\r\nViền tay áo bo gân\r\nHuy hiệu Arsenal thêu nổi','sd2dby','4e177a','active','2025-06-19 05:58:05','2026-03-16 23:03:38',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('at164o','Mũ Bảo Hiểm Xe Đua Kunee','ũ bảo hiểm xe đạp Fizik Kunee\r\nTime Trial – Triathlon – Khí động học tối đa\r\nFizik Kunee là mũ bảo hiểm chuyên biệt cho time-trial và triathlon, được phát triển từ nhiều năm nghiên cứu CFD và thử nghiệm cùng VĐV đẳng cấp thế giới. Với thiết kế giọt nước, bề mặt nhẵn mượt và panel gợn sóng độc đáo, Kunee tối ưu luồng khí, giảm lực cản và duy trì tốc độ tối đa.\r\n\r\nTÍNH NĂNG NỔI BẬT\r\nBề mặt mượt mà và thiết kế hình giọt nước: Giảm lực cản không khí, tối ưu hóa luồng gió để tăng hiệu suất.\r\nCông nghệ tấm corrugate: giữ luồng gió hỗn loạn sát mũ, giảm lực cản thay vì phình rộng\r\nKính tích hợp nam châm: dễ dàng lắp đặt và tháo rời, tương thích với kính thông thường, vẫn đảm bảo hiệu suất aero khi tháo rời.\r\nĐiều chỉnh độ vừa vặn: Hỗ trợ tùy chỉnh để phù hợp với hình dáng đầu. \r\nTiện ích: kèm visor gương, visor trong, lớp lót tháo rời giặt được, hộp bảo quản.','3uzxgn','56fus5','active','2026-02-23 02:03:33','2026-03-16 23:03:42',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ay8bxe','Giày Cá Xe Đua Velocis','Trek Velocis — Giày đạp đường trường hiệu năng cao\r\nTrek Velocis là đôi giày đạp đường trường hiệu năng cao, kết hợp giữa sự thoải mái và truyền lực tối ưu — dành cho người đạp quyết tâm muốn cải thiện hiệu suất trên mọi chặng.\r\n\r\n \r\n\r\n\r\nTại sao chọn Trek Velocis \r\nVelocis mang nhiều công nghệ từ dòng Race Shop Limited hàng đầu của Trek, đem đến khả năng ôm chân chính xác, giảm điểm áp lực, và bản đế carbon composite hỗ trợ truyền lực hiệu quả — giúp bạn có lợi thế ngay trên mỗi lần đạp.\r\n\r\n \r\n\r\nĐặc điểm nổi bật\r\nVùng METNET giảm áp lực: Các khu vực co giãn được bố trí thông minh giúp giảm cảm giác tê, ở những điểm thường chịu áp lực nhiều khi đạp xe.\r\nForm Trek Pro Last tối ưu: Thiết kế form giày công thái học, ôm khít bàn chân nhưng vẫn giữ sự thoải mái, đặc biệt phù hợp cho những buổi đạp cường độ cao.\r\nHệ thống BOA L6: Núm vặn gọn nhẹ, cho phép điều chỉnh từng nấc nhỏ để đạt được độ vừa vặn chính xác nhất.\r\nĐế carbon composite (OCLV + sợi thủy tinh): Truyền lực hiệu quả, mang lại độ cứng lý tưởng giữa hiệu suất mạnh mẽ và cảm giác thoải mái.\r\nTương thích cleat 3 chấu: Phù hợp với hầu hết các loại bàn đạp đường trường chuyên dụng.\r\nGót cố định, lót chống trượt: Giữ gót chân chắc chắn, hạn chế trượt và nâng cao hiệu quả mỗi vòng đạp.\r\nVật liệu tái chế: Phần upper được sản xuất từ 30% vật liệu tái chế theo trọng lượng, thân thiện hơn với môi trường.\r\n ','8hgm3b','0dpoy0','active','2025-11-08 13:53:36','2026-03-16 23:03:34',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('b2z7zy','Joola Pro Pickleball Net (C)','Lưới pickleball JOOLA Pro Pickleball (C) là lưới di động chơi như được gắn chặt vào mặt đất. Khung thép dày khiến nó trở thành sản phẩm được ưa chuộng tại các trung tâm giải trí và câu lạc bộ thể thao vì khả năng dễ dàng chuyển đổi sân tennis thành sân pickleball. 6 bánh xe cho phép nó lăn từ phòng tập thể dục trong nhà ra sân ngoài trời. Chiều dài tiêu chuẩn 22ft để đạt được chiều cao khuyến nghị là 12in vượt ra ngoài các đường sân pickleball ở mỗi bên. Hệ thống căng cáp thép khổ lớn sử dụng tay quay để đạt chiều cao quy định là 36in ở hai bên trong khi dây đai ở giữa đảm bảo phần giữa đạt đến mốc 34in. Dải vinyl trên cùng duy trì độ bền, nhưng cũng mang lại khả năng chơi mà những người chơi pickleball mong đợi tại các giải đấu và câu lạc bộ hàng đầu. Khung sơn tĩnh điện có thể chịu được thiên nhiên và nhiều giờ chơi ngoài trời.','gfwht4','0lifzq','active','2025-12-12 09:55:11','2026-03-16 23:03:43',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('b726bv','Mũ Bơi Speedo Long Hair','MŨ BƠI SPEEDO LONG HAIR\r\nMũ Bơi Speedo Long Hair là người bạn đồng hành lý tưởng dành cho những người bơi có mái tóc dài. Sản phẩm được thiết kế với kích thước rộng rãi, giúp bạn dễ dàng che gọn mái tóc bên trong, tận hưởng cảm giác thoải mái và vừa vặn trong suốt buổi bơi. Đặt hàng ngay hôm nay để sở hữu Mũ Bơi Speedo Long Hair và trải nghiệm cảm giác thoải mái, tự tin khi bơi lội!\r\n\r\nTHÔNG SỐ\r\nThiết kế rộng rãi: Phù hợp với mái tóc trung bình đến dài\r\nChất liệu silicone cao cấp, mềm mại, thoải mái, không chứa latex, không gây kích ứng\r\nKhả năng đàn hồi tốt, độ bền lâu dài\r\nHạn chế tiếp xúc của tóc với nước hồ bơi có chứa clo, ngăn ngừa tóc hư tổn','b38g5m','h2v6o2','active','2025-12-02 19:54:40','2026-03-16 23:03:43',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('bhhmgf','Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Adidas Copa Pure Iii League','GIÀY ĐÁ BÓNG SÂN CỎ NHÂN TẠO NAM ADIDAS COPA PURE III LEAGUE\r\nTrải nghiệm kiểm soát bóng tuyệt đỉnh cùng cảm giác êm chân tối ưu với Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Adidas Copa Pure Iii League. Thiết kế hiện đại với chất liệu tổng hợp Fusionfeel mềm mại, ôm sát chân như da thật, kết hợp công nghệ in 3D ở mũi giày giúp kiểm soát bóng tuyệt vời trong từng tình huống. Đệm giữa EVA cùng đế cao su chắc chắn mang đến cảm giác êm ái, linh hoạt, hỗ trợ bạn thi đấu mượt mà, tự tin.\r\n\r\nTHÔNG SỐ\r\nForm dáng Regular Fit\r\nHệ thống buộc dây chắc chắn, phù hợp với nhiều kiểu chân.\r\nThân giày Fusionfeel bền bỉ, vân nổi tăng độ bám bóng.\r\nLưỡi gà thoáng khí, êm ái giúp giảm áp lực lên mu bàn chân.\r\nGót giày được lót đệm, hạn chế chấn thương khi di chuyển.\r\nĐệm giữa EVA giảm chấn, tăng độ êm vượt trội.\r\nĐế ngoài cao su bám tốt trên bề mặt cỏ nhân tạo.','eqj3j1','4e177a','active','2026-02-11 05:30:54','2026-03-16 23:03:36',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('bmwwlq','Bóng chuyền MIKASA V200W','V200W loại bóng chuyền chính thức của FIVB năm 2019.\r\nV200W có thiết kế khí động học 18 múi, cân bằng hoàn hảo giúp cải thiện chuyển động của bóng và giúp người chơi kiểm soát bóng tốt hơn. Bóng mới thiết kế dễ nhìn hơn trong nhà giúp tối ưu hóa chất lượng thi đấu và việc chơi trở nên thích thú hơn.\r\nBề mặt sợi siêu nhỏ lún sâu 2 lần giúp ổn định đường bay của bóng và tăng thêm khả năng kiểm soát bóng trong khi chức năng chống mồ hôi “Nano Balloon Silica” giúp bề mặt bóng không bị trơn trượt khi chơi với cường độ cao. Bóng vượt trên các tiêu chuẩn khắt khe của FIVB và đã vượt qua các quy trình kiểm tra nghiêm ngặt được thực hiện bởi các đội tuyển quốc gia và câu lạc bộ hàng đầu trong suốt sáu tháng','26j3e6','ea945m','active','2025-07-16 02:03:54','2026-03-16 23:03:43',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('bn100m','Quần Đệm Lót Underalls Liner','Quần đệm đạp xe Fast\'r Underalls Liner – Người bạn đồng hành hoàn hảo trên mọi cung đường\r\nBạn có từng gặp tình trạng mặc quần đạp xe lâu bị cọ xát khó chịu hay nóng bức? Fast\'r Underalls Liner sẽ là giải pháp hoàn hảo cho bạn. Thiết kế ôm sát, siêu nhẹ và co giãn 3 chiều giúp bạn thoải mái vận động, giữ mát suốt cả ngày dài.\r\n\r\nĐiểm nhấn là lớp đệm yên mềm mại, không gây kích ứng da, hỗ trợ bảo vệ vùng nhạy cảm khi bạn đạp xe trên những cung đường dài. Bạn sẽ cảm nhận được sự khác biệt ngay từ lần đầu sử dụng.\r\n\r\n \r\n\r\n \r\n\r\n\r\n \r\n \r\n\r\nTính năng nổi bật\r\nLiền mạch, không đường may – tránh gây cọ xát khó chịu khi đạp xe.\r\nĐệm yên mềm mại, không gây dị ứng, bảo vệ tối ưu vùng nhạy cảm.\r\nChất liệu co giãn 3 chiều, giữ cho bạn luôn mát mẻ và thoải mái.','z6x5ni','czsd09','active','2026-03-15 18:04:44','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('bogf8e','Chân Váy Nữ Adidas Club Pleat','CHÂN VÁY NỮ ADIDAS CLUB PLEAT\r\nThêm nét quyến rũ và năng động vào trận đấu của bạn với Chân Váy Nữ Adidas Club Pleat. Thiết kế xếp ly tinh tế mang lại sự nữ tính và chuyển động linh hoạt trên sân. Phần cạp chun co giãn giúp bạn di chuyển thoải mái, trong khi công nghệ CLIMACOOL thấm hút mồ hôi nhanh chóng, giữ cho cơ thể luôn khô thoáng và dễ chịu. Đặc biệt, quần lót tích hợp mang đến độ che phủ tối ưu, giúp bạn tự tin hơn khi di chuyển. Sản phẩm được làm từ 100% polyester tái chế, góp phần bảo vệ môi trường mà vẫn đảm bảo độ bền bỉ và hiệu suất cao\r\n\r\nTHÔNG SỐ\r\nThiết kế xếp ly thời trang giúp chuyển động linh hoạt và tạo phong cách thể thao năng động\r\nCông nghệ CLIMACOOL thấm hút mồ hôi nhanh, giữ cơ thể khô thoáng suốt trận đấu\r\nCạp chun co giãn tạo cảm giác thoải mái, vừa vặn với nhiều dáng người\r\nQuần lót tích hợp giúp tăng cường độ che phủ và sự tự tin khi vận động\r\nChất liệu 100% polyester tái chế, thân thiện với môi trường nhưng vẫn bền bỉ và nhẹ nhàng\r\nKiểu dáng vừa vặn (Regular Fit)','cf5q51','4e177a','active','2026-03-12 17:23:27','2026-03-16 23:03:36',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('bvgt3k','Quần áo bóng chuyền Nam Beyono Heron II','','ehrxii','82c21b','active','2026-01-02 04:11:51','2026-03-16 23:03:34',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('bworcn','Giày Chạy Bộ Nam Mizuno Wave Rider 27 Ssw','Đưa những buổi chạy bộ lên một tầm cao mới với Giày Chạy Bộ Nam Mizuno Wave Rider 27 SSW. Mẫu giày này được nâng cấp với phần upper dệt kim co giãn nhẹ nhàng, ôm chân vừa vặn, kết hợp cùng sự cải tiến ở phần gót chân, mang đến cảm giác thoải mái tuyệt vời trong từng sải bước.\r\n\r\nTHÔNG SỐ\r\nMIZUNO ENERZY (ĐỆM): Đem lại sự linh hoạt và đa dạng trong từng chuyển động, đồng thời duy trì độ êm ái và khả năng phục hồi, giúp bạn nâng cao hiệu suất chạy bộ\r\nMIZUNO WAVE®: Mặt đế sóng MIZUNO WAVE® giúp phân tán lực tác động, tạo sự ổn định và giảm chấn tối ưu\r\nĐế ngoài X10: Cao su carbon bền bỉ, chống mài mòn tốt\r\nChất liệu thân thiện môi trường: Sử dụng vật liệu tái chế\r\nĐộ chênh lệch: 12mm\r\nĐộ cao đế: Bàn chân trước 26mm / Gót chân 38mm\r\nTrọng lượng: 298g (Size 9)\r\nChất liệu: Vải dệt kim co giãn\r\nLoại giày: Neutral (trung tính)','lskyuc','69f937','active','2025-06-17 23:42:37','2026-03-16 23:03:39',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('c2iy8v','Quần Ngắn Thể Thao Nam Adidas Club Tennis Climacool 3-Stripes','QUẦN NGẮN THỂ THAO NAM ADIDAS CLUB TENNIS CLIMACOOL 3-STRIPES\r\nQuần Ngắn Thể Thao Nam Adidas Club Tennis Climacool 3-Stripes mang đến cảm giác mát mẻ, khô ráo và luôn sẵn sàng cho mọi trận đấu. Thiết kế thể thao năng động với phần đáy mở rộng giúp bạn di chuyển linh hoạt, thoải mái bứt phá từng pha bóng. Công nghệ CLIMACOOL thấm hút mồ hôi hiệu quả, giữ thân nhiệt ổn định để bạn tự tin tập luyện. Nét nổi bật với sọc 3-Stripes nổi bật ở một bên, khẳng định phong cách thể thao chuyên nghiệp. Sản phẩm sử dụng 100% chất liệu polyester tái chế, góp phần bảo vệ môi trường và giảm thiểu lãng phí.\r\n\r\nTHÔNG SỐ\r\nDáng regular fit: Vừa vặn, không bó sát\r\nLưng thun đàn hồi, có dây rút tiện lợi\r\n100% polyester tái chế\r\nCông nghệ CLIMACOOL thoáng khí, thấm hút mồ hôi\r\nĐáy quần lưới tăng độ thoáng mát','2sx26h','4e177a','active','2025-09-16 09:12:01','2026-03-16 23:03:37',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('c2vmhy','Giày Bóng Rổ Nam Nike Jordan Heir Series','GIÀY BÓNG RỔ NAM NIKE JORDAN HEIR SERIES\r\nTối ưu từng pha bóng cùng Giày Bóng Rổ Nam Nike Jordan Heir Series – lựa chọn được các cầu thủ nữ truyền cảm hứng. Thiết kế linh hoạt, hạ thấp trọng tâm giúp kiểm soát trận đấu. Đệm giữa linh hoạt tăng khả năng di chuyển, khung ngoài ôm chân vững chắc, sẵn sàng tự tin bứt phá và đổi hướng cực nhanh.\r\n\r\nTHÔNG SỐ\r\nĐệm giữa Cushlon 3.0 dạng thả rời mang lại cảm giác êm, nhẹ, nhạy, tăng linh hoạt khi chuyển động; thiết kế sát mặt đất nổi bật so với các mẫu bóng rổ hiệu suất khác.\r\nĐế cao su với hoa văn xương cá tăng độ bám, hỗ trợ dừng đột ngột và đổi hướng chính xác.\r\nThân giày dùng chất liệu dệt nhẹ, siêu thoáng khí và êm ái.\r\nPhần trên có thêm da tổng hợp giúp giày bền chắc hơn.\r\nPhiên bản PF thiết kế rộng, phù hợp sân ngoài trời.','xijocy','962d78','active','2024-12-07 13:53:16','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('c62dk5','Joola Elemental Pickleball Net','Tự tạo sân chơi pickleball của riêng bạn ở bất cứ nơi nào bạn đến với Lưới Pickleball JOOLA Elemental. Hệ thống dễ vận chuyển này có chiều cao theo quy định là 36in và chiều dài được USAPA khuyến nghị là 22ft. Chiều dài 22ft cung cấp thêm 12 inch ở cả hai bên để có thêm phạm vi che phủ của lưới. Được thiết kế với độ bền cao, lưới có vải nylon và lưới PPVC không thắt nút. Các chân thép liên kết rộng, cong giúp tăng độ ổn định. Lắp đặt và tháo dỡ chỉ trong vài phút. Túi đựng được gia cố giúp việc lắp đặt này cực kỳ dễ vận chuyển.','gfwht4','0lifzq','active','2025-09-29 17:32:46','2026-03-16 23:03:38',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('c73fx4','Áo Thun Nam Under Armour Hoops Certified','ÁO THUN NAM UNDER ARMOUR HOOPS CERTIFIED\r\nÁo Thun Nam Under Armour Hoops Certified có họa tiết lấy cảm hứng từ môn bóng rổ, ấn tượng và đầy năng động. Không dừng ở đó, chiếc áo thun họa tiết của Under Armour còn có chất liệu cotton mềm mại, dày dặn mang lại cảm giác dễ chịu suốt ngày dài.\r\n\r\nTHÔNG SỐ\r\nChất liệu vải pha cotton dày dặn, mềm mại mang lại sự thoải mái suốt cả ngày.\r\nCổ áo bo gân.\r\n60% Cotton/40% Polyester.','3pxej5','1791f2','active','2025-12-01 20:51:52','2026-03-16 23:03:42',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ccbtk7','Đồ Bơi Thể Thao Một Mảnh Nữ Nike Swim Crossback','ĐỒ BƠI THỂ THAO MỘT MẢNH NỮ NIKE SWIM CROSSBACK\r\nSneakerkini 2.0 được thiết kế với phần “dây giày” đàn hồi cải tiến, đặt đúng vị trí cho những tín đồ đích thực của sneaker. Thiết kế đáy kiểu “cheeky” cùng đường cắt cao ở phần đùi giúp bạn di chuyển linh hoạt tự nhiên, đồng thời tăng thêm phần cuốn hút.\r\n\r\nTHÔNG SỐ\r\nSản phẩm được làm từ ít nhất 75% vật liệu tái chế.\r\nThiết kế dây đeo chéo lưng có thể điều chỉnh cố định cùng phần lưng hở giúp giảm thiểu sự phân tâm.\r\nĐệm ngực nhẹ mang lại cảm giác thoải mái cả trong và ngoài nước.\r\nMiếng lót ngực có thể tháo rời, tạo độ che phủ thoải mái.\r\nThiết kế đáy kiểu “cheeky” mang lại độ che phủ tối thiểu — gợi cảm và nổi bật.\r\n83%17 Recycled Poly%Elas Knit - Solid','sgd0rk','962d78','active','2024-12-08 02:59:12','2026-03-16 23:03:35',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('cd01i4','Quần Dài Thể Thao Nữ Nike Fast Mid-Rise With Pockets','QUẦN ÔM NỮ NIKE FAST MID-RISE 7/8 RUNNING - ĐEN\r\nQuần Ôm Nữ Nike Fast Mid-Rise 7/8 Running được kết hợp hoàn hảo giữa phong cách thời trang, chất liệu cao cấp và các tính năng ưu việt. Chiếc quần này là sự lựa chọn hoàn hảo cho các nữ vận động viên yêu thích yoga, gym, chạy bộ hoặc các hoạt động thể thao khác. Đặt hàng ngay hôm nay để trải nghiệm sự thoải mái, tự tin và năng động cùng Quần Ôm Nữ Nike Fast Mid-Rise 7/8 Running!\r\n\r\nTHÔNG SỐ\r\nThân chính: 80% polyester/20% elastane\r\nMảng lưới: 94% polyester/6% elastane\r\nLớp lót gusset: 100% polyester\r\nCông nghệ Dri-FIT giúp thấm hút mồ hôi\r\nMặt vải co giãn linh hoạt\r\nLưới thoáng khí phía sau đầu gối tăng cường khả năng lưu thông khí\r\nThiết kế lưng giữa, ôm vừa vặn và thoải mái vào phần eo\r\nNgăn đựng điện thoại và các vật dụng cá nhân\r\nĐộ dài: 7/8 (tới mắt cá chân)','m40hn6','962d78','active','2025-05-04 17:26:47','2026-03-16 23:03:38',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('cihcuv','Vớ Thể Thao Under Armour Playmaker Mid','VỚ THỂ THAO UNDER ARMOUR PLAYMAKER MID\r\n\"Mọi sản phẩm có tên tôi đều phải tốt—phải giúp bạn chơi tốt hơn và là một phần trong sứ mệnh thay đổi cuộc chơi của chúng tôi.\" – Stephen Curry, một trong những cầu thủ bóng rổ xuất sắc nhất lịch sử NBA. Chính vì thế, sản phẩm hợp tác mang tên Curry - Vớ Thể Thao Under Armour Playmaker Mid hứa hẹn sẽ cho bạn trải nghiệm khác biệt. Vớ nhẹ, khô cực nhanh và được tích hợp hỗ trợ vòm chân giúp giảm mệt mỏi.\r\n\r\nTHÔNG SỐ\r\nChất liệu vải dệt kim với sợi ArmourDry® khô cực nhanh giúp đôi chân bạn nhẹ nhàng, khô ráo & mát mẻ\r\nSản phẩm thấm hút mồ hôi hai chiều với sợi ArmourGrip® ở lòng bàn chân, chống trơn trượt khi đi tất và giày\r\nSợi ArmourDry® giúp phân tán độ ẩm, khiến mồ hôi nhanh chóng bay hơi\r\nĐệm ở gót chân giảm đau mỏi khi di chuyển nhiều\r\nCông nghệ khử mùi giúp ngăn mùi trong tất\r\nChất liệu lưới thoáng khí ở đầu ngón chân\r\nĐệm tối đa ở ngón chân, lòng bàn chân và gót chân, tăng cường khả năng bảo vệ\r\nĐệm mắt cá chân 360°, tăng độ ổn định và vừa vặn khi mang giày\r\nCác đường viền gót chân được thiết kế bọc quanh bàn chân\r\nThiết kế trái phải riêng biệt\r\nChất liệu: 94% Polyester/4% Elastane/2% Nylon','f4vq37','1791f2','active','2025-08-15 21:04:57','2026-03-16 23:03:41',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ciqsjo','Giày bóng chuyền nam Asics NETBURNER BALLISTIC FF MT 4','Giày thể thao trong nhà NETBURNER BALLISTIC™ FF MT 4 được thiết kế để giúp tăng tốc độ và sự linh hoạt cho các chuyển động đa hướng.\r\n\r\nCông nghệ SPEEDTRUSS™ được thiết kế cho khả năng tăng tốc nhanh và các động tác xoay người, cho phép bạn di chuyển nhanh hơn.\r\n\r\nThiết kế đế ngoài PRECISION SOLE™ sử dụng ứng dụng mô hình hóa 3D để tạo ra mẫu đế ngoài mới, đạt được sự cân bằng tốt nhất giữa độ linh hoạt, trọng lượng nhẹ và độ bám; kết hợp với công nghệ X-GUIDANCE™ trong các rãnh uốn cong để cung cấp thêm sự linh hoạt trong các chuyển động đa hướng.\r\n\r\nCuối cùng, lớp đế giữa FLYTEFOAM™ với độ chênh lệch chiều cao gót 15mm giúp cải thiện sự thoải mái và tốc độ di chuyển.','m65tw5','3aa1e6','active','2025-11-22 08:01:37','2026-03-16 23:03:40',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('cj4pzy','Áo Thun Nam Nike Court Victory Dri-Fit Print','ÁO THUN NAM NIKE COURT VICTORY DRI-FIT PRINT\r\nTự tin bung sức với Áo Thun Nam Nike Court Victory Dri-Fit Print – thiết kế thể thao năng động, chất vải mềm nhẹ, thấm hút mồ hôi giúp cơ thể luôn khô thoáng suốt cú đánh. Đường may lệch vai đặc trưng cho vận động tennis linh hoạt hơn, cùng phần lưới giãn ở sườn tăng cường chuyển động. Phù hợp cho mọi trận đấu, đem lại cảm giác thoải mái và sẵn sàng chinh phục mỗi ngày.\r\n\r\nTHÔNG SỐ\r\nCông nghệ Nike Dri-FIT thấm hút mồ hôi, giúp khô thoáng nhanh\r\nPhom dáng tiêu chuẩn vừa vặn, không bó sát\r\nChất vải knit mềm nhẹ, thoáng khí\r\nLưới giãn 2 bên tăng linh hoạt khi vận động\r\nChất liệu piqué-knit\r\nĐường may vai lệch giúp chuyển động dễ dàng\r\nLogo Swoosh thêu nổi bật\r\nChất liệu: 100% polyester\r\nGiặt máy an toàn','00f3pn','962d78','active','2025-07-01 15:14:51','2026-03-16 23:03:40',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ctu2pl','Quần Bơi Thể Thao Nữ Nike Swim Hipster','QUẦN BƠI THỂ THAO NỮ NIKE SWIM HIPSTER\r\nHãy chọn chiếc Quần Bơi Thể Thao Nữ Nike Swim Hipster sang trọng này với eo thấp thoải mái và độ che phủ tiêu chuẩn. Kết hợp với bất kỳ chiếc áo terry để tạo nên sự hoàn hảo từ đầu đến chân.\r\n\r\nTHÔNG SỐ\r\nSản phẩm được làm từ ít nhất 75% vật liệu tái chế.\r\nĐộ che phủ tiêu chuẩn lý tưởng cho mọi hoạt động nước.\r\nĐáy thấp ngồi thấp qua hông mang lại cảm giác thoải mái.\r\nCó lớp lót để cải thiện độ vừa vặn và an toàn.','37u1i1','962d78','active','2025-12-12 05:56:14','2026-03-16 23:03:39',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('cvbxln','Quần Ngắn Thể Thao Nữ Mizuno 2In1 4.5','QUẦN NGẮN THỂ THAO NỮ MIZUNO 2IN1 4.5\r\nQuần Ngắn Thể Thao Nữ Mizuno 2In1 4.5 Inch là người bạn đồng hành lý tưởng cho các nữ vận động viên đam mê chạy bộ. Sản phẩm mang đến sự thoải mái vượt trội nhờ chất liệu vải dệt kim co giãn nhẹ, cho phép bạn chuyển động dễ dàng và tự tin chinh phục mọi cung đường. Điểm nổi bật của chiếc quần này là lớp quần lót bên trong. Lớp lót này cung cấp khả năng hỗ trợ nhẹ, giúp bạn cảm thấy an toàn và thoải mái trong suốt quá trình chạy. Công nghệ DryLite độc đáo của Mizuno đảm bảo mồ hôi được thấm hút hiệu quả, mang lại cảm giác dễ chịu ngay cả khi vận động cường độ cao.\r\nTHÔNG SỐ\r\nLớp vải dệt kim co giãn nhẹ cho phép bạn chuyển động tự do, không bị cản trở\r\nLớp quần compression bên trong ôm sát, hỗ trợ nhẹ nhàng, giảm thiểu chấn thương và đau mỏi cơ bắp\r\nQuần có túi zip phía sau giúp bạn đựng an toàn các vật dụng cá nhân cần thiết trong khi chạy\r\nCác chi tiết phản quang tăng cường khả năng nhận diện khi chạy trong điều kiện thiếu sáng\r\nCông nghệ DryLite mang đến sự thoải mái và khô thoáng tối ưu cho hiệu suất vận động tốt nhất\r\nQuần cạp chun với dây rút điều chỉnh độ vừa vặn theo ý thích\r\nChiều dài quần (size M): 4.5 inch\r\nThành phần: Ít nhất 50% sợi polyester tái chế','m40hn6','69f937','active','2026-03-04 04:03:39','2026-03-16 23:03:41',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('cw9ksn','Giày Tennis Nữ Nike Vapor Lite 3 Hard Court','GIÀY TENNIS NỮ NIKE VAPOR LITE 3 HARD COURT\r\nĐược ra mắt lần đầu trên sân tennis những năm 90 và gắn liền với phong cách đầy cá tính của các ngôi sao thời bấy giờ, mẫu Hot Lava nay đã trở lại trong phiên bản Giày Tennis Nữ Nike Vapor Lite 3 Hard Court đặc biệt. Giữ nguyên vẻ phá cách độc đáo từng làm bao người mê mẩn - kết hợp hiệu suất thi đấu hiện đại, đôi giày này sở hữu lớp đế ngoài cải tiến với hợp chất cao su mới, sẵn sàng giúp bạn tỏa sáng và bứt phá trên sân đấu.\r\n\r\nTHÔNG SỐ\r\nMũi giày được gia cố bằng hợp chất cao su mới siêu bền, tăng tuổi thọ ngay cả ở những vị trí mài mòn nhiều nhất.\r\nVải lưới kỹ thuật cải tiến, cứng cáp và thoáng khí vượt trội, mang lại cảm giác thoải mái cả ngày.\r\nThiết kế chuyên biệt cho bề mặt sân cứng, nâng cao hiệu suất thi đấu.\r\nĐế giữa đệm foam mềm mại, hỗ trợ tối ưu cho từng bước di chuyển.','uicjou','962d78','active','2024-12-02 04:12:03','2026-03-16 23:03:42',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('cwyiya','Giày Tennis Nữ Asics Gel-Tactic 13','GIÀY TENNIS NỮ ASICS GEL-TACTIC 13\r\nGiày Tennis Nữ Asics Gel-Tactic 13 là lựa chọn lý tưởng cho những ai tìm kiếm sự ổn định và tự tin trong từng bước di chuyển. Với thiết kế cải tiến, đôi giày này mang lại lực bám vượt trội, giúp bạn dễ dàng kiểm soát và chuyển hướng trên sân. Công nghệ STABLETRUSS™ giúp cố định bàn chân, hỗ trợ tốt từ mũi đến gót trong các động tác di chuyển ngang. Đế ngoài được thiết kế ôm sát, tăng sự ổn định và độ bám trên nhiều bề mặt khác nhau - nhờ các rãnh tròn và ngang, tối ưu hóa chuyển động và cân bằng trọng lượng, mang đến cảm giác vững vàng và linh hoạt.\r\n\r\nTHÔNG SỐ\r\nThân giày vải lưới phủ màng không đường may, tạo cảm giác nhẹ và thoáng khí.\r\nĐế ngoài ôm sát tăng độ ổn định khi di chuyển ngang.\r\nCông nghệ GEL™ hấp thụ lực, giảm chấn động cho mỗi bước chân.\r\nTrang bị STABLETRUSS™ giúp tăng ổn định khi chuyển động sang hai bên.\r\nĐế ngoài với họa tiết tròn tăng độ bám chắc, hỗ trợ di chuyển linh hoạt.\r\nLót giày nhuộm solution dye giúp tiết kiệm nước tới 33% và giảm 45% lượng khí thải so với công nghệ truyền thống.','uicjou','3aa1e6','active','2025-10-03 23:44:54','2026-03-16 23:03:35',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('cx8abb','Giày Bóng Rổ Unisex Under Armour Curry 4 Low Flotro','GIÀY BÓNG RỔ UNISEX UNDER ARMOUR CURRY 4 LOW FLOTRO\r\nChúng tôi đã kết hợp khả năng đệm UA Flow nhẹ nhàng và độ bám tốt với kiểm soát vững chãi của mẫu giày bóng rổ thấp Curry 4 yêu thích của bạn. Vì sao? Bởi vì sự kết hợp này thúc đẩy bạn vượt xa so với đối thủ trong suốt cả trận đấu.\r\n\r\nTHÔNG SỐ\r\nUpper bằng sợi dệt kỹ thuật nhẹ, thoải mái và thoáng khí\r\nLớp phủ TPU chiến lược để tăng thêm sự hỗ trợ và độ bền\r\nGót chân bằng chất liệu bọt biển giúp tăng cường sự êm ái và tăng cường độ bám\r\nĐế lót bằng bọt biển mềm mịn giúp tạo sự thoải mái cho bàn chân\r\nThanh chắn Pebax® tích hợp giúp tạo sự ổn định cho phần giữa chân\r\nCông nghệ đệm UA Flow siêu nhẹ, đàn hồi và mang lại độ bám tuyệt vời\r\nĐế ngoài bền bỉ UA Flow giúp tạo cảm giác sân trượt tốt hơn, giúp bạn di chuyển, cắt bóc và dừng/khởi động nhanh hơn bao giờ hết\r\nTrọng lượng: 12.8 ounce / 363g\r\nKiểu dây giày: thông thường','xijocy','1791f2','active','2024-10-31 09:53:10','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('cyvoey','Vợt cầu lông Yonex Astrox 66','Vợt cầu lông Yonex Astrox 66 là cây vợt trong dòng vợt cao cấp của Yonex, nằm trong Series vợt Astrox nổi tiếng, được Yonex cho ra mắt phù hợp với phái nữ thích vợt có khối lượng trung bình không quá nặng cũng như không quá nhẹ và thích đập cầu, theo lối chơi tấn công.','50r71o','7d1050','active','2024-10-27 02:34:46','2026-03-16 23:03:42',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('d219op','Áo Thun Chạy Bộ Nam Under Armour Seamless Stride','ÁO THUN NAM UNDER ARMOUR SEAMLE\r\nSử dụng lớp lưới phân bố theo từng vùng trên cơ thể, Áo Thun Nam Under Armour Seamle không chỉ giúp thông thoáng ở những nơi cần thiết mà còn mang lại cảm giác thoải mái hơn với số lượng đường may ít hơn. Đây thực sự là một trong những trải nghiệm tập luyện thoải mái nhất mà bạn từng trải qua.\r\n\r\nTHÔNG SỐ\r\nChất liệu: 64% Nylon/36% Polyester\r\nChất liệu vải mới, mềm mại hơn với lưới thông hơi được thiết kế kỹ thuật, phân bố đều tại những vị trí cần thiết nhất\r\nThiết kế gần như không có đường may giúp loại bỏ sự cọ xát trên da\r\nChất liệu giúp hút ẩm và khô nhanh, giữ cho cơ thể luôn thoải mái trong suốt quá trình tập luyện\r\nChi tiết phản quang giúp tăng cường khả năng nhận biết trong những buổi chạy khi ánh sáng yếu','cxo8ft','1791f2','active','2025-07-24 12:30:41','2026-03-16 23:03:36',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('d4dfwy','Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Adidas Predator Club','GIÀY ĐÁ BÓNG SÂN CỎ NHÂN TẠO NAM ADIDAS PREDATOR CLUB\r\nKhám phá sự khác biệt giữa việc chỉ cố gắng ghi bàn và tự tin sẽ chiến thắng với Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Adidas Predator Club – thiết kế dành riêng cho những bàn thắng. Đôi giày sở hữu phần thân trên tổng hợp với lớp phủ Strikeprint độc quyền, mang lại cảm giác bám bóng vượt trội và kiểm soát bóng tối ưu. Đế ngoài bằng cao su bám sân chuyên biệt sẽ giúp bạn sẵn sàng cho những pha dứt điểm đỉnh cao trên mặt sân cỏ nhân tạo.\r\n\r\nTHÔNG SỐ\r\nKiểu dáng vừa vặn, ôm chân thoải mái.\r\nThiết kế dây buộc chắc chắn, dễ điều chỉnh.\r\nThân giày tổng hợp cùng bề mặt Strikeprint giúp kiểm soát bóng tốt hơn.\r\nLớp lót vải mềm mại, tăng sự êm ái khi di chuyển.\r\nĐế cao su chuyên biệt cho sân cỏ nhân tạo, tăng độ bám và linh hoạt.','eqj3j1','4e177a','active','2024-12-03 02:58:58','2026-03-16 23:03:37',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('d9d965','Quần Ngắn Thể Thao Nam Puma Teamrise','QUẦN NGẮN THỂ THAO NAM PUMA TEAMRISE\r\nQuần Ngắn Thể Thao Nam Puma Teamrise mang phong cách năng động với thiết kế thời thượng, giúp bạn luôn tự tin và thoải mái trên sân tập. Lưng thun co giãn kết hợp dây rút điều chỉnh dễ dàng, cùng công nghệ dryCELL thấm hút mồ hôi hiệu quả, giữ cơ thể luôn khô thoáng. Logo PUMA đặc trưng tạo điểm nhấn nổi bật, phù hợp cho mọi hoạt động thể thao.\r\n\r\nTHÔNG SỐ\r\nChất liệu: 100% polyester\r\nCông nghệ dryCELL thấm hút mồ hôi, giữ khô thoáng khi vận động\r\nDáng chuẩn thể thao\r\nLưng thun co giãn, dây rút điều chỉnh\r\nLogo PUMA Cat in nhiệt nổi bật ở ống quần bên trái','yrgs2k','a8073f','active','2025-05-17 20:32:55','2026-03-16 23:03:34',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('djtb1y','Áo Đá Bóng Nam Adidas Arsenal','ÁO ĐÁ BÓNG NAM ADIDAS ARSENAL\r\nMang biểu tượng sấm sét huyền thoại trở lại, áo đá bóng nam Adidas Arsenal gây ấn tượng mạnh với họa tiết xanh nhạt – xanh navy hiện đại phủ toàn bộ bề mặt. Thiết kế lấy cảm hứng từ những khoảnh khắc rực lửa trong lịch sử Pháo Thủ, kết hợp chất liệu interlock mềm mại và công nghệ AEROREADY thấm hút mồ hôi, giúp fan luôn thoải mái khi cổ vũ đội bóng. Logo pháo thêu nổi trước ngực khẳng định niềm tự hào Arsenal trong từng nhịp bóng lăn.\r\n\r\nTHÔNG SỐ\r\nDáng slim fit\r\nCổ tròn (crewneck)\r\nChất liệu 100% polyester tái chế\r\nCông nghệ AEROREADY kiểm soát ẩm\r\nLogo pháo Arsenal thêu nổi','sd2dby','4e177a','active','2024-12-26 08:03:30','2026-03-16 23:03:34',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('doz2py','Vớ Adidas Milano 23 ','ĐÔI TẤT THẤM HÚT ẨM CÓ SỬ DỤNG CHẤT LIỆU TÁI CHẾ.\r\nGiờ đây bạn có thể trút bỏ mọi vướng bận trên đôi chân và tập trung cho màn thể hiện đẹp mắt. Đôi tất đá bóng cao cổ hiệu năng cao này của adidas có các vùng nâng đỡ vòm bàn chân và vùng đệm tại những vị trí cần thiết. Công nghệ AEROREADY thấm hút ẩm giúp đôi chân bạn luôn khô ráo khi trau chuốt kỹ năng.\r\n\r\nLàm từ một loạt chất liệu tái chế và có chứa tối thiểu 40% thành phần tái chế, sản phẩm này đại diện cho một trong số rất nhiều các giải pháp của chúng tôi hướng tới chấm dứt rác thải nhựa.\r\n\r\nTHÔNG SỐ\r\nChiều dài 1/2 bắp chân\r\n99% polyester tái chế, 1% elastane\r\nCác vùng đệm\r\nAEROREADY\r\nGấu quần bo gân\r\nNâng đỡ vòm bàn chân\r\nVải lưới thoáng khí\r\nĐường may phẳng ở mũi chân','1wyf0i','4e177a','active','2025-04-08 20:38:54','2026-03-16 23:03:38',5,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('du7h7q','Banh Bóng Đá Adidas World Cup Mini','BANH BÓNG ĐÁ ADIDAS WORLD CUP MINI\r\nMột hình ảnh ngoạn mục lần đầu xuất hiện tại các sự kiện thể thao khắp châu Mỹ – làn sóng “la ola” mang tính biểu tượng – chính là nguồn cảm hứng cho thiết kế 4 mảnh liền mạch của Banh Bóng Đá Adidas World Cup Mini. Hoàn hảo để bạn phô diễn kỹ năng mọi lúc mọi nơi, bóng có lõi bọt xốp và kích thước nhỏ gọn. Lấy cảm hứng từ diện mạo của quả bóng chính thức FIFA World Cup 26™, bề mặt bóng được dập nổi chi tiết, kết hợp cùng biểu tượng và màu sắc của ba quốc gia đồng đăng cai giải đấu.\r\n\r\nTHÔNG SỐ\r\n100% polyurethane nhiệt dẻo tái chế (TPU)\r\nLõi bọt xốp đặc\r\nLogo FIFA World Cup 26™ in nổi bật\r\nKhông cần bơm hơi','rm0g8a','4e177a','active','2025-05-03 12:16:21','2026-03-16 23:03:42',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('dw8bp9','Áo Đá Bóng Nam Adidas Liverpool Fc Sân Thứ Ba Mùa Giải 25/26','ÁO ĐÁ BÓNG NAM ADIDAS LIVERPOOL FC SÂN THỨ BA MÙA GIẢI 25/26\r\nÁo Đá Bóng Nam Adidas Liverpool Fc Sân Thứ Ba Mùa Giải 25/26 là sự kết hợp hiện đại giữa phong cách cổ điển và tinh thần thể thao sôi động. Thiết kế sọc dọc tông xanh Equipment nổi bật, biểu tượng câu lạc bộ và logo Trefoil cổ điển xuất hiện đầy ấn tượng trên ngực áo. Công nghệ AEROREADY giúp kiểm soát mồ hôi, mang lại cảm giác khô ráo và thoải mái khi di chuyển – hoàn hảo cho fan Liverpool đam mê năng động trên mọi hành trình.\r\n\r\nTHÔNG SỐ\r\nKiểu dáng ôm vừa (Slim fit)\r\nCổ tròn thể thao (Crewneck)\r\nChất liệu: 100% polyester tái chế\r\nCông nghệ AEROREADY thấm hút mồ hôi\r\nLogo Trefoil thêu nổi và logo câu lạc bộ dệt\r\nBa sọc dọc cổ điển Adidas\r\nHuy hiệu Liverpool FC dệt','sd2dby','4e177a','active','2025-07-07 03:49:22','2026-03-16 23:03:38',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('e19w4h','Quần Short Men Elite Cargo Short','Men Elite Cargo Shorts – Quần đạp xe túi hông tiện dụng, thoải mái cho mọi hành trình\r\nCargo Shorts là mẫu quần đạp xe có túi hông tiện lợi, thiết kế cho những chuyến đạp dài Road, Gravel và Bikepacking. Với chất liệu co giãn cao, bền bỉ, thoáng và đàn hồi tốt, quần mang lại sự dễ chịu tối ưu ngay cả khi đạp nhiều giờ. Đệm công thái học êm ái giúp giảm áp lực và tăng hiệu suất cho những ngày chinh phục đường dài.\r\n\r\n \r\n\r\nĐặc điểm nổi bật\r\nVải co giãn đa chiều, hồi phục tốt, giữ form lâu dài.\r\nChống xù, chống mài mòn, bền bỉ với cường độ tập cao.\r\nKhông bị lộ và không mỏng dần theo thời gian.\r\nDây đeo bản rộng êm vai, thoáng khí, thoải mái cả ngày.\r\nMiếng đệm công thái học hỗ trợ tối ưu cho ride dài.\r\nBo chân đàn hồi Italy + lớp in gripper chống tuột.\r\nChi tiết phản quang tăng an toàn khi ánh sáng yếu.\r\n2 túi hông lớn tiện để điện thoại, gel, đồ nhỏ cần thiết.','z6x5ni','czsd09','active','2025-05-03 14:39:37','2026-03-16 23:03:36',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('e4jd0q','Giày Bóng Rổ Nam Nike Jordan Tatum 4 Pf','GIÀY BÓNG RỔ NAM NIKE JORDAN TATUM 4 PF\r\nTatum 4 là phiên bản hoàn thiện liên tục, luôn đồng hành cùng sự phát triển trong từng bước di chuyển của bạn. Với thanh TPU dưới bàn chân tăng cường sự ổn định vượt trội, nhưng đây vẫn là đôi giày nhẹ nhất trong dòng sản phẩm của chúng tôi. Thiết kế lấy cảm hứng từ giày thể thao chuyên nghiệp giúp bạn tận hưởng độ phản hồi nhanh và cảm giác bật nhảy linh hoạt, luôn giữ lợi thế trong mọi trận đấu.\r\n\r\nTHÔNG SỐ\r\nThân giày làm từ chất liệu vải bền chắc nhưng vẫn linh hoạt, ôm sát bàn chân.\r\nLớp đệm Cushlon kết hợp bộ đệm Air Zoom đàn hồi giúp bàn chân luôn êm ái, di chuyển nhẹ nhàng.','xijocy','962d78','active','2024-10-10 08:36:58','2026-03-16 23:03:40',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('e5jxwq','Vớ Thể Thao Adidas Adi 24 Sock','VỚ THỂ THAO ADIDAS ADI 24 SOCK\r\nTăng cường hiệu suất với vớ thể thao Adidas Adi 24 Sock, trang bị công nghệ AEROREADY và đệm mềm mại, giữ chân bạn khô ráo và thoải mái. Thiết kế dài đến đầu gối bảo vệ tối ưu và giảm thiểu sự di chuyển của vớ. Đặc biệt, sản phẩm làm từ ít nhất 50% vật liệu tái chế, giúp bảo vệ môi trường.\r\n\r\nTHÔNG SỐ\r\nVớ dài đến đầu gối\r\nChất liệu: 83% polyester (tái chế), 12% cotton, 5% elastane\r\nCông nghệ AEROREADY giúp hút ẩm hiệu quả, giữ cho đôi chân của bạn luôn khô ráo và thoải mái trong suốt trận đấu\r\nĐệm lót gót chân và đầu ngón chân giúp bảo vệ đôi chân của bạn khỏi áp lực từ đinh giày','1wyf0i','4e177a','active','2026-01-28 12:14:38','2026-03-16 23:03:43',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('e75a4j','Quần Ngắn Nam Adidas Ergo','QUẦN NGẮN NAM ADIDAS ERGO\r\nKhám phá quần ngắn Adidas Ergo từ bộ sưu tập Gameset, lý tưởng cho những ai yêu thích phong cách và hiệu suất trên sân tennis. Với công nghệ HEAT.RDY giữ cơ thể mát mẻ, thiết kế hỗ trợ chuyển động và túi quần thông minh để giữ bóng, quần Ergo giúp bạn thoải mái và tập trung trong mọi trận đấu.\r\n\r\nTHÔNG SỐ\r\nKiểu dáng vừa vặn, thoải mái (Regular Fit) và cạp cao vừa\r\nCạp chun thoáng khí có dây rút\r\nVải dệt trơn làm từ 84% polyester tái chế, 16% elastane\r\nLớp lót bằng vải lưới\r\nCông nghệ HEAT.RDY, quần ngắn Adidas Ergo giúp làm mát cơ thể trong những trận đấu căng thẳng, giữ cho bạn luôn khô ráo và thoải mái ngay cả khi nhiệt độ tăng cao.\r\nCác túi trước tiện lợi\r\nCác đường cắt tối ưu','2sx26h','4e177a','active','2024-10-09 15:34:05','2026-03-16 23:03:39',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('e9u4hd','Găng Tay Thể Thao Puma Ultra Play Rc','GĂNG TAY THỂ THAO PUMA ULTRA PLAY RC\r\nChinh phục mọi thử thách trên sân cỏ với Găng Tay Thủ Môn Puma Ultra Play RC. Được thiết kế để hỗ trợ các pha cứu thua ngoạn mục, đôi găng tay này trang bị lớp mút dày 2mm, đem lại độ bám dính tuyệt vời trong mọi điều kiện thời tiết.  Mặt lưng bằng cao su dập nổi đảm bảo sự linh hoạt tối đa cho đôi tay bạn, giúp bạn thoải mái thực hiện các kỹ thuật bắt bóng khó khăn.\r\n\r\nTHÔNG SỐ\r\nLớp đệm mút dày 2mm bám dính tuyệt vời\r\nMặt lưng bằng cao su dập nổi tăng tính linh hoạt\r\nQuai đeo Velcro điều chỉnh linh hoạt cho độ vừa vặn hoàn hảo\r\nThiết kế ôm sát cổ tay, hỗ trợ các pha đổ người bắt bóng','u8jlr1','a8073f','active','2025-04-08 22:04:32','2026-03-16 23:03:36',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('efw0hp','Vợt Lining Bladex 900 New China Master 2025 Limited','Bladex 900 New China Master 2025 – Mang dấu ấn độc quyền với logo “CHINA MASTERS” cùng phối màu biểu trưng cho tinh thần thể thao đỉnh cao, cây vợt không chỉ toát lên vẻ sang trọng và tinh tế mà còn trở thành một tuyệt phẩm sưu tầm mang giá trị biểu tượng dành cho người hâm mộ cầu lông.','50r71o','3371b3','active','2025-10-11 19:48:14','2026-03-16 23:03:42',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('eg60hx','Giày bóng chuyền Beyono Captain','','m65tw5','82c21b','active','2025-01-12 14:04:26','2026-03-16 23:03:35',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('eik69v','Vớ Thể Thao Beyono Sock VTT02','','y5tp3j','82c21b','active','2025-07-03 21:38:48','2026-03-16 23:03:43',5,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('eiqvlv','Vợt Pickleball JOOLA Agassi Pro V Andre Agassi 16Mm','VỢT PICKLEBALL JOOLA AGASSI PRO V ANDRE AGASSI 16MM\r\nĐược phát triển cùng huyền thoại quần vợt Andre Agassi, Agassi Pro V với phần cổ vợt thon gọn và vùng đánh mở rộng lý tưởng cho những ai thường đánh bóng phía trên mặt vợt, đặc biệt phù hợp với các tay vợt chuyên tennis.\r\n\r\nCông nghệ khung vợt KineticFrame đang chờ cấp bằng sáng chế giúp kiểm soát lực đánh từ cuối sân và đảm bảo độ ổn định tối ưu khi tranh chấp nhanh gần lưới. Agassi Pro V là lựa chọn hoàn hảo cho người chơi muốn kiểm soát bóng toàn diện, tự tin tấn công mạnh mẽ nhưng vẫn đảm bảo những pha chạm bóng tinh tế khiến đối thủ bất ngờ.\r\n\r\nĐó cũng là lý do vì sao Brooke Buckner và Kate Fahey – hai ngôi sao tennis đại học lừng danh, hiện là top 5 vận động viên pickleball chuyên nghiệp – đều tin tưởng chọn lựa cây vợt này.\r\n\r\nTHÔNG SỐ\r\nBề mặt sợi carbon nhám giúp tạo xoáy bóng và kiểm soát đường bóng tối ưu.\r\nLõi vợt 16mm/14mm cho cảm giác đánh chắc chắn và độ phản hồi tuyệt vời.\r\nĐạt chứng nhận UPA-A và USAP, thích hợp thi đấu chuyên nghiệp.\r\nThiết kế vợt dáng dài giúp mở rộng tầm đánh và linh hoạt trên sân.\r\nChiều dài vợt 42 cm, chiều rộng 19 cm, phù hợp nhiều dáng tay.\r\nTay cầm Feel-Tec dài 14 cm, tối ưu độ bám và sự thoải mái khi thi đấu.\r\nChu vi tay cầm 10,8 cm/10,4 cm, phù hợp đa số người chơi (có thể thay đổi nhẹ).','lsg423','0lifzq','active','2024-12-10 01:05:54','2026-03-16 23:03:41',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('emnqum','Áo Đá Bóng Nam Adidas Real Madrid 25/26 Sân Thứ Ba','ÁO ĐÁ BÓNG NAM ADIDAS REAL MADRID 25/26 SÂN THỨ BA\r\nThể hiện niềm tự hào cùng các tín đồ Real Madrid với Áo Đá Bóng Nam Adidas Real Madrid 25/26 Sân Thứ Ba. Thiết kế màu xanh cá tính kết hợp nét chấm phá của sân Bernabéu và phong cách adidas Originals, chiếc áo không chỉ tôn vinh di sản của câu lạc bộ mà còn khẳng định chất riêng cho người mặc. Đường sọc răng cưa 3-Stripes, logo Trefoil kinh điển cùng công nghệ kiểm soát ẩm AEROREADY giúp bạn luôn tự tin và thoải mái khi cổ vũ cho đội bóng yêu thích.\r\n\r\nTHÔNG SỐ\r\nKiểu dáng ôm gọn tôn vóc dáng hiện đại, năng động\r\nCổ tròn linh hoạt, dễ phối đồ\r\nChất liệu polyester tái chế thân thiện môi trường và siêu nhẹ\r\nCông nghệ AEROREADY giúp thấm hút mồ hôi nhanh, luôn khô ráo\r\nLogo Real Madrid thêu sắc nét, nâng tầm đẳng cấp người hâm mộ','sd2dby','4e177a','active','2024-09-27 22:31:40','2026-03-16 23:03:40',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('eqrurd','Áo Đấu Bóng Rổ Nam Nike Giannis Dna Basketball','ÁO ĐẤU BÓNG RỔ NAM NIKE GIANNIS DNA BASKETBALL\r\nÁo Đấu Bóng Rổ Nam Nike Giannis DNA Basketball tôn vinh hành trình tuyệt vời của Giannis Antetokounmpo với họa tiết hoa văn đặc trưng, lấy cảm hứng từ nguồn cội Nigeria và Hy Lạp của anh. Chất liệu vải thoáng khí, hút mồ hôi mang đến cảm giác thoải mái, dễ dàng kết hợp với nhiều phong cách.\r\n\r\nNgười mẫu cao 185 cm và đang mặc size L.\r\n\r\nTHÔNG SỐ\r\nChất liệu thoáng khí, hút mồ hôi mang lại cảm giác thoải mái tối đa\r\nCông nghệ Dri-FIT giúp giữ khô ráo và thoải mái\r\nHọa tiết hoa văn đại diện cho hành trình ấn tượng và cội nguồn của Giannis\r\nCổ và armholes dệt rib\r\nChất liệu thân/lót: 100% polyester\r\nCó thể giặt máy','3pxej5','962d78','active','2026-01-10 14:37:25','2026-03-16 23:03:39',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('euomiy','Mũ Lưỡi Trai Nike Jordan Rise','MŨ LƯỠI TRAI NIKE JORDAN RISE\r\nThiết kế cao cấp mang lại sự vừa vặn thoải mái và hiện đại cho Mũ Lưỡi Trai Nike Jordan Rise. Các tấm lưới giúp giữ cho thoáng khí, khóa cài snapback dễ dàng điều chỉnh vừa vặn theo ý muốn.\r\n\r\nTHÔNG SỐ\r\nĐược làm từ 100% cotton.\r\nThiết kế cao cấp mang lại sự vừa vặn thoải mái và hiện đại.\r\nChất liệu lưới thoáng khí.\r\nKhóa cài snapback cho phép bạn điều chỉnh vừa vặn theo ý muốn.','krrjqj','962d78','active','2025-08-25 07:34:28','2026-03-16 23:03:43',5,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('eure4n','Vợt Cầu Lông Yonex Astrox 99 Pro','Vợt cầu lông Yonex Astrox 99 Pro đỏ được Yonex cho ra mắt vào nửa cuối năm 2021. Bom tấn này có hai phiên bản màu đỏ cherry và trắng, được 2 tay vợt đơn nam hàng đầu Thế giới là Kento Momota và Lee Zi Jia lựa chọn sử dụng trong tập luyện và đều thi đấu rất thành công.','50r71o','7d1050','active','2026-02-03 16:46:57','2026-03-16 23:03:42',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('exapnp','Giày bóng chuyền Asics SKY ELITE FF 3','','m65tw5','3aa1e6','active','2026-02-12 15:10:28','2026-03-16 23:03:37',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('f1w8gd','Mũ Bơi Nike Swim Sport','MŨ BƠI NGƯỜI LỚN NIKE SWIM SPORT\r\nVới logo Swoosh nổi bật, Mũ Bơi Người Lớn Nike Swim Sport sẽ giúp bạn tỏa sáng trên từng sải bơi. Được chế tác từ 100% silicone co giãn cao, không gây dị ứng, mũ bơi bền bỉ vượt trội, chịu được tác động của clo. Lớp lót bên trong với họa tiết sần giúp mũ bám chặt mà vẫn êm ái, đảm bảo không bị tuột dù vận động mạnh. Đây chính là phụ kiện không thể thiếu, mang lại sự thoải mái và an tâm để bạn tập trung phá vỡ giới hạn và đạt được thành tích mới.\r\n\r\nTHÔNG SỐ\r\nChất liệu silicone co giãn cao, không gây dị ứng, mang lại cảm giác thoải mái và an toàn cho da.\r\nLớp lót bên trong với họa tiết sần giúp tăng độ bám, ôm sát và vừa vặn.\r\nLogo Swoosh nổi bật cùng màu sắc rực rỡ, giúp bạn nổi bật trên đường bơi.\r\nĐộ bền cao, chịu được clo tốt, phù hợp sử dụng lâu dài.','b38g5m','962d78','active','2025-07-18 21:45:01','2026-03-16 23:03:42',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('f9zcbv','Mũ Bảo Hiểm Xe Đua Aerohead MIPS','Giro Aerohead MIPS – Nón bảo hiểm khí động học cho ba môn phối hợp\r\nAerohead MIPS được thiết kế tối ưu khí động học giống Aerohead Ultimate nhưng tăng khả năng thông thoáng, giúp vận động viên ba môn phối hợp và đua xe tính giờ luôn mát mẻ trong các ngày thi đấu. Với lớp vỏ polycarbonate và hệ thống Wind Channel, nón vẫn giữ được tính khí động học trong khi cải thiện khả năng làm mát.\r\n\r\nTính năng nổi bật\r\nThiết kế khí động học – Tối ưu luồng gió nhưng vẫn tăng khả năng thông thoáng.\r\nKính chắn ZEISS – Tầm nhìn ấn tượng, tháo lắp dễ dàng, có nam châm gài lên nón khi không sử dụng.\r\nCông nghệ MIPS – Giảm lực tác động xoay trong các va chạm.\r\nĐệm lót kháng khuẩn Ionic+ – Giữ đầu khô ráo và thoải mái trong suốt cuộc thi.\r\nHệ thống điều chỉnh Roc Loc 5 Air – Điều chỉnh nhanh và vừa vặn với đầu.','3uzxgn','56fus5','active','2024-11-05 17:09:56','2026-03-16 23:03:40',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('fgrf7u','Giày Bóng Chuyền Beyono Storm Special Edition','','m65tw5','82c21b','active','2025-07-15 14:52:09','2026-03-16 23:03:35',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('fm7z7m','Vợt cầu lông Yonex Nanoflare 700 đỏ new 2022','Vợt cầu lông Yonex Nanoflare 700 đỏ new 2022 có khả năng phản tạt tuyệt vời, đây chính là điểm mạnh của cây vợt cầu lông cao cấp này, cũng chính là thứ đã làm nên thương hiệu cho cây vợt, với trọng lượng nhẹ cùng khung vợt mỏng tăng cường tốc độ vung vợt.','50r71o','7d1050','active','2025-09-19 12:30:09','2026-03-16 23:03:38',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('fpcrg0','Áo Thun Nữ Mizuno Impulse Core','ÁO THUN NỮ MIZUNO IMPULSE CORE\r\nTập trung hoàn toàn vào bài tập và tận hưởng sự thoải mái tối đa với Áo Thun Nữ Mizuno Impulse Core. Chất liệu vải nhẹ, thoáng khí cùng công nghệ DryLite tiên tiến giúp hút ẩm hiệu quả, giữ cho cơ thể luôn khô ráo và mát mẻ.\r\nBên cạnh đó, bạn hoàn toàn yên tâm về độ bền của áo thun Mizuno Impulse Core. Áo được áp dụng kỹ thuật BlindStitch - đường may phẳng chống mài mòn, giúp tăng độ bền và thoải mái cho người mặc. Đường may phẳng này loại bỏ các điểm cọ xát thường gặp, giảm thiểu khả năng trầy xước da khi vận động mạnh.\r\nTHÔNG SỐ\r\nGiữ mát và khô thoáng trong khi tập luyện\r\nChất liệu nhẹ, thoáng mát\r\nCông nghệ DryLite mang đến sự thoải mái và khô thoáng tối ưu cho hiệu suất vận động tốt nhất\r\nCông nghệ NightLite: Phản quang tốt khi chạy trong điều kiện thiếu sáng\r\nChống mài mòn và thoải mái hơn nhờ đường may phẳng','cxo8ft','69f937','active','2025-12-03 12:12:19','2026-03-16 23:03:35',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('fre454','Quần Dài Women Elite Tight','Women Elite Tight – Quần dài đạp xe nữ êm ái, thoáng khí cho mọi chuyến ride\r\nWomen Elite Tight là quần dài đạp xe dành riêng cho nữ, tối ưu cho Road, Gravel và Tour dài ngày. Với chất liệu co giãn, thoáng khí và đệm lót được thiết kế riêng cho nữ quần mang lại cảm giác êm ái, giảm áp lực hông và đùi, phù hợp cho những buổi đạp xe nhiều giờ.\r\n\r\n \r\n\r\nĐặc điểm nổi bật\r\nVải co giãn đa chiều giữ form lâu dài, nhẹ và bền bỉ.\r\nĐệm lót nữ công thái học, hỗ trợ đạp dài êm ái.\r\nChi tiết phản quang trên bắp chân không bị che khi mang giày overshoe.\r\nVải lưới thoáng khí và thấm hút mồ hôi giúp luôn khô thoáng.','z6x5ni','czsd09','active','2025-03-21 03:51:13','2026-03-16 23:03:37',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('fxx6b6','Áo Đá Bóng Nam Adidas Liverpool Icon','ÁO ĐÁ BÓNG NAM ADIDAS LIVERPOOL ICON\r\nThể hiện đam mê bóng đá với Liverpool FC cùng Áo Đá Bóng Nam Adidas Liverpool Icon lấy cảm hứng từ phong cách thập niên 80. Thiết kế đến từ adidas gợi nhớ kỷ nguyên huy hoàng với chi tiết sọc kim chỉ, logo Trefoil và huy hiệu câu lạc bộ cổ điển được thêu tinh tế trên nền vải, tạo nên một diện mạo hoài niệm cực chất cho ngày cổ vũ đội bóng. Áo sử dụng công nghệ UNITEFIT với phom dáng phù hợp cho mọi giới tính, đáp ứng đa dạng kích cỡ và hình thể.\r\n\r\nTHÔNG SỐ\r\nDáng áo ôm nhẹ, tôn dáng thể thao.\r\nCổ tròn năng động, dễ phối đồ.\r\nChất liệu 100% polyester tái chế, thân thiện môi trường và thấm hút mồ hôi tốt.\r\nLogo Liverpool FC in nhiệt bền đẹp và sắc nét.','sd2dby','4e177a','active','2024-10-05 15:51:09','2026-03-16 23:03:41',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('fzy3zr','Áo Đá Bóng Nam Adidas Arsenal Pre-Match','ÁO ĐÁ BÓNG NAM ADIDAS ARSENAL PRE-MATCH\r\nNằm trong bộ sưu tập hợp tác cùng Labrum London, chiếc Áo Đá Bóng Nam Adidas Arsenal Pre-Match chính là mẫu áo đồng hành cùng các cầu thủ khi tập luyện trước giờ thi đấu. Thể hiện hơi hướng Tây Phi của thương hiệu thời trang này, họa tiết graphic bắt mắt đảm bảo bạn sẽ luôn nổi bật khi tập giãn cơ và chạy bộ. Ẩn sau thiết kế ấy là công nghệ Aeroready giúp bạn luôn khô ráo, thoải mái và sẵn sàng cho mọi thử thách bóng đá.\r\n\r\nSản phẩm này làm từ 100% chất liệu tái chế, góp phần giảm thiểu lãng phí và hạn chế phụ thuộc vào các nguồn tài nguyên hữu hạn, cũng như giảm phát thải từ các sản phẩm mà adidas sản xuất.\r\n\r\nTHÔNG SỐ\r\nKiểu dáng ôm vừa vặn cơ thể (Slim fit)\r\nCổ tròn bo gân\r\nVải dệt interlock làm từ 100% polyester tái chế\r\nChất vải mềm mại\r\nAEROREADY\r\nHuy hiệu Arsenal thêu nổi','sd2dby','4e177a','active','2025-05-23 06:59:28','2026-03-16 23:03:41',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('g021ne','Quần Ngắn Nữ Adidas Own The Run Bike','QUẦN NGẮN NỮ ADIDAS OWN THE RUN BIKE\r\nHãy thúc đẩy bản thân chinh phục đường chạy với chiếc quần short adidas siêu nhẹ này. Với công nghệ AEROREADY thấm hút ẩm giúp bạn luôn khô ráo trên từng dặm đường, bạn sẽ tự tin làm chủ về cả cự ly và tốc độ. Các túi khóa kéo giữ chắc chìa khóa hoặc thanh năng lượng để tiện lấy khi di chuyển. Mẫu quần này làm từ chất liệu tái chế, nhờ đó bạn sẽ cảm thấy an tâm để dốc sức nỗ lực. Các chi tiết phản quang đảm bảo bạn luôn nổi bật và an toàn vào buổi tối. Hãy diện chiếc quần short này và giải phóng nhà vô địch trong bạn. Bạn sẽ làm được.\r\n\r\nSản phẩm này làm từ 100% chất liệu tái chế. Bằng cách tái sử dụng các chất liệu đã được tạo ra, chúng tôi góp phần giảm thiểu lãng phí và hạn chế phụ thuộc vào các nguồn tài nguyên hữu hạn, cũng như giảm phát thải từ các sản phẩm mà chúng tôi sản xuất.\r\n\r\nTHÔNG SỐ\r\nDáng regular fit\r\nCạp chun có dây rút\r\nVải dệt trơn làm từ 100% polyester tái chế\r\nCạp cao\r\nAEROREADY\r\nTúi khóa kéo đựng điện thoại di động ở cạp sau\r\nCác chi tiết phản quang','m40hn6','4e177a','active','2025-03-16 18:38:09','2026-03-16 23:03:35',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('g0rv7j','Áo Thun Tennis Nữ Nike Court Advantage Dri-Fit Short-Sleeve','ÁO THUN TENNIS NỮ NIKE COURT ADVANTAGE DRI-FIT SHORT-SLEEVE\r\nÁo Thun Tennis Nữ Nike Court Advantage Dri-Fit Tay Ngắn mềm mại, thoáng mát với công nghệ thấm hút mồ hôi vượt trội, co giãn linh hoạt giúp bạn vận động không giới hạn trên sân. Thiết kế ôm vừa vặn cùng cổ áo cao bảo vệ bạn trong mọi tư thế khi thi đấu.\r\n\r\nTHÔNG SỐ\r\nCông nghệ Nike Dri-FIT giúp thấm hút mồ hôi nhanh, giữ da luôn khô thoáng và dễ chịu\r\nChất liệu vải gân mềm mại, mịn màng bên trong cho cảm giác thoải mái\r\nChất liệu: 71% polyester, 29% elastane\r\nDễ dàng giặt máy, nhanh khô, bền màu','00f3pn','962d78','active','2024-11-28 07:38:28','2026-03-16 23:03:41',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('g8ty0x','Giày bóng chuyền Asics SKY ELITE FF MT 3','Giày trong nhà SKY ELITE™ FF MT 3 giúp bạn trải nghiệm những bước nhảy mạnh mẽ, cho phép trận đấu và trí óc của bạn đạt đến những tầm cao mới.​\r\n\r\nĐể tạo khả năng tăng tốc nhanh hơn nhằm chuẩn bị cho những bước nhảy cao hơn, đôi giày này sử dụng bộ phận công nghệ RISETRUSS™ để có lực nâng mạnh mẽ.​\r\n\r\nChúng tôi cũng đã cập nhật phần đế giữa với lớp đệm FF BLAST™ PLUS ECO để giúp tạo ra khả năng giảm chấn tiên tiến và độ nảy mạnh mẽ hơn khi nhảy.​\r\n\r\nCuối cùng, cấu trúc phần trên được thiết kế với nhiều hỗ trợ hơn nhằm giúp tạo cảm giác cố định, vừa khít hơn và tăng hiệu quả sử dụng lực.\r\n\r\nXuất xứ: Vietnam\r\n\r\nThành phần: 60% SYN LEATHER 40% SYN FIBER\r\n\r\nHướng dẫn sử dụng: giặt tay & phơi tránh nắng gắt\r\n\r\nThông tin cảnh báo: Không dùng bàn chải cứng, không dùng hóa chất tẩy rửa','m65tw5','3aa1e6','active','2025-05-15 05:56:07','2026-03-16 23:03:37',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('gcqe00','Quần Ngắn Thể Thao Nam Nike Court Dri-Fit Victory 9In','QUẦN NGẮN THỂ THAO NAM NIKE COURT DRI-FIT VICTORY 9IN\r\nQuần Ngắn Thể Thao Nam Nike Court Dri-Fit Victory 9In được thiết kế phù hợp cho bộ môn quần vợt với khả năng hỗ trợ hiệu quả tất cả các bài tập yêu thích của bạn. Chất liệu vải nhẹ và bền bỉ, hạn chế đổ mồ hôi sau mỗi lần tập luyện hăng say.\r\n\r\nTHÔNG SỐ\r\nCông nghệ Nike Dri-FIT thấm hút mồ hôi cực tốt, giữ cho bạn luôn khô ráo, mát mẻ\r\nVải dệt mịn, nhẹ và bền bỉ\r\nCạp quần co giãn tốt, có dây rút điều chỉnh dễ dàng để vừa vặn với cơ thể\r\nCác túi lưới tiện lợi giúp giữ những đồ dùng cá nhân trong quá trình tập luyện\r\nChất liệu phần túi: 100% polyester\r\nCó thể giặt bằng máy giặt','2sx26h','962d78','active','2024-12-11 00:28:53','2026-03-16 23:03:41',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ge4oou','Áo Ba Lỗ Nam Under Armour Baseline Cotton','ÁO BA LỖ NAM UNDER ARMOUR BASELINE COTTON\r\nÁo Ba Lỗ Nam Under Armour Baseline Cotton được thiết kế dành riêng cho những người đam mê và cuồng nhiệt với bóng rổ. Chất liệu mềm mại, co giãn 4 chiều giúp bạn tự tin tỏa sáng mọi lúc, mọi nơi.\r\n\r\nTHÔNG SỐ\r\nChất liệu vải cotton pha siêu mềm, nhẹ và nhanh khô, mang lại cảm giác dễ chịu tuyệt đối.\r\nVải co giãn 4 chiều giúp bạn di chuyển linh hoạt\r\nThiết kế khoét tay rộng - tăng phạm vi vận động\r\nViền áo ôm vừa vặn, tăng khả năng che phủ và sự tinh tế.\r\nForm dáng rộng rãi, thoải mái tối đa\r\n57% cotton, 38% polyester và 5% elastane','3pxej5','1791f2','active','2026-01-08 08:12:31','2026-03-16 23:03:42',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('gjk9gp','Quần Bơi Thể Thao Nữ Nike Swim Hipster','QUẦN BƠI THỂ THAO NỮ NIKE SWIM HIPSTER\r\nĐường nét tinh giản, chất liệu đẹp mắt và logo Swoosh tinh tế nâng tầm một thiết kế cổ điển. Sẵn sàng lướt sóng bất cứ lúc nào với chiếc quần bikini tuyệt đẹp này – dễ dàng phối cùng bất kỳ áo bơi yêu thích nào của bạn.\r\n\r\nTHÔNG SỐ\r\nSản phẩm này được làm từ ít nhất 75% vật liệu tái chế.\r\nĐộ che phủ tiêu chuẩn, lý tưởng cho mọi hoạt động dưới nước.\r\nCạp thấp ôm ngang hông, mang lại cảm giác siêu thoải mái.\r\nCó lớp lót bên trong giúp ôm dáng và tăng độ an toàn khi vận động.\r\n94% Recycled Polyester 6% Lycra Knit - Solid','37u1i1','962d78','active','2025-03-04 12:06:26','2026-03-16 23:03:36',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('gk0ksl','Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Puma Ultra 6 Match Tt','GIÀY ĐÁ BÓNG SÂN CỎ NHÂN TẠO NAM PUMA ULTRA 6 MATCH TT\r\nSẵn sàng bứt phá cùng ULTRA 6 – mẫu giày bóng đá mới với thiết kế phần thân vải lưới kỹ thuật hiện đại, giúp ôm sát bàn chân và tạo cảm giác siêu nhẹ. Khung đỡ chắc chắn hỗ trợ tối đa trong những pha chuyển hướng tốc độ, mang đến sự ổn định tuyệt đối. Đế giày mỏng nhẹ, đệm êm cùng thiết kế gai đặc biệt phù hợp cho cả sân cỏ tự nhiên và cỏ nhân tạo (2G), cho phép bạn phát huy tối đa khả năng trong mọi trận đấu.\r\n\r\nTHÔNG SỐ\r\nThân giày làm từ ít nhất 30% vật liệu tái chế, thân thiện với môi trường.\r\nKhung hỗ trợ siêu nhẹ giữ ổn định bàn chân, giúp chuyển hướng nhanh nhạy vượt trội.\r\nĐinh FastTrax đa hướng tăng độ bám sân, hỗ trợ mọi pha di chuyển linh hoạt.\r\nThân giày lưới với chất liệu 3D tăng độ bám bóng, giúp dứt điểm chính xác ở tốc độ cao.\r\nPhom giày vừa vặn, thiết kế mũi tròn tự nhiên cho cảm giác thoải mái.\r\nThắt dây chắc chắn, đế bằng tạo sự cân bằng hoàn hảo.\r\nTrọng lượng siêu nhẹ, đệm giữa êm ái bảo vệ bàn chân.\r\nĐế nhiều đinh thấp phù hợp sân cỏ tự nhiên cứng và cỏ nhân tạo (2G).\r\nLớp phủ GripControl giúp kiểm soát bóng tối ưu trong mọi tình huống.','eqj3j1','a8073f','active','2025-12-18 16:38:19','2026-03-16 23:03:35',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('gnfcq5','Mũ Bảo Hiểm Xe Địa Hình Fixture Mips II','BẢO VỆ TOÀN DIỆN - NÂNG TẦM PHONG CÁCH\r\nBạn đang tìm kiếm một chiếc mũ bảo hiểm vừa đảm bảo an toàn tuyệt đối, vừa thể hiện phong cách cá nhân? Fixture II MIPS chính là câu trả lời hoàn hảo. Được cải tiến từ phiên bản bán chạy nhất thế giới của Giro, phiên bản mới trang bị hệ thống bảo vệ Mips tiên tiến và khả năng thoáng khí vượt trội.\r\n\r\nDù bạn là tín đồ của những chuyến đi off-road đầy mạo hiểm hay chỉ đơn giản là muốn đạp xe thư giãn cuối tuần, Fixture II MIPS sẽ đồng hành cùng bạn. Với kiểu dáng mạnh mẽ, đệm lót thấm hút mồ hôi nhanh chóng và hệ thống điều chỉnh vừa vặn, chiếc mũ này sẽ mang đến cho bạn cảm giác thoải mái suốt cả ngày dài. Đặc biệt, dãy phản quang giúp bạn luôn nổi bật và an toàn khi di chuyển trong điều kiện thiếu sáng.\r\n\r\nĐiều đáng ngạc nhiên là, với những nâng cấp vượt bậc như vậy, Fixture II MIPS vẫn giữ nguyên mức giá phải chăng. Đây thực sự là một lựa chọn không thể bỏ qua cho những ai yêu thích đạp xe.','3uzxgn','56fus5','active','2024-12-25 19:38:57','2026-03-16 23:03:42',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('gryxai','Giày cầu lông Lining AYTV021-5','Lining AYTV021-5 được thiết kế dành cho người chơi tìm kiếm trải nghiệm tốc độ, ổn định và sự thoải mái trên sân. Phiên bản Lining AYTV021-5 với phối màu trắng xanh nổi bật, kết hợp cùng cùng chi tiết màu sắc điểm xuyết trên thân giày mang đến diện mạo hiện đại và đậm chất thể thao.','ayirn2','3371b3','active','2025-11-21 12:03:51','2026-03-16 23:03:39',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('gwh2sm','BÓNG CHUYỀN BÃI BIỂN THI ĐẤU MIKASA BV-550C-WYBR','Bề mặt có lỗ nhỏ độc đáo để tăng độ bám và kiểm soát bóng.\r\n\r\nCông nghệ mới để giảm thẩm thấu nước.\r\n\r\nCấu trúc van mới để giảm khí lọt ra bên ngoài.\r\n\r\nThiết kết màu mới để dễ nhìn hơn.\r\n\r\nNylon tái chế và mực nước để giảm thiểu tác hại môi trường.\r\n\r\n','26j3e6','ea945m','active','2025-04-10 08:51:29','2026-03-16 23:03:41',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('gy83ck','Quần Bơi Bé Trai Nike Swim Breaker Brief 7 Inch Volley','QUẦN BƠI BÉ TRAI NIKE SWIM BREAKER BRIEF 7 INCH VOLLEY\r\nĐược thiết kế cho những giờ vui đùa dưới làn nước hay thư giãn bên hồ bơi, qQuần Bơi Bé Trai Nike Swim Breaker Brief 7 Inch Volley mang lại cảm giác mát mẻ và thoải mái suốt cả ngày. Chất liệu nhẹ, nhanh khô kết hợp cùng quần lót lưới bên trong và túi lưới thoát nước giúp bé luôn khô ráo, dễ chịu sau mỗi lần bơi.\r\n\r\nTHÔNG SỐ\r\nTúi lưới thoát nước hiệu quả, giúp quần nhanh khô.\r\nLưng quần co giãn bổ sung dây rút bên trong, dễ dàng điều chỉnh vừa vặn.\r\nTích hợp lớp lót bên trong mang đến cảm giác an toàn và thoải mái.\r\nLogo thêu Swoosh tinh tế, khẳng định phong cách thể thao Nike.\r\nChiều dài ống 18cm lý tưởng cho hoạt động thể thao dưới nước.\r\nChất liệu thân: 100% polyester; lớp lót: 100% polyester tái chế, thân thiện môi trường.','37u1i1','962d78','active','2026-02-18 16:12:12','2026-03-16 23:03:39',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('gz6fv2','Áo Thun Tay Ngắn Nam Under Armour Court Hunt','ÁO THUN TAY NGẮN NAM UNDER ARMOUR COURT HUNT\r\nÁo Thun Tay Ngắn Nam Under Armour Court Hunt sở hữu chất liệu siêu nhẹ, mềm mại, thấm hút nhanh, giúp bạn luôn năng động và thoải mái trong mọi hoạt động thể thao.\r\n\r\nTHÔNG SỐ\r\nChất liệu cotton pha siêu mềm cho cảm giác dễ chịu suốt ngày dài\r\nCổ áo gân chắc chắn\r\nChất liệu: 60% cotton, 40% polyester\r\nPhom rộng, thoải mái tối đa cho vận động','3pxej5','1791f2','active','2025-10-26 16:37:05','2026-03-16 23:03:42',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('h4pngf','Giày Đá Bóng Sân Cỏ Tự Nhiên Nam Adidas Predator League Fold-Over Tongue Fg ','GIÀY ĐÁ BÓNG SÂN CỎ TỰ NHIÊN NAM ADIDAS PREDATOR LEAGUE FOLD-OVER TONGUE FG\r\nChinh phục mọi khung thành với Giày Đá Bóng Sân Cỏ Tự Nhiên Nam Adidas Predator League Fold-Over Tongue Fg. Thân giày bằng vải lưới Nanostrike siêu nhẹ, mềm mại, với lớp phủ haptic tích hợp giúp tăng độ chính xác cho từng cú sút. Thiết kế lưỡi gà - tạo bề mặt sút bóng mượt mà. Công nghệ Powerspine giữ vững bàn chân giữa, cho lực sút mạnh mẽ. Đế Strikeframe siêu nhẹ cho độ bám tối ưu giúp ghi bàn hiệu quả. Hãy xỏ giày và trải nghiệm khác biệt trên sân cùng adidas – nơi thăng hoa cho phong độ và cảm hứng thi đấu của bạn!\r\n\r\nTHÔNG SỐ\r\nForm ôm vừa chân, tạo cảm giác thoải mái khi di chuyển\r\nHệ thống dây thắt chắc chắn, hỗ trợ giữ chân tốt\r\nThân giày phối hợp vải và da tổng hợp, nhẹ nhàng, bền bỉ\r\nLót trong êm ái, tăng cảm giác khi thi đấu\r\nĐế ngoài tổng hợp bám sân, chống trơn trượt\r\nThiết kế chuyên biệt cho sân cỏ tự nhiên\r\nĐế STRIKEFRAME nhẹ giúp tăng lực bám và linh hoạt\r\nCông nghệ POWERSPINE tăng ổn định và sức mạnh cho mỗi cú sút\r\nLưỡi gà gập giúp kiểm soát bóng tốt hơn và sút bóng chính xác','eqj3j1','4e177a','active','2025-05-31 06:23:40','2026-03-16 23:03:36',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('h7fgkr','Giày Chạy Bộ Nam Nike Air Winflo 11','GIÀY CHẠY BỘ NAM NIKE AIR WINFLO 11\r\nGiày Chạy Bộ Nam Nike Air Winflo 11 mang đến cho bạn trải nghiệm chạy bộ êm ái mỗi ngày - nhờ vào lớp bọt Cushlon 3.0 và đệm Nike Air đàn hồi. Không chỉ vậy, dải đàn hồi ở giữa bàn chân và phần mũi chân rộng rãi còn đảm bảo sự vừa vặn, dễ chịu trên từng bước chạy.\r\n\r\nTHÔNG SỐ\r\nMũ giày từ vải lưới kỹ thuật - thoáng khí.\r\nĐế giữa bọt Cushlon 3.0 êm ái\r\nĐế ngoài được lấy cảm hứng từ đế giày Waffle - chống trơn trượt\r\nDải đàn hồi ở giữa bàn chân để vừa vặn với nhiều kích cỡ và hoạt động khác nhau.\r\nTrọng lượng: ~325g (size 9 nam).\r\nĐộ chênh lệch gót - mũi: 10mm.\r\nCông nghệ MR-10 Last — Sự vừa vặn tốt nhất và ổn định nhất của chúng tôi.\r\nHỗ trợ: Trung bình\r\nChi tiết thiết kế phản quang.','lskyuc','962d78','active','2024-12-17 00:24:34','2026-03-16 23:03:34',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('h8keqb','Giày Tennis Nữ Asics Game Ff','GIÀY TENNIS NỮ ASICS GAME FF\r\nSản phẩm Giày Tennis Nữ Asics Game Ff mang đến trải nghiệm vượt trội cho các tay vợt nhờ thiết kế siêu nhẹ, linh hoạt và hỗ trợ tối đa trên mọi mặt sân. Được cải tiến với khả năng thông thoáng và linh hoạt vượt trội, đôi giày này giúp bạn luôn thoải mái, tự tin di chuyển, kể cả trong những trận đấu kéo dài hoặc vận động cường độ cao.\r\n\r\nTHÔNG SỐ\r\nThiết kế lưới thoáng khí giúp lưu thông không khí, giữ cho đôi chân luôn mát mẻ.\r\nLớp phủ da tổng hợp kết hợp màng PU tăng độ ổn định khi di chuyển nhanh, bất ngờ.\r\nCông nghệ TRUSSTIC® ở đế giữa giữ chắc bàn chân, giúp vững vàng trên sân đấu.\r\nĐệm FLYTEFOAM® giúp giảm trọng lượng giày, tăng cảm giác êm ái và linh hoạt khi chạy nhảy.\r\nĐế giày được cải tiến tăng độ bền, đàn hồi và linh động cho mọi động tác.','uicjou','3aa1e6','active','2025-12-13 02:42:34','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('hen7ud','Áo Polo Nữ Adidas Club Tennis Climacool 3-Stripes','ÁO POLO NỮ ADIDAS CLUB TENNIS CLIMACOOL 3-STRIPES\r\nTỏa sáng phong cách thể thao trên sân quần vợt với Áo Polo Nữ Adidas Club Tennis Climacool 3-Stripes. Thiết kế cổ polo hai nút năng động, phần nách thoáng giúp tối ưu vận động khi thực hiện các cú đánh trên cao. Công nghệ CLIMACOOL cao cấp thấm hút mồ hôi, giữ bạn luôn khô ráo và tập trung. Sọc 3-Stripes nổi bật trên tay áo tăng dấu ấn Adidas thời thượng. Sản phẩm làm từ ít nhất 70% chất liệu tái chế, góp phần bảo vệ môi trường.\r\n\r\nTHÔNG SỐ\r\nDáng suông thể thao\r\nCổ polo hai nút\r\nChất liệu: 86% polyester tái chế, 14% elastane\r\nCông nghệ CLIMACOOL thoáng khí, thấm hút mồ hôi\r\nLưới thoáng ở phần dưới cánh tay\r\nGấu áo cong nữ tính','00f3pn','4e177a','active','2025-03-02 04:16:17','2026-03-16 23:03:38',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('hicu69','Vợt cầu lông Lining Halbertec 9000 Power 2026','Lining Halbertec 9000 Power được thiết kế với điểm cân bằng nặng đầu kết hợp với thân vợt hơi cứng cung cấp sức mạnh uy lực trong từng pha tấn công, đồng thời duy trì tốc độ phản ứng nhanh và chính xác cao.','50r71o','3371b3','active','2025-01-15 13:15:01','2026-03-16 23:03:43',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('hjcmtu','Áo Đá Bóng Nam Nike Dri-Fit Academy 25','ÁO ĐÁ BÓNG NAM NIKE DRI-FIT ACADEMY 25\r\nÁo Đá Bóng Nam Nike Dri-Fit Academy 25 được thiết kế siêu nhẹ, mát mẻ với các mảng lưới hai bên giúp tăng sự thông thoáng. Dáng ôm vừa vặn giúp bạn vận động tự do, thoải mái trong từng bài tập và trận đấu, để bạn luôn tập trung phát huy tối đa tốc độ và kỹ năng.\r\n\r\nTHÔNG SỐ\r\nCông nghệ Nike Dri-FIT giúp thấm hút mồ hôi, giữ cơ thể luôn khô ráo và dễ chịu.\r\nChất liệu vải dệt mịn nhẹ, thoáng mát tuyệt đối.\r\nCác mảng lưới ở hai bên và sau lưng tăng cường khả năng thông khí.\r\nLogo Nike thêu sắc nét, tạo điểm nhấn tinh tế.\r\nThành phần: 100% polyester cao cấp, nhẹ bền và nhanh khô.','sd2dby','962d78','active','2025-03-25 01:47:34','2026-03-16 23:03:35',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ht3r3z','Banh Bóng Đá Nike Pitch','BANH BÓNG ĐÁ NIKE PITCH\r\nBóng Đá Nike Pitch là lựa chọn lý tưởng cho các buổi tập luyện cơ bản, giúp nâng cao kỹ thuật và cải thiện động tác chân của bạn. Với thiết kế 12 mảnh và vỏ bóng bền bỉ, Nike Pitch duy trì hình dạng nhất quán và độ bền cao qua từng buổi tập, giúp bạn luyện tập hiệu quả và lâu dài. Đây là công cụ tuyệt vời để nâng cao kỹ năng bóng đá và chuẩn bị tốt cho các trận đấu sắp tới.\r\n\r\nTHÔNG SỐ\r\nVỏ may bằng máy: Tối ưu hóa hình dạng, cảm giác và độ bền.\r\nBầu khí cao su: Giúp duy trì áp suất và hình dạng.\r\nThành phần: 60% Cao su / 15% Polyurethane (PU) / 13% Polyester / 12% Ethylene Vinyl Acetate (EVA).','rm0g8a','962d78','active','2025-07-25 15:17:21','2026-03-16 23:03:41',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('htpyhd','Áo Bơi Thể Thao Nữ Nike Swim Triangle','ÁO BƠI THỂ THAO NỮ NIKE SWIM TRIANGLE\r\nKhi bạn muốn vẻ đẹp sang trọng, hãy chọn chiếc áo này với họa tiết Swoosh link terry đặc biệt. Dây đeo vai điều chỉnh và dây buộc lưng giúp bạn tìm được kích thước vừa vặn hoàn hảo.\r\n\r\nTHÔNG SỐ\r\nSản phẩm được làm từ ít nhất 75% vật liệu tái chế.\r\nDây đeo lưng và vai có thể điều chỉnh giúp bạn tìm được kích thước hoàn hảo.\r\nHỗ trợ nhẹ cho ngực giúp bạn cảm thấy thoải mái cả trong và ngoài nước.\r\nCúp ngực có thể tháo rời cung cấp độ che phủ thoải mái.\r\nCó lớp lót để cải thiện độ vừa vặn và an toàn.','v20opm','962d78','active','2025-10-06 14:50:23','2026-03-16 23:03:37',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('huoqvu','Giày Bóng Rổ Unisex Under Armour Dub Nation','GIÀY BÓNG RỔ UNDER ARMOUR DUB NATION\r\n\"Bùng nổ\" - Lịch sử đã thay đổi khi Stephen Curry đặt chân đến Oakland. Và nó sẽ lặp lại trong cuộc chơi của chính bạn - Với Giày Bóng Rổ Under Armour Unisex Dub Nation. Đệm UA Flow siêu nhẹ, với 2 tấm đệm tăng tốc - một để tăng độ ổn định và một để giúp bạn bay vút. Hãy sẵn sàng!\r\n\r\nTHÔNG SỐ\r\nPhần upper bằng lưới kỹ thuật thoáng khí, kết hợp với lớp phủ bền bỉ: Mang lại sự thoải mái và kiểm soát tốt khi di chuyển linh hoạt.\r\nLưỡi giày được đúc khuôn: Tạo cảm giác êm ái tối ưu.\r\nGót giày TPU 3D được đúc cứng bên ngoài: Tăng cường sự vừa vặn và hỗ trợ.\r\nMiếng lót giày bằng mút xốp có lỗ thoáng: Êm ái ngay từ bước đầu tiên.\r\nPhần đế trước của giày được chia thành nhiều đoạn: Giúp bạn cảm nhận bề mặt sân tốt hơn và di chuyển linh hoạt hơn\r\nKhung ở giữa bàn chân: Tăng độ ổn định khi vận động.\r\nĐệm UA Flow 2 lớp: Siêu nhẹ, đàn hồi, mang lại sự thoải mái vượt trội và độ bám đáng kinh ngạc.\r\nĐế ngoài UA Flow bền bỉ: Cảm giác sân tốt hơn, giúp bạn cắt bóng và dừng/chạy nhanh hơn bao giờ hết.\r\nKiểu dáng: Thường\r\nTrọng lượng: 12.125 oz (~343g)\r\nKiểu buộc dây: Buộc dây tiêu chuẩn','xijocy','1791f2','active','2025-01-12 04:49:56','2026-03-16 23:03:41',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('i3neg2','Quần Yếm Đạp Xe Women Elite Bib Cargo Short','Women Elite Bib Cargo Short – Quần yếm đạp xe êm ái, thoáng khí cho mọi chuyến ride\r\nWomen Elite Bib Cargo Short là quần yếm đạp xe cao cấp, thiết kế cho Road, Gravel và Tour dài ngày. Với chất liệu co giãn, nhẹ, bền bỉ và đệm công thái học, giúp đạp xe thoải mái, hiệu suất cao, giảm mỏi hông và đùi ngay cả khi đạp nhiều giờ.\r\n\r\n \r\n\r\nĐặc điểm nổi bật\r\nĐai yếm liền mảnh lưới thoáng khí, ôm vừa vai, giảm áp lực.\r\nVải co giãn đa chiều giữ form lâu dài, nhẹ và bền bỉ.\r\nĐệm lót công thái học, hỗ trợ ride dài êm ái.\r\n2 túi hông tiện dụng đựng gel, điện thoại, đồ cá nhân.\r\nChi tiết phản quang sau chân tăng an toàn khi ánh sáng yếu.','z6x5ni','czsd09','active','2025-08-15 10:43:52','2026-03-16 23:03:41',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('i8oku9','Vợt cầu lông Lining Windstorm 72 Power','Lining Windstorm 72 Power là siêu phẩm mới được nhà Lining cho ra mắt thời gian gần đây. Cây vợt thuộc Windstorm series, dòng vợt với đặc trưng trọng lượng siêu nhẹ, tối ưu hóa tốc độ vung vợt và sự linh hoạt trong từng pha cầu.','50r71o','3371b3','active','2025-08-31 20:52:43','2026-03-16 23:03:42',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ian9dz','Giày Cá Xe Đua Cadet','\r\nGiro Cadet Road Shoes\r\nCadet kết hợp phần trên vật liệu Synchwire, thoáng khí với đế bằng sợi carbon cứng cáp để tăng hiệu quả khi đạp xe , cùng với lót giữa được xử lý chống khuẩn Aegis để tạo sự thoải mái và vừa vặn tối ưu. Nút vặn BOA L6 điều chỉnh vi mô với gia số 1mm và kết hợp với dây gài điều chỉnh được, nâng niu bàn chân của bạn một cách chắc chắn. Cadet là sự lựa chọn tuyệt vời cho những tay đua đang tìm kiếm cảm hứng mới , hiệu suất ,giá trị và sự thoải mái lâu dài. \r\n\r\n \r\n\r\n\r\n\r\n \r\n\r\nTHÔNG SỐ KỸ THUẬT\r\nBề mặt giày:\r\n\r\nVật liệu ép nhiệt SYNCHWIRE 1 tấm duy nhất thoáng khí và BO® L6 điều chỉnh vi mô với gia số 1mm\r\n\r\nĐế ngoài:\r\n\r\nSợi Carbon , tương thích can 2 và 3 chấu\r\n\r\nĐế trong:\r\n\r\nMặt đế EVA hỗ trợ tấm đệm má bàn chân loại trung\r\n\r\nTrọng lượng:\r\n\r\n245 grams (size 42)','8hgm3b','56fus5','active','2025-09-11 16:35:40','2026-03-16 23:03:34',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ibny6t','Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Nike Zoovapor 16 Pro','GIÀY BÓNG ĐÁ SÂN CỎ NHÂN TẠO NAM NIKE ZOOVAPOR 16 PRO\r\nGiày Bóng Đá Sân Cỏ Nhân Tạo Nam Nike Zoovapor 16 Pro chính là lựa chọn dành cho bạn – những người luôn mong muốn bứt phá suốt cả trận đấu. Với bộ đệm Air Zoom cải tiến, sản phẩm giúp bạn dễ dàng tăng tốc, vượt qua hàng phòng ngự đối phương một cách mạnh mẽ. Kết hợp cùng loạt công nghệ tiên tiến của Nike như All Conditions Control và lớp Flyknit siêu nhẹ trên thân giày, bạn sẽ nâng tầm kỹ năng và chơi bóng thật nhanh nhẹn, linh hoạt trong mọi điều kiện thời tiết.\r\n\r\nTHÔNG SỐ\r\nCông nghệ All Conditions Control (ACC) giữ độ bám tối ưu dù mưa hay nắng.\r\nĐế ngoài thiết kế mới tăng hỗ trợ gót chân và bám sân cực tốt khi dừng hoặc chuyển hướng nhanh.\r\nMũ giày Flyknit toàn phần lần đầu xuất hiện trên Mercurial, vừa nhẹ vừa chắc chắn, giúp kiểm soát bóng tốt hơn.\r\nPhù hợp trên các bề mặt cỏ nhân tạo ngắn.\r\nLót đệm êm ái giúp thoải mái suốt trận đấu.','eqj3j1','962d78','active','2025-10-10 11:51:48','2026-03-16 23:03:36',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('idt5md','Giày bóng chuyền Beyono Orca','','m65tw5','82c21b','active','2025-07-23 08:32:06','2026-03-16 23:03:37',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ielszq','Giày Tennis Nam Asics Gel-Rocket 12','GIÀY TENNIS NAM ASICS GEL-ROCKET 12\r\nGiày Tennis Nam Asics Gel-Rocket 12 nổi bật với thiết kế cân bằng giữa độ ổn định và linh hoạt, giúp bạn di chuyển tự tin, nhanh nhẹn trên sân. Phần upper hỗ trợ vượt trội cho các chuyển động ngang, kết hợp cùng công nghệ TRUSSTIC™ ở đế giữa giúp tăng sự ổn định trong các pha chuyển hướng nhanh. Đây là lựa chọn lý tưởng cho những ai yêu thích bộ môn thể thao trong nhà.\r\n\r\nTHÔNG SỐ\r\nUpper lưới thoáng khí\r\nCông nghệ GEL™: Lớp đệm giữa hỗ trợ giảm chấn, êm ái\r\nCông nghệ TRUSSTIC™ giúp ổn định khi di chuyển\r\nĐế ngoài có rãnh linh hoạt tăng độ uốn dẻo','uicjou','3aa1e6','active','2025-03-07 11:52:30','2026-03-16 23:03:40',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ifueyl','Giày Bóng Rổ Unisex Under Armour Spawn Flotro','GIÀY BÓNG RỔ UNISEX UNDER ARMOUR SPAWN FLOTRO\r\nGiày Bóng Rổ Unisex Under Armour Spawn Flotro mang đến sự bứt phá với công nghệ đệm UA Flow siêu nhẹ, đàn hồi và bám sân vượt trội. Thiết kế đa lớp kết hợp giữa lưới và TPU giúp đôi giày linh hoạt nhưng vẫn ổn định, hỗ trợ tối đa cho những pha di chuyển nhanh, cắt hướng và dừng đột ngột trên sân.\r\n\r\nTHÔNG SỐ\r\nThân giày đa lớp kết hợp lưới và TPU, linh hoạt nhưng vững chắc\r\nGia cố hai bên giúp hỗ trợ chuyển động mạnh mẽ\r\nCổ giày êm ái, ôm chặt mắt cá chân\r\nLót giày bằng foam mềm, tăng độ êm ái khi mang\r\nCông nghệ đệm UA Flow siêu nhẹ, bám sân tốt\r\nĐế ngoài UA Flow bền bỉ, tăng cảm giác sân, hỗ trợ di chuyển nhanh\r\nKiểu buộc dây: Cổ điển','xijocy','1791f2','active','2025-11-12 09:17:15','2026-03-16 23:03:40',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ilqzmg','Banh Bóng Rổ Spalding Tf Gold - All Surface','BANH BÓNG RỔ SPALDING TF GOLD - ALL SURFACE\r\nSpalding TF Gold - All Surface - Trải nghiệm bóng rổ đỉnh cao trên mọi mặt sân. Trái bóng rổ được thiết kế để mang lại sự đa dụng và độ bền bỉ, thích hợp chơi trên mọi địa hình, đảm bảo cảm giác bóng nhất quán và độ nảy hoàn hảo mỗi lần chạm sàn. Với thiết kế thời trang cùng thương hiệu TF Gold danh tiếng, quả bóng này toát lên sự tự tin và phong cách. Quả bóng rổ size No-7 đem đến khả năng cầm nắm và điều khiển bóng tối ưu, cho phép người chơi thống trị trận đấu với độ chính xác và tinh tế. Nâng tầm trải nghiệm bóng rổ của bạn với Spalding TF Gold - All Surface!\r\n \r\n\r\nTHÔNG SỐ\r\nSize: No-7 (Kích thước tiêu chuẩn)\r\nThiết kế đa địa hình: Chuyển đổi liền mạch giữa chơi trong nhà và ngoài trời\r\nĐộ bền vượt trội: Cho hiệu suất lâu dài\r\nThương hiệu TF Gold thời trang: Vẻ ngoài cao cấp\r\nĐộ bám và độ nảy bóng đặc biệt: Cải thiện khả năng kiểm soát bóng\r\nLựa chọn hoàn hảo cho những người chơi tìm kiếm hiệu suất hàng đầu trên mọi mặt sân','wwayj1','q18zwp','active','2025-12-22 02:04:05','2026-03-16 23:03:43',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('j9yghn','Quần Ngắn Thể Thao Nam Adidas Tiro 26 League Training','QUẦN NGẮN THỂ THAO NAM ADIDAS TIRO 26 LEAGUE TRAINING\r\nQuần Ngắn Thể Thao Nam Adidas Tiro 26 League Training là lựa chọn lý tưởng cho những buổi tập luyện năng động nhờ công nghệ vải Climacool khô thoáng, mát mẻ. Thiết kế hiện đại lấy cảm hứng từ cầu thủ chuyên nghiệp, kết hợp phom regular fit vừa vặn với dây rút dễ điều chỉnh, ôm sát linh hoạt mà vẫn thoải mái khi vận động. Chất liệu interlock cao cấp bền nhẹ, phối lưới sau lưng tăng độ thoáng khí, hỗ trợ bạn luôn tự tin ngay cả khi tập luyện căng thẳng. Túi khóa kéo thuận tiện, chi tiết 3 Sọc đặc trưng và kiểu dáng thể thao giúp bạn nổi bật trên sân cỏ cũng như ngoài đời thường. \r\n\r\nTHÔNG SỐ\r\n\r\nDáng regular fit: Vừa vặn\r\nDây rút điều chỉnh ở cạp\r\nChất liệu 100% polyester tái chế\r\nLớp lưới phối ở mặt sau tăng thoáng khí\r\nTúi khóa kéo tiện lợi\r\nCông nghệ vải CLIMACOOL khô thoáng\r\nHọa tiết sọc adidas nổi bật hai bên\r\nChiều dài chuẩn, lưng vừa\r\nPhù hợp cho tập luyện và thi đấu','yrgs2k','4e177a','active','2024-11-23 08:11:07','2026-03-16 23:03:40',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('japoic','Áo Đá Bóng Sân Nhà Nam Nike Fc Barcelona 2025/26','ÁO ĐÁ BÓNG SÂN NHÀ NAM NIKE FC BARCELONA 2025/26\r\nÁo Đá Bóng Sân Nhà Nam Nike Fc Barcelona 2025/26 mang đến diện mạo mới mẻ cho một trong những biểu tượng bóng đá nổi tiếng nhất thế giới. Sự kết hợp giữa sọc Blaugrana truyền thống cùng họa tiết chuyển động và điểm nhấn rực rỡ - tôn vinh tinh thần đoàn kết và niềm đam mê cuồng nhiệt của người hâm mộ dành cho đội bóng xứ Catalan.\r\n\r\nTHÔNG SỐ\r\nThiết kế mô phỏng trang phục thi đấu chuyên nghiệp, phù hợp cho mọi tín đồ bóng đá.\r\nLogo đội bóng được dệt nổi bật, thể hiện niềm tự hào với Barca.\r\nChất liệu 100% polyester nhẹ, bền và thoáng khí.\r\nCông nghệ Nike Dri-FIT giúp thấm hút mồ hôi nhanh, giữ cơ thể luôn khô ráo và dễ chịu suốt trận đấu.','sd2dby','962d78','active','2025-07-30 21:23:12','2026-03-16 23:03:35',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('jcqysu','Găng Tay Thủ Môn Nike Match','GĂNG TAY THỦ MÔN NIKE MATCH\r\nChuẩn bị sẵn sàng cho mọi thử thách trên sân cỏ với Găng Tay Thủ Môn Nike Match. Được thiết kế với lớp đệm latex foam có khả năng hấp thụ tác động mỗi khi bạn bắt bóng, mang lại sự an toàn tối ưu. Đặc biệt, thiết kế cổ tay rộng rãi giúp giữ cho đôi găng tay của bạn luôn vừa vặn và thoải mái suốt trận đấu. Với Găng Tay Nike Match, bạn có thể tự tin thể hiện những pha cứu thua ấn tượng và hoàn thành trận đấu một cách xuất sắc.\r\n\r\nTHÔNG SỐ\r\nChất liệu: 37% cao su latex / 33% polyester / 21% ethylene vinyl acetate (EVA) / 9% nylon','u8jlr1','962d78','active','2026-02-11 01:09:30','2026-03-16 23:03:35',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('jked5v','Đồ Bơi Hai Mảnh Nữ Speedo Js2','ĐỒ BƠI HAI MẢNH NỮ SPEEDO JS2 BIKINI 2 PIECES BLACK / WHITE\r\nĐã đến lúc trở nên nổi bật và thực hiện những giấc mơ điên rồ nhất của bạn!\r\n\r\nKhông còn sự chờ đợi hay bất kỳ giới hạn nào. Giờ đây, bạn có thể thiết lập những quy tắc của riêng mình và tận hưởng niềm vui theo ý muốn. Cùng hòa mình vào bộ sưu tập Jetsetter mới của Speedo và biến mọi hồ bơi hoặc bãi biển thành sân chơi riêng của bạn. Cá tính hay ngọt ngào, sắc sảo hay gợi cảm, bạn luôn là nhân vật chính là tỏa sáng dưới ánh nắng mặt trời. Chiếc áo bơi khoét lưng đầy phong cách và tôn dáng này sẽ ngay lập tức khiến bạn trở thành tâm điểm chú ý khi chơi đùa dưới nước.\r\n\r\nTHÔNG SỐ\r\nThiết kế nổi bật mang dấu ấn cá nhân\r\nCác dây đai đàn hồi được trang trí bằng các họa tiết đặc trưng của chúng tôi mang đến vẻ ngoài tinh tế\r\nMiếng đệm ngực có thể tháo rời để vệ sinh\r\nĐường may dưới ngực mang lại sự hỗ trợ an toàn và thoải mái.\r\nCác sợi trong vải được làm từ rác thải sau tiêu dùng, mang lại cảm giác thoải mái khi mặc đồng thời giảm thiểu tác động lên môi trường\r\nSử dụng loại vải ECO EnduraBrite cải tiến với khả năng kháng clo\r\nKhả năng chống nắng tối ưu UPF50+, ngăn ngừa đến 98% tia UV nên bạn có thể vui chơi cả ngày dưới nước','rup31n','h2v6o2','active','2025-09-03 02:00:26','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('jl9fwz','Giày cầu lông Yonex Eclipsion Z3 Women','Yonex Eclipsion Z3 Women là mẫu giày cầu lông được ra mắt vào đầu năm 2023 dành riêng cho các nữ lông thủ. Xây dựng trên nền tảng công nghệ của dòng Eclipsion, Yonex Eclipsion Z3 Women đáp ứng các yêu cầu về sự ổn định, an toàn và chắc chắn tối đa trong từng bước di chuyển.','ayirn2','7d1050','active','2025-10-12 08:11:32','2026-03-16 23:03:39',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ju48t3','Áo Đạp Xe Tay Dài Men Elite Long Sleeve','Áo đạp xe tay dài Nam Fastr Men Elite – Mát hơn, nhẹ hơn, thoải mái suốt ngày dài\r\nFastr Men Elite Long Sleeve là áo jersey dài tay dành cho nam, thiết kế cho road, gravel và touring với khả năng thoáng khí, co giãn vượt trội và cảm giác thoải mái khi đạp đường dài. Nhờ chất liệu thấm hút nhanh và thân áo dài hơn, sản phẩm giúp bạn tự tin chinh phục mọi cung đường trong nhiều điều kiện thời tiết.\r\n\r\n \r\n\r\nĐặc điểm nổi bật\r\nChất liệu co giãn cao giúp tản nhiệt, thoát ẩm nhanh, giữ cơ thể khô thoáng.\r\nThiết kế dài tay bảo vệ da, phù hợp đi nắng & gió.\r\nThân áo dài hơn cho cảm giác thoải mái khi đạp đường dài.\r\nKhóa kéo YKK lock-zip chắc chắn, không tuột khi vận động mạnh.\r\n3 túi sau mở rộng + chống xệ giữ đồ ổn định, an toàn khi đạp.\r\nChi tiết phản quang tăng an toàn khi chạy sáng sớm hoặc chiều tối.','4c7anp','czsd09','active','2025-11-18 22:03:47','2026-03-16 23:03:39',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('jxm4c4','Dụng Cụ Tập Lặn Cho Bé Speedo Spinning Dive','DỤNG CỤ TẬP LẶN CHO BÉ SPEEDO SPINNING DIVE TOYS IU ASSORTED PASTEL\r\nDụng cụ tập lặn này từ từ chìm xuống đáy hồ bơi khiến việc học bơi dưới nước trở nên thú vị đối với những học viên nhí. \r\n\r\nTHÔNG SỐ \r\n\r\nThiết kế đầy màu sắc, những con cá nhỏ này sẽ thu hút sự chú ý của bé trong hồ bơi \r\nSản xuất theo tiêu chuẩn an toàn của Úc và Châu Âu','3myvj5','h2v6o2','active','2025-05-30 13:56:48','2026-03-16 23:03:39',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('k3j8yr','Áo Thun Nữ Nike Dri-Fit Victory Short Sleeve','ÁO THUN NỮ NIKE DRI-FIT VICTORY SHORT SLEEVE\r\nĐược cải tiến từ những phản hồi thực tế của cộng đồng chạy bộ, Áo Thun Nữ Nike Dri-Fit Victory Short Sleeve phiên bản mới ưu tiên tối đa về tính năng và sự tiện dụng. Chất vải co giãn, kết hợp công nghệ thấm hút mồ hôi mang lại cảm giác khô thoáng và hỗ trợ vừa vặn, ôm sát cơ thể. Thiết kế khoá kéo hai chiều giúp bạn dễ dàng điều chỉnh luồng không khí, tập trung cải thiện từng bước chạy mà không bị phân tâm.\r\n\r\nTHÔNG SỐ\r\nThiết kế tay áo raglan cải tiến hạn chế cọ xát dưới cánh tay, gia tăng sự linh hoạt cho từng chuyển động.\r\nCông nghệ Nike Dri-FIT giúp thấm hút mồ hôi nhanh, giữ cho cơ thể luôn khô ráo và thoải mái.\r\nDáng ôm, tôn dáng vòng eo\r\nLỗ xỏ ngón tay tăng diện tích che phủ và cố định tay áo chắc chắn.\r\nTúi khoá kéo bên hông để vừa tai nghe, chìa khoá hoặc thẻ tiện lợi khi di chuyển.\r\nLogo Nike Swoosh và các họa tiết phản quang trên tay áo và lưng giúp bạn nổi bật khi tập luyện trong điều kiện thiếu sáng.\r\nChất liệu: 75% polyester, 25% elastane','00f3pn','962d78','active','2025-10-23 22:54:03','2026-03-16 23:03:37',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('k9zxx5','Giày Bóng Chuyền Nam Asics NETBURNER BALLISTIC FF 4 ','Giày thể thao trong nhà NETBURNER BALLISTIC™ FF 4 được thiết kế để giúp tăng tốc độ và sự linh hoạt cho các chuyển động đa hướng.\n\nCông nghệ SPEEDTRUSS™ được thiết kế cho khả năng tăng tốc nhanh và các động tác xoay người, cho phép bạn di chuyển nhanh hơn.\n\nThiết kế đế ngoài PRECISION SOLE™ sử dụng ứng dụng mô hình hóa 3D để tạo ra mẫu đế ngoài mới, đạt được sự cân bằng tốt nhất giữa độ linh hoạt, trọng lượng nhẹ và độ bám; kết hợp với công nghệ X-GUIDANCE™ trong các rãnh uốn cong để cung cấp thêm sự linh hoạt trong các chuyển động đa hướng.\n\nCuối cùng, lớp đế giữa FLYTEFOAM™ với độ chênh lệch chiều cao gót 15mm giúp cải thiện sự thoải mái và tốc độ di chuyển.','m65tw5','3aa1e6','active','2025-11-20 02:04:34','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('kak045','Giày Bóng Rổ Nam Nike Air Jordan Xxxviii Low Pf','GIÀY BÓNG RỔ NAM NIKE AIR JORDAN XXXVIII LOW PF - BE\r\nBước vào sân và thống trị trận đấu với Giày Bóng Rổ Nike Air Jordan XXXVIII Low PF. Được thiết kế dành cho các cầu thủ đề cao tốc độ và sự linh hoạt, đôi giày này trang bị những công nghệ tân tiến, giúp bạn bứt phá trên sân với phong cách huyền thoại của Michael Jordan.\r\n\r\nTHÔNG SỐ\r\nĐệm Zoom Air Strobel cấu hình thấp\r\nThân giày bằng vải lưới nhẹ, thoáng khí\r\nLớp phủ tăng cường sự ổn định\r\nĐế ngoài bằng cao su bền bỉ\r\nThiết kế lấy cảm hứng từ Michael Jordan\r\nÍt nhất 20% vật liệu tái chế\r\nHộp giày \"Move to Zero\" thân thiện với môi trường\r\nPhiên bản PF dành cho sân ngoài trời','xijocy','962d78','active','2025-03-01 05:48:50','2026-03-16 23:03:35',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('kfn712','Giày Cá Xe Đua Circuit',' Circuit — Giày đạp đường trường đa dụng, thoải mái và hiệu quả\r\nTrek Circuit là đôi giày đạp đường trường đa năng, cân bằng hoàn hảo giữa sự thoải mái hằng ngày và hiệu suất trên xe — lựa chọn lý tưởng cho cả tập luyện lẫn những chặng dài.\r\n\r\n \r\n\r\n\r\nTại sao chọn Trek Circuit \r\nVới form vừa vặn thoải mái hơn, vùng METNET giảm áp lực và hệ thống BOA chính xác, Trek Circuit mang đến sự dễ chịu trên mọi hành trình. Đế nylon composite cứng vừa đủ để truyền lực tốt nhưng vẫn thuận tiện khi đi bộ, đồng thời hỗ trợ cả cleat 2 chấu và 3 chấu — cho tính linh hoạt tối đa.\r\n\r\n \r\n\r\nĐặc điểm nổi bật\r\nForm Trek Comp Last: Thiết kế rộng rãi hơn đôi chút, vừa thoải mái vừa giữ hiệu suất.\r\nVùng METNET giảm áp lực: Co giãn theo hình dáng bàn chân, giảm cảm giác khó chịu ở các điểm tì phổ biến.\r\nĐế nylon composite: Chỉ số cứng 7/14 — đủ truyền lực hiệu quả nhưng vẫn thoải mái khi đi bộ.\r\nHệ thống BOA L6: Núm vặn tinh chỉnh chính xác, mang lại cảm giác vừa vặn và phản hồi linh hoạt.\r\nDây dán mũi chân: Cho phép điều chỉnh nhanh và cố định chắc chắn hơn.\r\nThân giày đục lỗ: Tăng độ thoáng khí và khả năng tản nhiệt, giữ chân mát mẻ trên quãng đường dài.\r\nTương thích cleat 2 và 3 chấu: Phù hợp với cả bàn đạp đường trường lẫn MTB/SPD.\r\nVật liệu tái chế: Upper sử dụng 21% vật liệu tái chế theo trọng lượng, góp phần thân thiện với môi trường.','8hgm3b','0dpoy0','active','2025-07-12 00:15:30','2026-03-16 23:03:38',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('khk3c1','Quần áo bóng chuyền Nữ Beyono King II','','ehrxii','82c21b','active','2025-09-05 05:03:43','2026-03-16 23:03:36',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('khvauo','Áo Ba Lỗ Nam Under Armour Curry Signature Sub','ÁO BA LỖ NAM UNDER ARMOUR CURRY SIGNATURE SUB\r\nThoáng khí vượt trội, thấm hút mồ hôi nhanh, giúp bạn luôn mát mẻ và nhẹ nhàng khi vận động. Lấy cảm hứng từ tinh thần bứt phá của Stephen Curry, chiếc Áo Ba Lỗ Nam Under Armour Curry Signature Sub này không chỉ mang đến sự thoải mái mà còn thể hiện phong cách thể thao đầy năng lượng.\r\n\r\nTHÔNG SỐ\r\nChất liệu lưới in sublimation toàn bộ, mềm mại và cực kỳ thoáng khí.\r\nCông nghệ thấm hút mồ hôi, khô nhanh vượt trội.\r\nViền cổ và nách bo gân giúp giữ form tốt hơn.\r\nĐường xẻ gấu hai bên tạo sự linh hoạt khi di chuyển.\r\nPhom dáng rộng rãi, thoải mái tối đa.\r\nChất liệu: 100% Polyester.','3pxej5','1791f2','active','2025-03-25 02:19:51','2026-03-16 23:03:42',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('kmfaai','Áo Bơi Chống Nắng Nữ Nike Swim Cropped Short-Sleeve','ÁO BƠI CHỐNG NẮNG NỮ NIKE SWIM CROPPED SHORT-SLEEVE\r\nThỏa sức vận động dưới nắng cùng Áo Bơi Chống Nắng Nữ Nike Swim Cropped Short-Sleeve! Thiết kế croptop năng động, cổ cao và tay ngắn giúp bảo vệ tối ưu, đồng thời chất vải co giãn, lót mềm mại đảm bảo cố định và thoải mái dù tập luyện hay vui chơi. Hoàn hảo cho nàng yêu thể thao, thích khám phá không giới hạn.\r\n\r\nTHÔNG SỐ\r\nMay lót hoàn toàn, tăng cảm giác yên tâm và lịch sự\r\nDáng ôm sát, vừa vặn theo đường nét cơ thể\r\nLogo Swoosh xử lý nhiệt nổi bật\r\nThân áo: 83% recycled polyester, 17% spandex (kháng chlorine)\r\nLớp lót: 100% recycled polyester','v20opm','962d78','active','2025-09-24 03:12:31','2026-03-16 23:03:39',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('kp9arz','Áo Polo Tennis Nam Nike Court Dri-Fit Solid','ÁO POLO TENNIS NAM NIKE COURT DRI-FIT SOLID\r\nÁo Polo Tennis Nam Nike Court Dri-Fit Solid được làm từ chất liệu vải dệt mềm mại, 100% sợi polyester tái chế, mang đến vẻ ngoài cổ điển cùng khả năng thoát mồ hôi nhanh chóng, giúp bạn luôn thoáng mát và tự tin trên sân.\r\n\r\nTHÔNG SỐ\r\nCông nghệ Nike Dri-FIT giúp đẩy mồ hôi ra khỏi da, tăng tốc độ bay hơi, giữ bạn khô thoáng và dễ chịu.\r\nLogo thêu tinh tế trên ngực.\r\nSản phẩm có khả năng chống tia UVA và UVB tại vùng da được áo che phủ; nên sử dụng kem chống nắng cho những vùng da hở.\r\nCổ áo gập lịch lãm.\r\nThiết kế khóa cài 2 nút tiện dụng.\r\nChất liệu 100% polyester.\r\nDễ dàng giặt bằng máy.','00f3pn','962d78','active','2025-12-22 20:27:49','2026-03-16 23:03:40',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ksspmu','Vợt Tennis Wilson Shift 99L V1 Horse 2026','Vợt Tennis Wilson Shift 99L V1 Horse 2026\r\n\r\nThiết kế lấy cảm hứng từ Năm Ngựa 2026 – biểu trưng cho sức mạnh, tốc độ và tinh thần bứt phá.\r\n\r\nChạm đến sự cân bằng hoàn hảo giữa độ xoáy mãnh liệt và sức mạnh đầy kiểm soát cùng Wilson Shift 99L V1. Cây vợt được tạo ra dành cho những tay vợt trình độ trung cấp đến nâng cao, theo đuổi lối chơi toàn diện và yêu thích một khung vợt nhẹ hơn, linh hoạt hơn nhưng vẫn vững vàng trong từng pha bóng.\r\n\r\nVới cấu trúc dây đan và biên độ uốn cong mang tính đột phá, Shift 99L duy trì độ ổn định cần thiết đồng thời gia tăng độ linh hoạt theo phương ngang, giúp giải phóng sức mạnh có kiểm soát và tạo nên những cú xoáy đầy uy lực, sắc bén và chính xác.\r\n\r\nLà dấu mốc tiên phong của Wilson, bộ sưu tập Shift V1 được nghiên cứu, hoàn thiện và tinh chỉnh thông qua phản hồi của người chơi trên khắp thế giới. Kết hợp cùng các vật liệu có nguồn gốc thực vật được ứng dụng ở nắp chuôi và viền bảo vệ, cây vợt không chỉ nâng tầm hiệu suất thi đấu mà còn thể hiện tinh thần hướng đến tương lai bền vững.\r\n\r\n \r\n\r\nSHIFT – Bố cục xoay (Rotation Layout)\r\n\r\nGiúp dễ tạo độ xoáy cho bóng, đồng thời tăng độ sâu của cú đánh\r\n\r\nKhi đánh bóng, mặt vợt cong\r\n\r\nĐộ cong và thời gian tiếp xúc bóng tăng lên\r\n\r\nKéo dài thời gian bóng nằm trên dây, giúp tăng lực đánh và tăng độ xoáy của bóng khi bay ra\r\n\r\nCông nghệ ARC của đội ngũ sáng tạo WLabs\r\n\r\nĐược tạo ra bằng phần mềm mô phỏng và tính toán, thiết kế hình dạng khung độc đáo\r\n\r\nTrong điều kiện không làm mất độ ổn định khi xoắn, giúp tăng độ ổn định tổng thể của khung vợt\r\n\r\nMặt dây 16 × 20\r\n\r\nCân bằng giữa sức mạnh và khả năng kiểm soát\r\n\r\nChỉ số hiệu năng:\r\n\r\nSức mạnh: 3\r\n\r\nĐộ xoáy: 5\r\n\r\nKiểm soát: 4\r\n\r\nThông số vợt:\r\n\r\nMặt vợt: 99 inch²\r\n\r\nTrọng lượng chưa căng dây: 285 g\r\n\r\nCân bằng: Nhẹ đầu 7 điểm\r\n\r\nMật độ dây: 16 × 20\r\n\r\nCỡ cán: Cán số 2','p0d6db','p3c68s','active','2026-02-14 04:24:45','2026-03-16 23:03:43',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ktf7ja','Giày Bóng Rổ Nam Nike Lebron Witness Viii Ep','GIÀY BÓNG RỔ NAM NIKE LEBRON WITNESS VIII EP\r\nSở hữu ngay đôi giày này để cảm nhận sự bùng nổ năng lượng, làm chủ mọi pha bóng và tỏa sáng rực rỡ trên sân đấu. Đôi giày với thiết kế mạnh mẽ này mang đến sự ổn định khi bật nhảy mãnh liệt và tiếp đất êm ái, giúp bạn làm chủ mọi ngóc ngách sân bóng. Giày Bóng Rổ Nam Nike Lebron Witness Viii Ep là tuyên ngôn cho đam mê bóng rổ bất tận, cho khát khao chinh phục mọi giới hạn.\r\n\r\nTHÔNG SỐ\r\nĐế giữa Max Air kết hợp lớp foam hỗ trợ, tạo lực chuyển đổi mượt mà từ gót chân đến ngón chân, giúp mỗi bước di chuyển của bạn trở nên linh hoạt, uyển chuyển\r\nThân giày bằng lưới thoáng khí, ôm vừa vặn, mang đến cảm giác nhẹ nhàng\r\nĐế ngoài cao su tách rời, linh hoạt, giúp đế giày dễ dàng uốn cong, linh hoạt đồng thời giảm trọng lượng tổng thể\r\nHọa tiết xương cá tăng độ bám\r\nCổ giày đệm êm mang đến sự thoải mái và bảo vệ tối ưu cho mắt cá chân\r\nLưỡi giày kim cương chần tinh tế, nâng cao vẻ đẹp sang trọng','xijocy','962d78','active','2025-03-07 00:08:34','2026-03-16 23:03:37',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ktrhs5','Giày Cá Xe Địa Hình Sector','Giày Đạp Xe Địa Hình Giro Sector – Nhẹ, Cứng Cáp & Linh Hoạt\r\n \r\n\r\nSẵn sàng cho cuộc đua – Khơi nguồn phiêu lưu!\r\nGiro Sector là lựa chọn hoàn hảo cho những tay đua tìm kiếm hiệu suất cao, phù hợp cả địa hình gravel, XC lẫn đường mòn kỹ thuật. Kết hợp giữa phần thân trên Synchwire liền mạch, thoáng khí với tấm đế carbon-composite nhẹ và cứng, Sector mang lại độ truyền lực tối ưu trong khi vẫn đảm bảo sự thoải mái suốt cả ngày.\r\n\r\nPhần đế ngoài làm bằng cao su đúc kép bám đường cực tốt, hạn chế trơn trượt và chống bong tróc hiệu quả. Hệ thống 2 nút vặn BOA L6 cho phép điều chỉnh vi mô 1mm, dễ dàng đạt được độ ôm vừa vặn, cùng khả năng nhả nhanh tiện lợi khi cần.\r\n\r\n 	\r\nTính Năng Nổi Bật\r\nThân giày Synchwire nguyên khối – siêu nhẹ, thoáng khí, ép nhiệt chắc chắn\r\n\r\nGia cố mũi & gót giày – tăng độ bền khi off-road\r\n\r\nLót giày đúc 3D – hỗ trợ vòm bàn chân, thoải mái cả ngày dài\r\n\r\nLớp xử lý kháng khuẩn Aegis – khô thoáng, sạch sẽ\r\n\r\nĐế carbon-composite – truyền lực hiệu quả\r\n\r\nĐế ngoài cao su kép – bám đường, bền chắc\r\n\r\nCleat: 2 chấu – tương thích với hệ SPD\r\n\r\nTrọng lượng nhẹ: 342g (size 42)','8hgm3b','56fus5','active','2025-03-18 15:28:53','2026-03-16 23:03:38',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('kx02yi','Quần Ngắn Nam Under Armour Launch 7\'\'','QUẦN NGẮN NAM UNDER ARMOUR LAUNCH 7\'\' - ĐEN\r\nBạn đang tìm kiếm chiếc quần ngắn hoàn hảo để đồng hành cùng mỗi bước chạy của mình? Quần Ngắn Nam Under Armour Launch 7\'\' là người bạn đồng hành lý tưởng cho mọi buổi tập, với sự kết hợp giữa chất liệu siêu nhẹ, thiết kế linh hoạt và công nghệ tiên tiến, mang đến cảm giác tự do tột bậc, đưa bạn đến những cột mốc mới trên hành trình chinh phục đường chạy\r\n\r\nTHÔNG SỐ\r\nChất liệu: 100% Polyester, chất liệu vải sợi dệt bền bỉ và thoải mái\r\nLớp lót lưới nhẹ nhàng, êm ái, hỗ trợ tối đa\r\nCông nghệ thấm hút mồ hôi, khử mùi\r\nVải dệt co giãn linh hoạt\r\nNgăn đựng điện thoại riêng biệt\r\nNgăn bên hông rộng rãi\r\nThiết kế hiện đại, trẻ trung','m40hn6','1791f2','active','2025-05-28 09:20:25','2026-03-16 23:03:39',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('l0x2y4','Quần Ngắn Thể Thao Nam Adidas Squadra 25','QUẦN NGẮN THỂ THAO NAM ADIDAS SQUADRA 25\r\nKhẳng định phong cách thi đấu chuyên nghiệp cùng Quần Ngắn Thể Thao Nam Adidas Squadra 25! Thiết kế năng động kết hợp cùng dây rút ôm vừa vặn, chất liệu AEROREADY thấm hút mồ hôi hiệu quả, giúp bạn tự tin bứt phá đến phút cuối.\r\n\r\nTHÔNG SỐ\r\nDáng regular vừa vặn, thoải mái cho mọi chuyển động.\r\nDây rút trên lưng thun giúp điều chỉnh kích thước linh hoạt.\r\nChất liệu polyester tái chế bền bỉ, thân thiện môi trường.\r\nCông nghệ AEROREADY thấm hút mồ hôi vượt trội, luôn khô ráo.','yrgs2k','4e177a','active','2025-11-18 18:36:43','2026-03-16 23:03:40',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('l33t79','Vớ Đá Bóng Thể Thao Adidas Adi 24','VỚ THỂ THAO ADIDAS ADI 24\r\nHãy tiến lên và đạt mục tiêu của bạn với đôi tất bóng đá adidas được thiết kế để tăng hiệu suất. Công nghệ AEROREADY hút ẩm để giữ cho bạn khô ráo và thoải mái, đồng thời lớp đệm mềm bảo vệ chống lại áp lực để bạn có thể tập trung vào việc chiếm ưu thế trên sân. Những chiếc tất này sẽ đảm bảo đôi chân của bạn luôn sẵn sàng tỏa sáng.\r\nSản phẩm này được làm bằng ít nhất 50% vật liệu tái chế. Bằng cách tái sử dụng những vật liệu đã được tạo ra, chúng tôi giúp giảm thiểu chất thải và sự phụ thuộc vào nguồn tài nguyên hữu hạn.\r\n\r\nTHÔNG SỐ\r\nChiều dài đến đầu gối\r\nChất liệu: 83% polyester tái chế, 12% cotton, 5% elastane\r\nAEROREADY\r\nĐệm gót chân và ngón chân','1wyf0i','4e177a','active','2025-10-29 10:02:37','2026-03-16 23:03:36',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('l50tx6','Giày cầu lông Yonex Cascade Drive 3','Khác với thế hệ trước, Yonex Cascade Drive 3 được trang bị phần thân trên làm từ sợi tổng hợp – loại vật liệu nổi tiếng nhờ trọng lượng nhẹ, độ thoáng khí cao, mềm mại và linh hoạt, thường được ưu tiên sử dụng trên các dòng giày Yonex tốc độ như Aerus Z.','ayirn2','7d1050','active','2024-11-03 03:47:50','2026-03-16 23:03:40',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('l6spjr','Banh Bóng Rổ Tf 3X3 Gold Fiba Competitive Approved','BANH BÓNG RỔ UNISEX TF3X3 GOLD FIBA COMPETITIVE APPROVED \r\nTừ đường phố đến sân tập, Spalding TF33 được thiết kế đáp ứng các thông số kỹ thuật về kích thước và trọng lượng của một quả bóng chính thức được FIBA phê duyệt.\r\n\r\nThích hợp chơi sân trong nhà hay ngoài trời, loại bóng rổ này mang lại độ bám và khả năng kiểm soát cần thiết để vượt trội trong không gian tràn đầy năng lượng của trò chơi.\r\n\r\nTHÔNG SỐ \r\nBóng kích thước 6 (trọng lượng cỡ kích thước 7)\r\nThích hợp cho các bề mặt trong nhà / ngoài trời \r\nChất liệu: bề mặt cao su ','wwayj1','q18zwp','active','2025-11-15 10:14:02','2026-03-16 23:03:35',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('lcb0zj','Đồ Bơi Hai Mảnh Nữ Speedo Logo Volley','ĐỒ BƠI HAI MẢNH NỮ SPEEDO LOGO VOLLEY - HỒNG\r\nKhao khát hòa mình vào bầu không khí sôi động của bãi biển Bondi, hãy để Đồ Bơi Hai Mảnh Nữ Speedo Logo Volley sẽ đưa bạn đến thiên đường nhiệt đới, nơi phong cách thể thao rực rỡ hòa quyện cùng cảm giác sảng khoái tột đỉnh trên từng nhịp bơi\r\n\r\nTHÔNG SỐ\r\nKiểu dáng ôm sát, tôn vóc dáng, thoải mái linh hoạt\r\nLớp lót đầy đủ, kín đáo, tự tin\r\nVải ECO EnduraBrite bền bỉ, giữ màu, chống clo tuyệt đối\r\nCông nghệ CREORA® HighClo™ đảm bảo form dáng\r\nLàm từ 100% sợi polyester tái chế, thân thiện môi trường','rup31n','h2v6o2','active','2024-10-04 20:44:50','2026-03-16 23:03:40',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('m0yzc0','Kính Bơi Speedo Fastskin Hyper Elite Mirrored (Asia Fit)','KÍNH BƠI SPEEDO FASTSKIN HYPER ELITE MIRRORED (ASIA FIT)\r\nKỷ niệm 10 năm dẫn đầu đường đua, kính bơi Speedo Fastskin Hyper Elite Mirrored (Asia Fit) đánh dấu bước phát triển vượt trội từ dòng FS3 Elite đình đám. Trang bị công nghệ khí động học hiện đại giúp tối ưu tốc độ, Hyper Elite mang đến cảm hứng chiến thắng trong mọi cuộc đua. Tròng kính tráng gương giúp giảm chói, hạn chế hiện tượng lóa mắt khi bơi ngoài trời. Sản phẩm được hợp tác phát triển cùng vận động viên đỉnh cao thế giới, đạt chuẩn kiểm duyệt của World Aquatics.\r\n\r\nTHÔNG SỐ\r\nĐệm kính công nghệ IQfit™ 3D, cho cảm giác ôm khít, chống nước tối ưu\r\nTròng kính cong Hydroscopic, mở rộng tối đa tầm nhìn hai bên\r\nDây đeo kiểu liền mạch ôm sát, cho cảm giác vừa vặn cá nhân hóa\r\nCầu nối mũi dễ dàng điều chỉnh phù hợp nhiều dáng mặt\r\nChống mờ, giúp tầm nhìn luôn rõ ràng\r\nBảo vệ mắt 100% khỏi tia UV\r\nKhông chứa latex, an toàn cho da','7iai8b','h2v6o2','active','2025-06-01 18:34:26','2026-03-16 23:03:43',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('mb2jc3','Vợt Tennis Wilson Blade Feel 100','Vợt Tennis Wilson Blade Feel 100 RKT\r\nBạn mang đến sức mạnh. Blade Feel 100 mang đến khả năng kiểm soát.  Vợt tennis Wilson này khiến bạn cảm thấy được kết nối với quả bóng, mang đến cho những người chơi câu lạc bộ cạnh tranh sự tự tin cần thiết để kiểm soát điểm. Mọi thứ về cây vợt này đều được thiết kế để tăng cường cảm giác, từ hình dạng của khung vợt đến đầu vợt cỡ trung bình đến công nghệ BLX lọc rung động.\r\nSợi bazan dệt lọc tần số và độ rung để có phản hồi sạch hơn và cảm giác tốt hơn khi tiếp xúc với bóng.\r\nTay cầm mềm mang lại sự thoải mái tuyệt vời cho mọi cú đánh.\r\nSự kết hợp của các vật liệu composite cao cấp tạo ra độ cứng cao hơn giúp kiểm soát tốt hơn trong một kết cấu nhẹ.\r\nThành phần than chì mang lại sự kết hợp tuyệt vời giữa khả năng kiểm soát, cảm giác và sức mạnh với kết cấu chắc chắn.\r\nBLX - Basalt Carbon Fiber Composite làm giảm độ rung của vợt để có cảm giác tốt hơn.\r\nHệ thống cân chỉnh chu vi cải thiện độ ổn định xoắn.\r\nĐầu gậy có kích thước trung bình mang lại cảm giác và khả năng kiểm soát tốt hơn.\r\nCushion-Aire Grip mang lại cảm giác cầm vợt thoải mái hơn.\r\nThiết kế sắc nét và hiệu suất cảm nhận được lấy cảm hứng từ dòng sản phẩm Blade.','p0d6db','p3c68s','active','2025-09-25 02:39:21','2026-03-16 23:03:39',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('mdobi6','Vợt Tennis Wilson Intrigue SAKURA SE','Wilson Intrigue SE RKT 2 là cây vợt tennis lý tưởng dành cho người mới bắt đầu hoặc trình độ trung cấp. Tạo ấn tượng ngay lập tức trên sân đấu và trong lối chơi của bạn với vợt tennis Wilson Intrigue S thiết kế hướng đến sự dễ đánh, thoải mái và kiểm soát tốt. Với thiết kế hiện đại, trọng lượng nhẹ, mặt vợt rộng và đã căng dây sẵn, người chơi có thể sử dụng ngay khi nhận hàng mà không cần chỉnh sửa thêm.\r\n\r\nCây vợt này nổi bật với điểm ngọt (sweet spot) cực lớn nhờ vào phần đầu vợt quá khổ, cùng với thiết kế hình học giúp tăng khả năng phản hồi và tạo ra biên độ sai số lớn hơn khi tiếp xúc bóng không chính giữa.\r\n\r\nAirLite Alloy giúp cải thiện hiệu suất nhờ khung vợt nhẹ và bền.\r\nMiếng bảo vệ đầu vợt (bumper guard) giúp bảo vệ khung vợt khỏi va chạm và trầy xước.\r\n\r\nCây vợt này được căng sẵn dây, sẵn sàng để bạn ra sân ngay khi nhận được. Thiết kế bóng bẩy, lý tưởng cho người chơi tennis giải trí.\r\n\r\nThông số kỹ thuật\r\n\r\nTrọng lượng chưa căng: 264 g (9.3 oz)\r\n\r\nTrọng lượng đã căng: 280 g (9.9 oz)\r\n\r\nDiện tích mặt vợt: 105 in² (~677 cm²)\r\n\r\nChiều dài: 27 in (~68.6 cm)\r\n\r\nCân bằng chưa dây: 33.0 cm\r\n\r\nCân bằng sau căng dây: 34.0 cm khi căng dây – hơi nhẹ về đầu\r\n\r\nPattern căng dây: 16×20\r\n\r\nĐộ cứng khung: ~58 RA – vừa phải\r\n\r\nBeam width: khoảng 23.0–23.5 mm – khung dày trung bình\r\n\r\nChất liệu khung: Graphite nhẹ\r\n\r\nMã SKU: WR169410U2','p0d6db','p3c68s','active','2025-10-19 07:46:27','2026-03-16 23:03:43',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('mf6e3z','Giày Bóng Rổ Nam Nike Jordan Luka 2 Pf','GIÀY BÓNG RỔ NAM NIKE JORDAN LUKA 2 PF - VÀNG\r\nBản lĩnh tốc độ trong tay bạn, mang đến cho bạn sự ổn định đến từ Luka 2. Giày Luka 2 được thiết kế để hỗ trợ kỹ năng của bạn, đặc biệt dành cho các động tác bật lùi, di chuyển ngang và dừng đột ngột. Đế giữa được gia cố với lớp đệm vừa vững vừa dẻo dai, giúp bạn phản ứng nhanh nhạy hơn khi đổi hướng trên sân. Thân giày ôm trọn bàn chân với thiết kế lồng bảo vệ, giúp bạn giữ vững cổ chân dù đang qua người đối thủ hay ném bóng vào rổ. Công nghệ đỉnh cao gói gọn trong một đôi giày siêu nhẹ, cho bạn tự tin phô diễn kỹ thuật. Phần còn lại phụ thuộc vào bạn thôi!\r\n\r\nTHÔNG SỐ\r\nKhi bạn di chuyển sang ngang liên tục, bạn cần một đôi giày đỡ chắc nhưng vẫn dẻo dai. Giày Luka 2 PF trang bị miếng đệm wedge tại đế giữa, kết hợp với thành bên trong thân giày, giúp bạn đổi hướng di chuyển mượt mà và tự tin kiểm soát nhịp độ trận đấu. Lót giày dày, được định hình sẵn ôm theo lòng bàn chân giúp bạn giữ vững cảm giác tiếp đất.\r\nNgoài khả năng di chuyển sang ngang, đôi giày này còn chú trọng đến độ ôm chân (lateral support - hỗ trợ ngang). Để giúp bạn dừng lại đột ngột một cách an toàn, chúng tôi đã trang bị một miếng đệm cứng và đàn hồi chạy dọc thân giày bên hông, kết hợp với lõi xốp chắc chắn và lớp bọt Formula 23 ở đế giữa.\r\nMột lớp khung cứng cáp ôm trọn thân giày cung cấp độ hỗ trợ 360 độ, giúp đôi chân bạn được giữ chặt chẽ bất kể hướng di chuyển hay dừng đột ngột.\r\nPhiên bản PF được thiết kế với form rộng hơn và được tối ưu hóa để chơi trên sân ngoài trời.','xijocy','962d78','active','2025-09-13 08:17:09','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('mggc34','Vợt cầu lông Yonex Voltric GlanZ','Vợt cầu lông Yonex Voltric GlanZ là một trong số ít những cây vợt chuyên công mà linh hoạt trong cả các kỹ thuật phòng thủ nhờ kết hợp từ rất nhiều những công nghệ riêng biệt của dòng Voltric. Thành công của Yonex khi áp dụng những công nghệ này vào dòng vợt Voltric là khiến cây vợt không chỉ mang đến những pha tấn công uy lực và ổn định mà còn mang đến lối chơi linh hoạt hơn cho những lông thủ thiên công.','50r71o','7d1050','active','2026-02-26 19:56:40','2026-03-16 23:03:42',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('mk1a9u','Quần Short Women\'s Chrono Short','Quần đạp xe nữ Chrono Short\r\nBảo vệ da khỏi tia UV, thấm hút mồ hôi và tăng độ an toàn khi đạp xe.\r\nChrono Short dành cho nữ là lựa chọn lý tưởng cho những ai mới bắt đầu sử dụng quần đạp xe có đệm – kết hợp giữa sự thoải mái, chất lượng và giá thành hợp lý. Với chất liệu vải nylon/spandex co giãn, form ôm sát cơ thể và dễ dàng mặc cùng quần thường hoặc mặc riêng, mẫu quần này giúp bạn làm quen với trang phục xe đạp chuyên dụng mà vẫn tự tin, linh hoạt.\r\n\r\nLớp đệm Women\'s Chrono Chamois có độ dày 10mm vừa đủ để hỗ trợ và tạo cảm giác êm ái, không quá cồng kềnh, giúp bạn di chuyển dễ dàng hơn trong mọi hành trình.\r\n\r\n \r\n\r\nĐặc điểm nổi bật\r\nVải thấm hút mồ hôi, luôn khô thoáng khi vận động.\r\n\r\nKhả năng chống nắng UPF 50+ bảo vệ da khỏi tác hại của tia UV.\r\n\r\nLưng quần thiết kế bản rộng, tạo cảm giác thoải mái khi mặc.\r\n\r\nGấu quần có dải silicon chống trượt, giữ quần cố định khi đạp xe.\r\n\r\nLogo phản quang giúp tăng khả năng nhận diện trong điều kiện ánh sáng yếu.','z6x5ni','56fus5','active','2025-06-01 20:50:55','2026-03-16 23:03:40',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('mptjtq','Quần Ngắn Thể Thao Nam Nike Dri-Fit Classic 8 Inch','QUẦN NGẮN THỂ THAO NAM NIKE DRI-FIT CLASSIC 8 INCH\r\nHãy nâng tầm phong cách thể thao của bạn với Quần Ngắn Thể Thao Nam Nike Dri-Fit Classic 8 Inch. Chất liệu lưới cao cấp, siêu thoáng khí và công nghệ Dri-FIT thấm hút mồ hôi giúp bạn luôn mát mẻ, khô ráo, tự tin chinh phục mọi trận đấu.\r\n\r\nTHÔNG SỐ\r\nCông nghệ Dri-FIT giúp thấm hút mồ hôi nhanh, giữ cơ thể luôn thoải mái và khô thoáng.\r\nLớp ngoài bằng lưới nhẹ, thoáng khí kết hợp bên trong mềm mại, bền lâu theo thời gian.\r\nTúi tiện dụng có khóa kéo ẩn ở đường may hông, bảo vệ an toàn, không gây vướng víu khi vận động.\r\nĐộ dài ống quần (từ đáy quần tới gấu quần):~ 21cm.\r\nLưng thun co giãn với dây rút chắc chắn, dễ dàng điều chỉnh.\r\nChất liệu 100% polyester cao cấp, dễ giặt và mau khô.','j1jpkb','962d78','active','2024-12-17 05:06:10','2026-03-16 23:03:35',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('mwz1l0','Giày Bóng Rổ Nam Nike Air Jordan Xxxviii Lunar New Year Pf','GIÀY BÓNG RỔ NAM NIKE AIR JORDAN XXXVIII LUNAR NEW YEAR PF - ĐỎ\r\nChào đón năm mới với phong cách bứt phá cùng Giày Bóng Rổ Nam Nike Air Jordan XXXVIII Lunar New Year PF. Thiết kế lấy cảm hứng từ Rồng, linh vật duy nhất mang tính thần thoại trong 12 con giáp, kết hợp sắc màu lễ hội và chi tiết kim loại tinh tế. Công nghệ đỉnh cao như đế X-Plate ổn định và đệm Zoom Strobel toàn bộ chiều dài giúp bạn thống trị sân đấu.\r\n\r\nTHÔNG SỐ\r\nĐế Zoom Air Strobel cấu trúc thấp cho khả năng đáp ứng nhanh\r\nThân giày bằng vải lưới nhẹ, thoáng khí, hỗ trợ ôm chân\r\nCác chi tiết thêu tinh tế gia tăng độ ổn định\r\nThiết kế lấy cảm hứng từ mùa giải 1993 và chức vô địch thứ ba của Michael Jordan\r\nHộp giày Move to Zero thân thiện môi trường\r\nPhiên bản PF form rộng, tối ưu cho sân ngoài trời','xijocy','962d78','active','2025-11-30 09:47:32','2026-03-16 23:03:39',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('n07w0t','Mũ Lưỡi Trai Puma Runner Short Visor 5 Panel','MŨ LƯỠI TRAI PUMA RUNNER SHORT VISOR 5 PANEL\r\nGiữ đầu luôn mát mẻ và tập trung với Mũ Lưỡi Trai Puma Runner Short Visor 5 Panel. Chất liệu microfibre siêu nhẹ, thoáng khí cùng thiết kế lưới hai bên giúp bạn luôn dễ chịu khi vận động. Kiểu dáng năng động, dễ điều chỉnh phù hợp mọi hoạt động – phụ kiện không thể thiếu cho phong cách sống năng động của bạn.\r\n\r\nTHÔNG SỐ\r\nChất liệu microfibre cao cấp thấm hút mồ hôi, siêu nhẹ.\r\nLưới thoáng khí hai bên giúp đầu luôn thông thoáng.\r\nĐường viền nổi bật tạo điểm nhấn thời trang.\r\nDây rút điều chỉnh linh hoạt, vừa vặn mọi kích cỡ đầu.\r\nLưỡi trai cong sẵn bảo vệ mặt khỏi nắng.\r\nToàn bộ vỏ, lớp lót trước và phần dưới lưỡi trai đều làm từ 100% polyester bền bỉ.','j5up22','a8073f','active','2025-12-22 00:36:22','2026-03-16 23:03:40',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('n55hi1','Áo Ba Lỗ Nam Under Armour Launch Singlet','ÁO BA LỖ NAM UNDER ARMOUR LAUNCH SINGLET\r\nChạy bộ đường dài đòi hỏi sự thoải mái tuyệt đối, độ co giãn linh hoạt và trọng lượng nhẹ. Áo Ba Lỗ Nam Under Armour Streaker Singlet chính là người bạn đồng hành lý tưởng, giúp bạn chinh phục mọi thử thách trên đường đua. Công nghệ dệt may tiên tiến mang đến cảm giác nhẹ tênh, cho phép bạn tập trung tối đa vào mục tiêu phía trước.\r\n\r\nTHÔNG SỐ\r\nChất liệu: 94% Polyester / 6% Elastarell\r\nVải mềm mại, nhẹ và thoáng khí\r\nChất liệu thấm mồ hôi và khô nhanh\r\nChi tiết vạt áo xếp chồng giúp tăng cường thông gió\r\nChi tiết phản quang cải thiện tầm nhìn trong điều kiện thiếu sáng\r\nCông nghệ kiểm soát mùi giúp giảm thiểu mùi hôi','cxo8ft','1791f2','active','2025-12-02 23:51:48','2026-03-16 23:03:40',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('n6bhtr','Áo Đá Bóng Nam Nike Liverpool Fc Sân Nhà 2022/23','ÁO THUN THI ĐẤU NAM NIKE APP LFC M NK STAD JSY SS HM\r\nTương tự như những sản phẩm áo thi đấu khác trong bộ sưu tập Stadium của Nike, chiếc áo này là sự kết hợp hoàn hảo giữa chất liệu vải thấm hút mồ hôi và thiết kế tương tự như chiếc áo thi đấu của đội bóng mà bạn yêu thích, bạn đã sẵn sàng cho trận đấu tiếp theo?\r\n\r\nTHÔNG SỐ\r\nCông nghệ Nike Dri-FIT thấm hút mồ hôi và khô rất nhanh, giúp bạn luôn khô ráo và thoải mái.\r\nThiết kế mô phỏng theo mẫu áo của các cầu thủ chuyên nghiệp trên sân cỏ\r\nKiểu dáng vừa vặn, thoải mái\r\n100% polyester tái chế\r\nCó thể giặt máy','sd2dby','962d78','active','2025-11-07 20:25:46','2026-03-16 23:03:42',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('n8eqim',' Bộ Quần Áo Bóng chuyền Nam Beyono Grind','','ehrxii','82c21b','active','2025-01-02 09:51:59','2026-03-16 23:03:40',5,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('nd8qf8','Áo Polo Nam Adidas Club Tennis Graph','ÁO POLO NAM ADIDAS CLUB TENNIS GRAPH\r\nBùng nổ sức mạnh trên sân với Áo Polo Nam Adidas Club Tennis Graph – lựa chọn hoàn hảo cho những tay vợt hiện đại. Kiểu dáng năng động, chất liệu siêu nhẹ và công nghệ CLIMACOOL giúp thấm hút mồ hôi vượt trội, mang đến cảm giác mát mẻ, khô ráo và tự tin trong từng pha giao bóng. Thiết kế FreeLift linh hoạt hỗ trợ chuyển động thoải mái, tối ưu cho những pha đánh trên cao mạnh mẽ, giúp bạn luôn sẵn sàng bứt phá mọi giới hạn.\r\n\r\nTHÔNG SỐ\r\nDáng áo regular-fit vừa vặn, dễ phối đồ và vận động\r\nCổ áo polo cổ điển với 2 nút gài, tôn vẻ thể thao lịch lãm\r\nChất liệu polyester tái chế thân thiện môi trường, bền đẹp\r\nCông nghệ CLIMACOOL thấm hút, làm mát nhanh, chống ẩm ướt\r\nThiết kế FreeLift hỗ trợ tối đa chuyển động khi chơi tennis','00f3pn','4e177a','active','2025-10-10 08:04:26','2026-03-16 23:03:37',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('nf93vq','Áo Đá Bóng Nam Adidas Sân Nhà Real Madrid 25/26','ÁO ĐÁ BÓNG NAM ADIDAS SÂN NHÀ REAL MADRID 25/26\r\nTôn vinh thánh địa Bernabéu huyền thoại, áo đấu sân nhà Real Madrid 25/26 sở hữu thiết kế tinh tế với họa tiết hình khối và gam màu thanh lịch, gợi nhớ hành trình lịch sử đầy tự hào của CLB. Công nghệ AEROREADY giúp kiểm soát mồ hôi hiệu quả, trong khi huy hiệu thêu tỉ mỉ thể hiện rõ tinh thần chiến đấu của Los Blancos trên sân nhà mới nâng cấp.\r\n\r\nTHÔNG SỐ\r\nThiết kế ôm dáng\r\nCổ tròn\r\n100% polyester (tái chế)\r\nCông nghệ AEROREADY\r\nHuy hiệu Real Madrid thêu nổi','sd2dby','4e177a','active','2025-11-12 21:05:07','2026-03-16 23:03:42',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('nfe5xs','Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Nike Phantom 6 Low Academy','GIÀY ĐÁ BÓNG SÂN CỎ NHÂN TẠO NAM NIKE PHANTOM 6 LOW ACADEMY\r\nKhám phá Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Nike Phantom 6 Low Academy – lựa chọn hoàn hảo để nâng cao độ chính xác trong từng pha bóng của bạn. Đôi giày này được trang bị vùng chạm NikeSkin hiện đại, mang đến cảm giác bóng tự nhiên và chính xác vượt trội. Bề mặt bám dính giúp bàn chân tiếp xúc gần hơn với bóng, mở ra cơ hội ghi bàn tối đa. Dù trong điều kiện mưa hay khô, Phantom 6 Academy vẫn đảm bảo kiểm soát, rê bóng và chuyền bóng nhẹ nhàng như ý. Đế cao su đặc biệt giúp bám sân tốt trên mặt cỏ nhân tạo, kết hợp dáng giày ôm sát, ôm trọn đầu ngón chân để bạn tự tin tung các pha dứt điểm chuẩn xác hơn bao giờ hết.\r\n\r\nTHÔNG SỐ\r\nVùng chạm NikeSkin mở rộng cho cảm giác bóng chính xác trong mọi điều kiện.\r\nThiết kế ôm chân tự nhiên, sát bóng, đặc biệt ở phần đầu ngón chân.\r\nĐế cao su tối ưu lực bám, linh hoạt trên sân cỏ nhân tạo.\r\nBề mặt bám dính tăng độ kiểm soát và chuẩn xác trong từng đường chuyền hay cú sút.','eqj3j1','962d78','active','2025-02-26 20:26:10','2026-03-16 23:03:36',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ni339m','Áo Thun Nam Nike Basketball','ÁO THUN NAM NIKE BASKETBALL\r\nDành cho những người yêu bóng rổ thực thụ, Áo Thun Nam Nike Basketball mang đến phong cách phóng khoáng với dáng rộng, vai rơi và tay áo dài, giúp bạn tự tin thể hiện mọi kỹ năng trên sân bóng đường phố.\r\n\r\nTHÔNG SỐ\r\nDáng rộng, thoải mái, thích hợp mặc thường ngày.\r\nChất liệu cotton mềm mại, nhẹ nhàng, dễ chịu cho làn da.\r\nThiết kế vai rơi, tay áo dài và dáng rộng tạo vẻ ngoài trẻ trung, năng động.\r\nPhù hợp với nhiều phong cách thời trang đời thường.\r\nCổ áo bo gân chắc chắn, giữ dáng bền lâu.\r\nThành phần 100% cotton','3pxej5','962d78','active','2025-08-11 10:59:46','2026-03-16 23:03:38',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('np6bzw','Áo Bơi Chống Nắng Nam Nike Swim Hydroguard Short Sleeve','ÁO BƠI CHỐNG NẮNG NAM NIKE SWIM HYDROGUARD SHORT SLEEVE\r\nÁo Bơi Chống Nắng Nam Nike Swim Hydroguard Short Sleeve là trợ thủ lý tưởng cho những buổi vận động dưới nắng. Thiết kế tay ngắn thoáng mát cùng chất liệu Nike Dri-FIT hiện đại giúp cơ thể luôn khô ráo, dễ chịu khi hoạt động cao độ. Áo mang đến khả năng chống tia UV mạnh mẽ (UPF40+) ở các vùng được che phủ, tôn lên sự năng động trẻ trung, giúp bạn tự tin \"bứt phá giới hạn\" mọi lúc.\r\n\r\nTHÔNG SỐ\r\nCông nghệ Nike Dri-FIT giúp mồ hôi bay hơi nhanh, luôn khô thoáng\r\nChống nắng UVA & UVB (UPF40+) tại vùng áo che phủ\r\nLời khuyên sử dụng kem chống nắng cho vùng da hở\r\nForm rộng linh hoạt vận động\r\nLogo Swoosh ép nhiệt nổi bật\r\nThân áo: 100% polyester tái chế','v20opm','962d78','active','2025-10-14 05:28:47','2026-03-16 23:03:39',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('nu6f8t','Vợt Cầu Lông Lining Axforce Bigbang New','Lining Axforce Bigbang New mang đến một siêu phẩm chất lượng, bền chắc, cho phép người chơi thực hiện những pha cầu tấn công mạnh mẽ và đầy uy lực.','50r71o','3371b3','active','2025-01-15 09:37:37','2026-03-16 23:03:42',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('o3xiq3','Áo Thun Tay Ngắn Nam Under Armour Hoops Courtside Heavyweight Oversized','ÁO THUN TAY NGẮN NAM UNDER ARMOUR HOOPS COURTSIDE HEAVYWEIGHT OVERSIZED\r\nÁo Thun Tay Ngắn Nam Under Armour Hoops Courtside Heavyweight Oversized mang đến phong cách thể thao đầy năng lượng với chất liệu dày dặn, mềm mại và cực kỳ thoải mái. Thiết kế oversize cùng họa tiết cảm hứng bóng rổ giúp bạn tự tin nổi bật và vận động linh hoạt cả ngày dài.\r\n\r\nTHÔNG SỐ\r\nChất liệu cotton pha mềm mại, dày dặn, thoải mái suốt ngày dài\r\nCổ áo bo gân chắc chắn\r\nVai rớt với kiểu dáng rộng rãi, thoải mái\r\nThân áo chứa ít nhất 40% polyester tái chế (không bao gồm viền trang trí)\r\nChất liệu: 60% Cotton, 40% Polyester\r\nPhom rộng (Loose Fit): Dáng suông tạo cảm giác thoải mái tối đa','3pxej5','1791f2','active','2025-08-05 18:04:34','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('o5nyu4','Banh Bóng Rổ Spalding Vba Rainbow Graffiti Outdoor','BANH BÓNG RỔ SPALDING VBA RAINBOW GRAFFITI OUTDOOR\r\nVượt qua mọi giới hạn với Bóng rổ Spalding VBA Rainbow Graffiti Outdoor - sự kết hợp hoàn hảo giữa phong cách thời thượng và hiệu năng đỉnh cao dành cho những người đam mê bóng rổ đường phố. Trái bóng được thiết kế để chịu đựng những điều kiện khắc nghiệt của sân ngoài trời, đồng thời sở hữu họa tiết graffiti cầu vồng độc đáo, giúp bạn nổi bật trên sân đấu. Quả bóng rổ Spalding VBA Rainbow Graffiti Outdoor có kích thước No-7, mang lại cảm giác cầm nắm và kiểm soát tuyệt vời, cho phép người chơi phô diễn kỹ năng qua từng đường dẫn bóng và cú ném.\r\n\r\nTHÔNG SỐ\r\nKích thước: Size No-7\r\nĐược thiết kế bền bỉ để chơi ngoài trời\r\nHoạ tiết graffiti cầu vồng bắt mắt\r\nĐộ bám và kiểm soát vượt trội, giúp nâng cao hiệu suất chơi\r\nChịu được điều kiện khắc nghiệt ngoài trời\r\nTuyệt vời cho những người chơi muốn thể hiện cá tính trên sân đấu','wwayj1','q18zwp','active','2025-01-20 21:16:54','2026-03-16 23:03:43',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('o9heyc','Kính Mát Nửa Gọng Sanctum SL','Kính Mát Nguyên Gọng TIFOSI Sanctum SL\r\nKính Sanctum SL không chỉ là kính thể thao thông thường, mà con mang thiết kế thời trang hiện đại, mang đến tầm nhìn mở tối đa với thiết kế nửa gọng hiện đại, giúp tập trung tuyệt đối vào phía trước.\r\n\r\nTròng kính chống vỡ bảo vệ toàn diện khỏi tia UV, bụi bẩn và va đập, duy trì độ sắc nét trong mọi điều kiện.\r\n\r\nNhẹ, ôm chắc và thoải mái khi vận động, Sanctum SL là lựa chọn lý tưởng cho những ai theo đuổi hiệu suất và phong cách năng động.\r\n\r\nThông tin sản phẩm:\r\nGọng: Gọng Thrive làm từ vật liệu có nguồn gốc thực vật, nhẹ và bền bỉ.\r\nTròng kính: Purple Mirror AR – tròng polycarbonate chống vỡ, bảo vệ 100% khỏi tia UVA/UVB gây hại.\r\nCó hỗ trợ độ (Rx): Không.\r\nTính năng: Đệm mũi cao su hydrophilic tăng độ bám khi ra mồ hôi; công nghệ Tifosi Glide giúp gọng trượt êm ái, ôm chắc và hạn chế rung lắc; bản lề tích hợp không gây kéo tóc.\r\nSize: Medium–Large\r\nTrọng lượng: 27g\r\nPhụ kiện đi kèm: Túi lau kính microfiber.','6b4vag','8s9w7a','active','2026-03-04 06:08:37','2026-03-16 23:03:41',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ogbufh','Áo Đá Bóng Nam Adidas Liverpool Sân Nhà 25/26','ÁO ĐÁ BÓNG NAM ADIDAS LIVERPOOL SÂN NHÀ 25/26\r\nChào mừng bạn trở về mái nhà của những người hâm mộ Liverpool! Áo Đá Bóng Nam Adidas Liverpool Sân Nhà 25/26 tái hiện những ký ức tuyệt vời của bóng đá thập niên 2000 với thiết kế đơn giản, sắc nét, nổi bật nhờ đường viền trắng tinh tế. Từng giấc mơ và bài ca chiến thắng sẽ thăng hoa cùng chất liệu AEROREADY tiên tiến, giúp bạn luôn khô ráo, dễ chịu khi cổ vũ cho đội bóng yêu thích. Huy hiệu Liver Bird trên ngực áo là nguồn cảm hứng và niềm tin bất diệt cho mọi người hâm mộ The Reds.\r\n\r\nTHÔNG SỐ\r\nThiết kế ôm vừa vặn, tôn dáng năng động.\r\nCổ tròn truyền thống, mang lại sự thoải mái tối đa.\r\nChất liệu polyester tái chế, thân thiện với môi trường và siêu nhẹ.\r\nCông nghệ AEROREADY thấm hút mồ hôi nhanh, thoáng khí vượt trội.\r\nHuy hiệu Liverpool FC dệt nổi bật, khẳng định niềm tự hào của bạn.','sd2dby','4e177a','active','2025-07-23 01:40:30','2026-03-16 23:03:38',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('op546r','Banh Bóng Rổ Nba High Light Neon - Outdoor Size 7','BANH BÓNG RỔ NBA HIGH LIGHT NEON - OUTDOOR SIZE 7 \r\n\r\nTHÔNG SỐ\r\n\r\nVỏ cao su phù hợp với mọi loại mặt sân\r\nSản xuất theo tiêu chuẩn quốc tế\r\nChất lượng đảm bảo, chính hãng Spalding (Mỹ)\r\nNhà sản xuất: Spalding\r\nChất liệu: Legacy có đệm mút giúp đàn hồi tốt','wwayj1','q18zwp','active','2026-01-10 05:00:43','2026-03-16 23:03:42',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('opqpvw','Đồ Bơi Hai Mảnh Bé Trai Speedo Digital Short Sleeve','ĐỒ BƠI HAI MẢNH BÉ TRAI SPEEDO DIGITAL SHORT SLEEVE\r\nSẵn sàng cho những chuyến phiêu lưu mùa hè rực rỡ Đồ Bơi Hai Mảnh Bé Trai Speedo Digital Short Sleeve! Thiết kế áo kéo chui đầu giúp bảo vệ vai, bụng và lưng bé dưới ánh nắng gay gắt. Đồng thời quần bơi phối hợp vừa vặn, thoải mái. Chất liệu EnduraBrite co giãn 4 chiều siêu bền, ứng dụng công nghệ CREORA® HighClo™ chống lại tác động của clo, giúp form đồ luôn như mới dù bé vui chơi dưới nước hàng giờ liền. Bộ đồ bơi được sản xuất từ polyester tái chế, vừa thân thiện với môi trường, vừa an toàn cho làn da nhạy cảm của trẻ.\r\n\r\nTHÔNG SỐ\r\nChất EnduraBrite siêu bền, co giãn 4 chiều, giữ form vượt trội và chống tia UV cao.\r\nÁo thun kéo chui tiện lợi, bảo vệ tối đa khi hoạt động ngoài trời hoặc dưới nước.\r\nSản phẩm gồm áo và quần đồng bộ, cho bé diện phong cách trọn bộ nổi bật.\r\nSử dụng sợi polyester tái chế thân thiện môi trường, giảm rác thải nhựa.\r\nCông nghệ CREORA® HighClo™ giúp chống tia chlorine, chống mòn, tăng tuổi thọ sản phẩm.\r\nKhông lót bên trong, mang lại cảm giác nhẹ và mau khô.','rup31n','h2v6o2','active','2025-08-26 12:37:53','2026-03-16 23:03:42',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('otfus9','Vợt Cầu Lông Yonex Astrox 99 Tour Gen 3 2025','Vợt cầu lông Yonex Astrox 99 Tour Gen 3 2025 kế thừa gần như toàn bộ tinh hoa về công nghệ và đặc tính tấn công hủy diệt của phiên bản Pro, nhưng được tinh chỉnh để trở nên dễ thuần hơn và có mức giá hợp lý hơn.','50r71o','7d1050','active','2026-03-01 07:22:07','2026-03-16 23:03:42',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ovgidf','Giày Bóng Rổ Nam Nike Lebron Nxxt Gen Ampd Ep','GIÀY BÓNG RỔ NAM NIKE LEBRON NXXT GEN AMPD EP\r\nCho dù bạn là một vận động viên bóng rổ với những cú nhảy cao úp rổ bách phát bách trúng hay là một kỳ tài đường biên, Giày Bóng Rổ Nam Nike Lebron Nxxt Gen Ampd Ep sẽ giúp bạn trở nên nhanh nhẹ hơn với những đường di chuyển linh hoạt và chắc chắn trên sân. Cải thiện tốc độ cùng đôi giầy hoàn hảo này, sẵn sàng cho những cú bứt tốc ghi dấu ấn như một huyền thoại. Đế ngoài được làm bằng cao su siêu bền, có độ bám đường tốt ngay cả khi chơi ở mặt sân ngoài trời.\r\n\r\nTHÔNG SỐ\r\nTạo lực kéo đa hướng, linh hoạt và điêu luyện trong từng đường di chuyển trên sân\r\nBộ phận Air Zoom ở bàn chân trước được uốn cong theo nhiều hướng giúp cung cấp năng lượng cho những cú vào cua nhanh và nhạy\r\nBộ phận Air Zoom được nạp phía trên ở gót chân giúp tăng thêm khả năng giảm chấn\r\nLớp bọt ở đế giữa tạo cảm giác mềm mại và mịn màng đồng thời tạo hiệu ứng để có cảm giác sân tốt hơn','xijocy','962d78','active','2025-12-18 06:48:01','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ox5ts4','Áo Đạp Xe Tay Ngắn Men Elite Short Sleeve','Áo đạp xe tay ngắn Nam Fastr Men Elite – Mát hơn, nhẹ hơn, thoải mái suốt ngày dài\r\nFastr Men Elite Short Sleeve là áo jersey ngắn tay dành cho nam, thiết kế cho road, gravel và touring với khả năng thoáng khí, co giãn vượt trội và cảm giác thoải mái khi đạp đường dài. Nhờ chất liệu thấm hút nhanh và thân áo dài hơn, sản phẩm giúp bạn tự tin chinh phục mọi cung đường trong nhiều điều kiện thời tiết.\r\n\r\n \r\n\r\nĐặc điểm nổi bật\r\nChất liệu co giãn cao giúp tản nhiệt, thoát ẩm nhanh, giữ cơ thể khô thoáng.\r\nThiết kế bảo vệ da, phù hợp đi nắng & gió.\r\nThân áo dài hơn cho cảm giác thoải mái khi đạp đường dài.\r\nKhóa kéo YKK lock-zip chắc chắn, không tuột khi vận động mạnh.\r\n3 túi sau mở rộng + chống xệ giữ đồ ổn định, an toàn khi đạp.\r\nChi tiết phản quang tăng an toàn khi chạy sáng sớm hoặc chiều tối.','4c7anp','czsd09','active','2024-11-28 19:22:02','2026-03-16 23:03:35',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('oxysl7','Bóng Joola Primo 20 quả','Bóng JOOLA Primo là lựa chọn tuyệt vời cho các giải đấu và giải trí. Những quả bóng pickleball ngoài trời này được USAP công nhận, có kích thước 74mm và nặng 26 gram. Bóng cân bằng tốt giúp giảm lắc và sử dụng dễ dàng với máy.\r\n\r\nBộ 20 quả bóng JOOLA Primo đi kèm túi lưới tiện lợi.','gfwht4','0lifzq','active','2026-01-06 23:15:15','2026-03-16 23:03:40',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('pe2qen','Găng Tay Adidas Predator Training Goalkeeper','GĂNG TAY ADIDAS PREDATOR TRAINING GOALKEEPER\r\nĐược thiết kế cho những thủ môn đam mê luyện tập, Găng Tay Adidas Predator Training hỗ trợ tối đa cho từng pha bóng. Kiểu ngón positive mang đến cảm giác bóng chân thật, giúp bắt dính bóng chính xác và ném bóng đi xa. Lòng bàn tay bằng latex Soft Grip tăng cường độ bám, tạo sự tự tin trong mọi tình huống.\r\nTHÔNG SỐ\r\nKiểu ngón positive\r\nLòng bàn tay: Soft Grip làm từ 1% latex\r\nChất liệu chính: 1% polyurethane\r\nĐai quấn cổ tay nửa vòng','u8jlr1','4e177a','active','2025-05-19 08:00:08','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('pe58yt','Mũ Lưỡi Trai Nữ Under Armour Iso-Chill Launch Adjustable','MŨ LƯỠI TRAI NỮ UNDER ARMOUR ISO-CHILL LAUNCH ADJUSTABLE - TRẮNG\r\nĐối với những người đam mê chạy bộ, mũ lưỡi trai là vũ khí bí mật, đồng hành cùng họ chinh phục mỗi con đường, vượt qua mọi giới hạn. Mũ Lưỡi Trai Nữ Under Armour Iso-Chill Launch Adjustable chính là ngọn lửa bùng cháy, mang đến sự thoáng mát, thoải mái, phong cách, biến mỗi bước chạy thành niềm đam mê bất tận.\r\n\r\nTHÔNG SỐ\r\nChất liệu: 100% Polyester\r\nVải dệt nhẹ, bền bỉ với lỗ thoáng khí và lớp lưới\r\nCo giãn 4 chiều\r\nCông nghệ Iso-Chill độc đáo, khả năng hút ẩm và khô nhanh vượt trội\r\nDây đeo có thể điều chỉnh dễ dàng','j5up22','1791f2','active','2025-07-18 19:14:03','2026-03-16 23:03:42',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('pjglsu','Bóng Joola Primo','Bóng JOOLA Primo Ball là sự lựa chọn lý tưởng cho các giải đấu và trò chơi giải trí. Những quả bóng pickleball ngoài trời chính thức được USAP chấp thuận này có kích thước 74mm và nặng 26 gram. Những quả bóng pickleball cân bằng tốt giúp giảm thiểu hiệu ứng lắc lư và cho phép sử dụng tốt hơn với máy pickleball. Bộ 4 quả bóng JOOLA Primo Balls đi kèm một hộp đựng tiện lợi.','gfwht4','0lifzq','active','2025-07-21 09:54:30','2026-03-16 23:03:43',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ppe6fy','Đồ Bơi Hai Mảnh Nữ Speedo Printed Banded Triangle (Asia Fit)','ĐỒ BƠI HAI MẢNH NỮ SPEEDO PRINTED BANDED TRIANGLE (ASIA FIT)\r\nTỏa sáng rực rỡ và nổi bật trên bãi biển cùng Đồ Bơi Hai Mảnh Nữ Speedo Printed Banded Triangle (Asia Fit). Được thiết kế đặc biệt phù hợp với vóc dáng người châu Á, bộ bikini mang đến cảm giác thoải mái và nâng đỡ nhẹ nhàng. Chất liệu vải Endurabrite thân thiện với môi trường, co giãn linh hoạt, chống clo vượt trội, cho bạn tự tin tận hưởng cả ngày dài vui chơi.\r\n\r\nTHÔNG SỐ\r\nChất liệu Endurabrite (SIL) và Eco EnduranceFlex (SNA) thân thiện với môi trường, bền đẹp lâu dài\r\nThành phần vải: 82% polyester tái chế và 18% elastane (Creora® HighClo™) cho độ co giãn tối ưu\r\nÁo tam giác điều chỉnh dễ dàng, hỗ trợ nhẹ nhàng, thoải mái khi mặc\r\nKhả năng chống clo cao, giữ màu đẹp dù sử dụng thường xuyên\r\nThiết kế in họa tiết năng động, giúp bạn nổi bật mọi lúc, mọi nơi','rup31n','h2v6o2','active','2025-08-15 19:37:50','2026-03-16 23:03:38',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('pro3ld','Nón Bơi Người Lớn Speedo Long Hair','NÓN BƠI NGƯỜI LỚN SPEEDO LONG HAIR CAP\r\nNón bơi dành cho người lớn của Speedo là sản phẩm phù hợp với người bơi có mái tóc dài. Được làm từ chất liệu silicone mềm mại, không pha trộn cao su, gia tăng độ bền sản phẩm, không gian mũ thoải mái với diện tích rộng giúp bảo vệ toàn bộ phần tóc của bạn khỏi tác động của clo.\r\n\r\nTHÔNG SỐ\r\nPhù hợp với người bơi với chiều dài tóc tầm trung và dài\r\nThiết kế đơn giản, tiện dụng mang lại sự thoải mái tối ưu cho người dùng\r\nBảo vệ tóc khỏi tác động của clo\r\nChất liệu: 100% silicone','b38g5m','h2v6o2','active','2025-06-13 00:17:08','2026-03-16 23:03:41',5,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('prt65f','Đồ Bơi Một Mảnh Nữ Speedo Texture Bound Scoop','ĐỒ BƠI MỘT MẢNH NỮ SPEEDO TEXTURE BOUND SCOOP\r\nĐồ Bơi Một Mảnh Nữ Speedo Texture Bound Scoop mang đến vẻ ngoài thể thao hiện đại với thiết kế ôm dáng thời thượng và chất liệu jacquard dệt nổi cao cấp. Được lót toàn bộ giúp che phủ tối ưu, sản phẩm vừa đảm bảo sự tự tin, vừa thoải mái trong mọi hoạt động dưới nước.\r\n\r\nTHÔNG SỐ\r\nChất liệu jacquard dệt nổi bền đẹp, tạo cảm giác sang trọng.\r\nLót kín toàn bộ, đảm bảo che phủ tốt và an tâm vận động.\r\nThiết kế gọn gàng, tôn dáng, thích hợp cho mọi hoạt động thể thao dưới nước.','sgd0rk','h2v6o2','active','2025-12-05 01:13:40','2026-03-16 23:03:40',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('pt8sna','Vợt Pickleball Onix Z5','VỢT PICKLEBALL ONIX Z5\r\nVợt Pickleball Onix Z5 là lựa chọn hàng đầu của các vận động viên nhờ khả năng kiểm soát bóng và cảm giác đánh tuyệt vời. Thiết kế mặt graphit kết hợp lõi nomex giúp bạn cảm nhận rõ ràng từng pha chạm bóng. Trọng lượng vừa phải (khoảng 213-232g) tạo nên sự cân bằng hoàn hảo giữa sức mạnh và tốc độ. Kiểu dáng Widebody với điểm ngọt lớn phù hợp cho cả người mới lẫn vận động viên chuyên nghiệp. Vợt Pickleball Onix Z5 là bạn đồng hành lý tưởng cho ai tìm kiếm sự kiểm soát đỉnh cao với paddle mặt graphit và lõi nomex.\r\n\r\nTHÔNG SỐ\r\nChiều dài vợt: 39,4 cm\r\nChiều dài cán: 12,7 cm\r\nChiều rộng mặt vợt: 20,6 cm\r\nChu vi cán cầm: 10,8 cm\r\nTrọng lượng: 213-232 g\r\nMặt vợt: Graphit\r\nLõi vợt: Nomex\r\nDáng vợt: Tiêu chuẩn\r\nCán cầm: Kiểu tennis\r\nViền bảo vệ: Có\r\nĐạt chuẩn USAPA thi đấu\r\nĐộ dày vợt: 12 mm','lsg423','esp763','active','2024-10-12 01:14:14','2026-03-16 23:03:38',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('pwnf3j','Găng Tay Thủ Môn Adidas Predator','GĂNG TAY THỦ MÔN ADIDAS PREDATOR\r\nLàm chủ khung thành với đôi găng tay thủ môn adidas giúp bạn ghi điểm phong độ. Với thiết kế nhằm mang lại độ ôm vừa vặn, quai cổ tay co giãn trên đôi găng tay bóng đá Predator Training này tạo độ ổn định cho khả năng xử lý bóng thoải mái. Phần lòng bàn tay bằng cao su latex Soft Grip cho độ êm ái, độ bám và độ bền trong mọi điều kiện thời tiết.\r\n\r\nTHÔNG SỐ\r\nKiểu ngón positive\r\nLòng bàn tay: Mút foam latex Soft Grip\r\nQuai co giãn nửa cổ tay','u8jlr1','4e177a','active','2025-04-08 16:56:15','2026-03-16 23:03:35',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('py19d3','Vợt cầu lông Yonex Voltric Z-Force II | Siêu phẩm tấn công','Vợt cầu lông Yonex Voltric Z-Force II là cây vợt tấn công cao cấp tới từ hãng, vợt cho những cú đập cầu uy lực, được tin dùng bởi rất nhiều các VĐV hàng đầu trên thế giới.','50r71o','7d1050','active','2025-09-05 03:09:25','2026-03-16 23:03:41',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('pywvkc','Quần Short Men\'s Chrono Sport Bib Short','Quần Bib Đạp Xe Nam Giro Chrono Sport\r\nSự lựa chọn đáng tin cậy cho những tay đua nghiêm túc.\r\nChrono™ Sport Bib là mẫu quần bib hiệu suất cao với mức giá dễ tiếp cận, sở hữu nhiều tính năng thiết kế của các dòng cao cấp. Dáng ôm sát cơ thể, chất liệu vải tái chế thoáng mát, chỉ số chống nắng UPF 50+ và chi tiết phản quang giúp bạn luôn tập trung vào từng vòng đạp. \r\n\r\n(*) Quần không kèm theo lớp áo lót. \r\n\r\n \r\n\r\n 	\r\nƯu điểm nổi bật\r\nVải Renew Series™ thân thiện với môi trường: 78% nylon tái chế, giữ hiệu suất và độ bền cao.\r\n\r\nĐệm ngồi Chrono Sport Chamois: 2 lớp density, dày 11mm, sử dụng bề mặt vải mềm mại giúp giảm áp lực khi đạp đường dài.\r\n\r\nDây đeo bằng lưới thoáng khí: Giữ mát và cố định quần một cách nhẹ nhàng.\r\n\r\nChi tiết phản quang 3M®: Giúp tăng khả năng nhận diện trong điều kiện thiếu sáng.\r\n\r\n3 túi sau lưng tiện lợi: Dễ dàng mang theo gel, thanh năng lượng hoặc điện thoại.\r\n\r\nChân quần có viền chống trượt: Giữ quần cố định mà không gây khó chịu.\r\n\r\nTích hợp khay gài kính – tiện lợi cho những lúc nghỉ giữa chặng hoặc khi thời tiết thay đổi.','z6x5ni','56fus5','active','2026-02-12 08:01:23','2026-03-16 23:03:40',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('q0qsg8','Quần Dài Thể Thao Nam Under Armour Splash Graphic','QUẦN DÀI THỂ THAO NAM UNDER ARMOUR SPLASH GRAPHIC\r\n\"Mọi sản phẩm mang tên tôi đều phải tốt - phải giúp bạn chơi tốt hơn và thay đổi cuộc chơi theo hướng tích cực\" - Stephen Curry, một trong những cầu thủ xuất sắc nhất lịch sử NBA. Mang tinh thần ấy, Quần Dài Thể Thao Nam Under Armour Splash Graphic mang đến cho bạn sự kết hợp giữa thời trang và hiệu suất. Chất vải nỉ cotton siêu mềm mại, với lớp lót chải mịn - ấm áp và thoải mái. Đồng thời tạo nên phong cách retro cổ điển.\r\n\r\nTHÔNG SỐ\r\nChất liệu nỉ cotton siêu mềm với lớp lót chải mịn - mang lại cảm giác cổ điển, đậm chất retro\r\nCạp chun với dây rút bên ngoài\r\nTúi hai bên tiện lợi và túi sau có nắp gài chắc chắn\r\nGấu quần bo chun\r\nĐộ dài (từ đáy quần đến gấu quần): 30\"\" (~76 cm)\r\nTúi: Có\r\n80% Cotton/20% Polyester\"','j1jpkb','1791f2','active','2024-10-28 08:30:10','2026-03-16 23:03:42',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('q115bo','Quần áo bóng chuyền Nữ Beyono Heron II','','ehrxii','82c21b','active','2025-11-21 21:49:21','2026-03-16 23:03:35',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('q4vv60','Áo Ba Lỗ Nam Nike Jordan Dri-Fit Sport Essentials','ÁO BA LỖ NAM NIKE JORDAN DRI-FIT SPORT ESSENTIALS\r\nÁo Ba Lỗ Nam Nike Jordan Dri-Fit Sport Essentials được thiết kế dành riêng cho những vận động viên mong muốn đạt hiệu suất tối đa trên sân đấu. Với công nghệ thấm hút mồ hôi vượt trội, sản phẩm giúp bạn luôn tươi mát và tập trung, ngay cả trong những trận đấu căng thẳng nhất. Phom dáng cổ điển mang lại sự thoải mái và vừa vặn linh hoạt cho mọi chuyển động.\r\n\r\nTHÔNG SỐ\r\nCông nghệ Nike Dri-FIT thấm hút mồ hôi nhanh, giúp bạn luôn khô ráo và thoải mái.\r\nChất liệu vải co giãn mềm mại, phù hợp với mọi vận động mạnh.\r\n84% polyester, 16% elastane','3pxej5','962d78','active','2025-04-24 06:35:04','2026-03-16 23:03:40',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('q6x3lg','Giày Đá Bóng Dành Cho Sân Trong Nhà Nam Adidas Samba Messi','GIÀY ĐÁ BÓNG DÀNH CHO SÂN TRONG NHÀ NAM ADIDAS SAMBA MESSI\r\nTỏa sáng như Lionel Messi với đôi giày đá bóng trẻ em adidas Samba này. Với logo iconic của GOAT trên lưỡi gà, mẫu giày này làm từ chất liệu da cao cấp được trang bị khả năng chống mài mòn nhờ mũi giày chữ T bằng da lộn clasisc. Bên dưới là đế ngoài bằng cao su tạo độ ổn định ở cả trong và ngoài sân futsal. Phía trên là những gam màu táo bạo mượn cảm hứng từ dòng giày đá bóng F50 của Messi.\r\n\r\nTHÔNG SỐ\r\nDáng regular fit\r\nCó dây giày\r\nThân giày bằng da\r\nCổ giày adidas PRIMEKNIT\r\nLớp lót bằng vải dệt\r\nĐế ngoài bằng cao su','eqj3j1','4e177a','active','2025-04-28 05:10:44','2026-03-16 23:03:35',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('q8glok','Mũ Bảo Hiểm Xe Đua Aries Spherical','Giro Aries Spherical – Mũ bảo hiểm siêu nhẹ, bảo vệ tối ưu\r\nGiro Aries Spherical là lựa chọn hàng đầu cho các tay đua đường trường muốn kết hợp giữa trọng lượng nhẹ, thông gió tối ưu và an toàn vượt trội. Công nghệ Spherical kết hợp MIPS® mang lại cảm giác “như không đội mũ” mà vẫn bảo vệ tối đa.\r\nTính năng nổi bật\r\nThiết kế siêu nhẹ – Chỉ 275g (size M), giảm áp lực lên cổ và vai.\r\nCông nghệ Spherical + MIPS – Phân tán lực va chạm, bảo vệ não tối ưu.\r\nLớp mút Nanobead EPS mật độ kép – Hấp thụ lực tác động hiệu quả, vẫn nhẹ.\r\n24 khe gió Wind Tunnel – Thông gió tối ưu, giữ đầu luôn mát mẻ.\r\nĐệm trán DryCore & lót Ionic+ – Thấm hút mồ hôi, kháng khuẩn và khô thoáng.\r\nHệ thống Roc Loc 5+ Air – Điều chỉnh dễ dàng, ôm vừa và ổn định.\r\nKhay gắn kính tích hợp – Tiện lợi khi cần tháo hoặc gắn kính nhanh.','3uzxgn','56fus5','active','2024-11-08 19:37:06','2026-03-16 23:03:40',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('qemncd','Áo Khoác Nam Adidas Own The Run 3-Stripes','ÁO KHOÁC NAM ADIDAS OWN THE RUN 3-STRIPES - TRẮNG\r\nĐánh tan những cơn gió lạnh và chinh phục mọi thử thách trên đường chạy với Áo Khoác Chạy Bộ Nam Adidas Own The Run 3-Stripes. Công nghệ WIND.RDY đột phá cùng chất liệu vải dệt siêu nhẹ, cho bạn tự do sải bước. Thiết kế gọn nhẹ, linh hoạt cùng phong cách thời trang đậm chất adidas giúp bạn luôn tự tin trên mọi nẻo đường.\r\nSản phẩm này làm từ tối thiểu 70% chất liệu tái chế. Bằng cách tái sử dụng các chất liệu đã được tạo ra, chúng tôi góp phần giảm lãng phí và giảm phụ thuộc vào các nguồn tài nguyên hữu hạn, cũng như giảm phát thải từ các sản phẩm mà chúng tôi sản xuất.\r\n\r\nTHÔNG SỐ\r\nDáng áo: Slim fit\r\nKhóa kéo toàn thân, có mũ trùm\r\nChất liệu: 100% polyester tái chế dệt trơn\r\nCông nghệ: WIND.RDY\r\nTúi: túi trước có khóa bấm, túi khóa kéo trên ngực','cxo8ft','4e177a','active','2024-10-13 18:36:58','2026-03-16 23:03:41',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('qi7cai','Vợt Pickleball JOOLA Kosmos Pro V Federico Staksrud 16Mm','VỢT PICKLEBALL JOOLA KOSMOS PRO V FEDERICO STAKSRUD 16MM\r\nVợt Kosmos Pro V giới thiệu hình dạng Hybrid mới, kết hợp tầm đánh xa của Perseus với vùng tiếp xúc bóng rộng hơn của Scorpeus, tạo ra một lựa chọn cân bằng cho những người chơi muốn tấn công từ vạch cuối sân, phản công ở khu vực gần lưới và chuyển đổi mượt mà sang lối chơi kiểm soát trên lưới.\r\n\r\nĐược thiết kế với công nghệ KineticFrame đang chờ cấp bằng sáng chế, vợt Kosmos Pro V có khả năng uốn cong để tích trữ động lượng khi vung vợt và giải phóng nó khi va chạm. Nó cũng hấp thụ năng lượng từ những quả bóng đang đến để giúp bạn kiểm soát nhịp độ trận đấu, phản hồi nhanh chóng mà không gây bất lợi cho những cú đánh không hoàn hảo và tạo điều kiện thuận lợi cho việc đặt bóng tự tin trong những pha giao tranh nhanh.\r\n\r\nVợt Kosmos Pro V 16mm đánh dấu cây vợt signature đầu tiên của Federico Staksrud trong dòng sản phẩm của JOOLA. Lõi vợt dày 16mm mang lại cho Fed thời gian tiếp xúc bóng cần thiết để làm chậm nhịp độ trận đấu, kiểm soát bóng trong các pha chuyển đổi và thực hiện chiến thuật của mình.\r\n\r\nVợt Kosmos Pro V 14mm là mẫu vợt đặc trưng mới nhất của Tyson McGuffin, mang đến lực đánh mạnh mẽ và khả năng phản hồi nhanh nhạy mà anh ấy cần cho lối chơi tấn công nhanh và mạnh mẽ của mình.\r\n\r\nTHÔNG SỐ\r\nMặt vợt bằng sợi carbon nhám tăng khả năng tạo xoáy và độ bền.\r\nLõi vợt 16mm kiểm soát bóng tối ưu, hỗ trợ chơi chiến thuật.\r\nĐạt chuẩn UPA-A và chứng nhận bởi USAP, phù hợp thi đấu chuyên nghiệp.\r\nThiết kế Hybrid cân bằng giữa sức mạnh và sự linh hoạt.\r\nChiều dài vợt 41,4cm giúp mở rộng tầm đánh và bảo vệ sân.\r\nBề ngang 19,5cm tạo điểm ngọt lớn, dễ điều khiển bóng.\r\nTay cầm Feel-Tec êm ái, chống trơn trượt trong mọi tình huống.\r\nChiều dài tay cầm 13,3cm phù hợp đa dạng kiểu cầm vợt.\r\nChu vi tay cầm 10,8cm hoặc 10,5cm, vừa vặn nhiều kích cỡ tay.','lsg423','0lifzq','active','2026-03-02 13:37:12','2026-03-16 23:03:36',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('qieywm',' Giày bóng chuyền Beyono Limit V3','','m65tw5','82c21b','active','2024-12-02 23:42:47','2026-03-16 23:03:34',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('qn91cc','Giày bóng chuyền Asics SKY ELITE FF MT 3','','m65tw5','3aa1e6','active','2025-11-05 20:26:44','2026-03-16 23:03:34',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('qq6gjw','Giáp Bảo Vệ Ống Chân Puma Ultra Flex','GIÁP BẢO VỆ ỐNG CHÂN PUMA ULTRA FLEX - HỒNG\r\nGiáp Bảo Vệ Ống Chân Puma Ultra Flex chính là người bạn đồng hành tin cậy, nâng tầm trải nghiệm chơi bóng của bạn lên một đẳng cấp mới. Thiết kế siêu linh hoạt, trọng lượng nhẹ và khả năng chống chịu va chạm vượt trội hứa hẹn bảo vệ đôi chân bạn an toàn mà không cản trở bất kỳ chuyển động nào. Hãy cùng Giáp Bảo Vỏ Ống Chân Puma Ultra Flex chinh phục mọi thử thách trên sân cỏ và chạm đến đỉnh cao của chiến thắng!\r\n\r\nTHÔNG SỐ\r\nVỏ ngoài TPU siêu mềm dẻo và chống chịu va chạm hiệu quả, giảm thiểu tối đa nguy cơ chấn thương\r\nLớp đệm EVA được dập nổi và đục lỗ thông khí, vừa nhẹ nhàng, vừa hấp thụ lực tác động tối ưu\r\nKiểu dáng: Ôm sát, linh hoạt\r\nChi tiết thiết kế: Túi đựng tích hợp, logo PUMA Cat','1wyf0i','a8073f','active','2025-01-09 11:31:34','2026-03-16 23:03:41',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('qws9zp','Ốp Bảo Vệ Ống Chân Adidas Tiro Club','ỐP CHÂN ADIDAS TIRO CLUB\r\nBảo vệ bản thân mà không làm mất đi khả năng di chuyển, những chiếc ốp bảo vệ ống chân adidas Tiro Club này được thiết kế dành cho những người chơi thích sự tiện lợi. Nhẹ và linh hoạt, tấm ốp có lớp nền EVA để hấp thụ va đập và có thiết kế thông thoáng để tăng cường sự thoáng khí.\r\nĐược làm bằng ít nhất 20% hàm lượng tái chế để tránh tác động môi trường lớn hơn khi sản xuất hàm lượng nguyên chất.\r\n\r\nTHÔNG SỐ\r\nChất liệu: 75% polypropylene, 25% polypropylene tái chế\r\nLớp nền xốp\r\nTấm chắn cứng linh hoạt có thiết kế đục lỗ để tăng cường sự thoáng khí','1wyf0i','4e177a','active','2024-09-29 15:27:51','2026-03-16 23:03:40',5,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('qzf3jv','Mũ Bảo Hiểm Xe Địa Hình Fixture II','ro Fixture II – Nón bảo hiểm hiệu suất cao, thiết kế cổ điển\r\nFixture II là phiên bản nâng cấp của một trong những chiếc nón bán chạy nhất của Giro, mang đến sự kết hợp tuyệt vời giữa hiệu suất, thiết kế cổ điển và sự thoải mái. Với lớp đệm khô nhanh, hệ thống điều chỉnh Roc Loc Sport và dãy phản quang phía sau, nón bảo vệ bạn trên mọi hành trình từ thành phố đến địa hình khó.\r\n\r\nTính năng nổi bật\r\nVỏ ngoài Full Hardbody – Bảo vệ chắc chắn và bền bỉ cho mọi chuyến đi.\r\nMiếng lưỡi trai có thể tháo rời – Linh hoạt tùy chỉnh theo nhu cầu.\r\nĐệm lót nhanh khô – Giữ cảm giác thoáng mát và sạch sẽ khi đội lâu.\r\nDãy phản quang phía sau – Tăng cường an toàn khi di chuyển vào ban đêm.','3uzxgn','56fus5','active','2025-04-28 02:33:51','2026-03-16 23:03:40',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('r0274r','Giày cầu lông Lining AYTV021-6','Lining AYTV021-6 là sản phẩm nổi bật trong phân khúc giá tầm trung mới được nhà Lining ra mắt thời gian gần đây. Sở hữu những cải tiến về công nghệ, vật liệu và kiểu dáng, Lining AYTV021-6 nhanh chóng trở thành lựa chọn được lông thủ phong trào săn đón.','ayirn2','3371b3','active','2025-07-12 10:01:15','2026-03-16 23:03:39',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('r2pgzd','Quần Short Men\'s Chrono Short','Quần đạp xe Chrono dành cho nam mang đến sự thoải mái và chất lượng với mức giá dễ tiếp cận. Chất liệu vải pha trộn nylon / spandex co giãn thoải mái và dễ mặc cho bất kỳ ai, kể cả những người có thể chưa quen với trang phục bó sát. Miếng đệm Chrono êm ái và thoải mái, với độ dày vừa phải cho phép tự do di chuyển.\r\n\r\n88% nylon / 12% spandex\r\nMiếng đệm Chrono&\r\nChỉ số chống UV : UPF 50+\r\nVải thấm hút thoáng mát&\r\nĐai silicon ở ống quần&\r\nLogo phản quang&\r\nGiặt bằng nước lạnh, sấy ở nhiệt độ thấp, treo và phơi đến khi khô ráo','z6x5ni','56fus5','active','2025-09-23 03:47:56','2026-03-16 23:03:41',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('rfq2wy','Quần Ngắn Nam Under Armour Launch Elite','QUẦN NGẮN NAM UNDER ARMOUR LAUNCH ELITE \r\nChiếc quần ngắn Launch Elite được thiết kế để đồng hành cùng bạn chinh phục các thử thách khó khăn nhất. \r\n\r\nƯu điểm sản phẩm\r\nVải dệt siêu nhẹ, co giãn để chuyển động hoàn toàn không bị hạn chế\r\n\r\nLớp lót lưới bên trong giúp thoát hơi ẩm & đục lỗ bằng laser thêm khả năng thở\r\n\r\nChất liệu co giãn 4 chiều di chuyển tốt hơn theo mọi hướng\r\n\r\nKhả năng thấm mồ hôi tốt & khô rất nhanh\r\n\r\nTúi trung tâm được cải tiến có thể mở rộng và chống nước, giữ điện thoại của bạn cố định, không bị nảy\r\n\r\nThắt lưng đàn hồi có dây rút bên trong\r\n\r\nTúi bên có khóa kéo, an toàn cho việc lưu trữ \r\n\r\nChi tiết phản quang khi chạy trong điều kiện ánh sáng yếu\r\n\r\nTHÔNG SỐ\r\nĐường may sườn trong (inseam): 5\" / 12.7cm\r\nChất liệu: 88% polyester / 12% elastane\r\nMã sản phẩm: 1376509-001','m40hn6','1791f2','active','2026-03-04 10:28:07','2026-03-16 23:03:37',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('rfulp9','Áo Bóng Rổ Nam Nike Dri-Fit Icon','ÁO BA LỖ THỂ THAO NAM AS M NK DF ICON JERSEY\r\nMịn, thấm mồ hôi và không thể thiếu biểu tượng đặc trưng - Swoosh. Nike đã thiết kế chiếc áo thi đấu này giống như những chiếc áo bạn nhìn thấy trên sân, với kiểu dáng vừa vặn để tạo sự thoải mái tối đa.\r\nƯu điểm sản phẩm\r\nCông nghệ Nike Dri-FIT thấm hút mồ hôi tốt, giúp bạn luôn khô thoáng và thoải mái.\r\nVải dệt kim mang lại cảm giác mịn màng trên da.\r\nHãy kết hợp nó với chiếc quần ngắn cùng thiết kế để hoàn thiện vẻ ngoài tràn đầy năng lượng.\r\n\r\nTHÔNG SỐ\r\nChi tiết swoosh in nổi bật\r\nChất liệu: 100% polyester\r\nSản phẩm có thể giặt máy','3pxej5','962d78','active','2025-06-01 01:11:33','2026-03-16 23:03:41',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ribrb5','Giày Tennis Nữ Adidas Gamecourt 2','GIÀY TENNIS NỮ ADIDAS GAMECOURT 2\r\nGiày Tennis Nữ Adidas Gamecourt 2 là lựa chọn lý tưởng cho những ai yêu thích bộ môn quần vợt, từ luyện tập đến thi đấu. Với thiết kế hiện đại, sản phẩm mang đến cảm giác thoải mái, hỗ trợ tối ưu với khả năng bám sân vượt trội trên nhiều loại mặt sân khác nhau. Đôi giày này sẽ luôn đồng hành cùng bạn trên mọi bước di chuyển, giúp bạn tự tin thể hiện kỹ thuật trên sân.\r\n\r\nTHÔNG SỐ\r\nForm giày ôm chân vừa vặn, tạo cảm giác vững chắc.\r\nThiết kế dây buộc dễ dàng điều chỉnh, giữ chân ổn định.\r\nThân giày kết hợp vải dệt và chất liệu tổng hợp, giúp thông thoáng vượt trội.\r\nLớp lót trong mềm mại, tăng êm ái khi vận động.\r\nĐế ngoài cao su chất lượng, bám sân tốt trên nhiều bề mặt khác nhau.\r\nCông nghệ COLD CEMENT cho độ bền cao và trọng lượng nhẹ.','uicjou','4e177a','active','2024-10-28 04:55:05','2026-03-16 23:03:37',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('rigru0','Áo Polo Nam Adidas Club','ÁO POLO NAM ADIDAS CLUB\r\nSở hữu phong cách lịch lãm và hiệu năng thể thao, áo polo nam Adidas Club là lựa chọn lý tưởng cho những tay vợt yêu thích sự linh hoạt. Thiết kế FreeLift hỗ trợ tối đa cho các động tác đánh trên cao, trong khi phần lưng bằng vải lưới giúp tăng độ thoáng khí suốt trận đấu. Cổ polo hai nút mang lại vẻ ngoài chỉnh chu, dễ dàng ứng dụng cả trên sân và ngoài đời thường. Sản phẩm được làm từ 100% polyester tái chế, thân thiện với môi trường và nhẹ thoáng khi vận động.\r\n\r\nTHÔNG SỐ\r\nDáng regular fit\r\nCổ polo hai nút\r\nChất liệu 100% polyester tái chế\r\nThiết kế FreeLift hỗ trợ vận động vai\r\nLưng áo bằng vải lưới thoáng khí','00f3pn','4e177a','active','2024-10-16 15:11:14','2026-03-16 23:03:34',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ro5pqt','Áo Đá Bóng Sân Nhà Nam Adidas Japan 26/27','ÁO ĐÁ BÓNG SÂN NHÀ NAM ADIDAS JAPAN 26/27\r\nÁo Đá Bóng Sân Nhà Nam Adidas Japan 26/27 không chỉ là một trang phục thi đấu — đó là biểu tượng của khát vọng và ý chí kiên cường. Lấy cảm hứng từ chủ đề “Vượt Ngoài Chân Trời”, chiếc áo này thấm đẫm tinh thần khai phá và khát vọng vượt qua mọi giới hạn của đội tuyển.\r\n\r\nChiếc áo đấu được trang bị công nghệ Climacool. Thoáng mát. Khô ráo. Sẵn sàng. Công nghệ Climacool thấm hút và phân tán mồ hôi, giúp bạn luôn mát mẻ, khô ráo và không chút phân tâm.\r\n\r\nĐược làm từ chất vải dệt kim đôi, chiếc áo đấu này có phom dáng ôm sát, tôn lên vóc dáng và mang lại cảm giác thoải mái cả trong và ngoài sân cỏ. Dù bạn đang ở trên khán đài hay trực tiếp thi đấu, chiếc áo luôn giúp bạn giữ vững sự tập trung và sẵn sàng bùng nổ.\r\n\r\nCác chi tiết thẩm mỹ trên áo đấu được thiết kế để truyền cảm hứng cho cả cầu thủ lẫn người hâm mộ, đại diện cho hành trình chinh phục những vùng đất chưa được khai phá và khát vọng vươn tầm thế giới. Khoác lên mình chiếc áo với niềm tự hào và đồng hành cùng đội tuyển trên hành trình chinh phục những đỉnh cao mới.\r\n\r\nTHÔNG SỐ\r\nDáng ôm vừa vặn, tôn dáng và thoải mái khi vận động\r\nChất liệu polyester 100% tái chế, thân thiện với môi trường và bền bỉ\r\nỨng dụng công nghệ CLIMACOOL hút ẩm, giữ cơ thể luôn mát và khô ráo','sd2dby','4e177a','active','2025-02-03 08:46:34','2026-03-16 23:03:41',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ruayi8','Quần Dài Thể Thao Nam Adidas Asernal Fc Icon','QUẦN DÀI THỂ THAO NAM ADIDAS ASERNAL FC ICON\r\nQuần Dài Thể Thao Nam Adidas Asernal Fc Icon được làm từ chất liệu jersey mềm mại mang lại sự thoải mái tối ưu. Họa tiết thêu hình con trâu và đám mây tượng trưng cho sự khỏe khoắn, kiên trì và khả năng vô hạn. Logo đội bóng được thêu tinh tế giúp bạn thể hiện niềm tự hào và tình yêu với đội bóng của mình.\r\n\r\nTHÔNG SỐ\r\nChất liệu: 70% cotton, 30% polyester tái chế\r\nThun lưng có dây rút: Tạo sự vừa vặn và dễ điều chỉnh\r\nTúi phía trước: Tiện lợi để đựng đồ cá nhân\r\nCó thể giặt máy','yrgs2k','4e177a','active','2025-03-04 10:32:24','2026-03-16 23:03:41',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('s3a6mf','Mũ Bảo Hiểm Xe Đua Syntax MIPS','Nón Bảo Hiểm Giro Syntax Mips – Thoải Mái Trên Mọi Cung Đường\r\nHiệu suất bền bỉ – Phong cách tinh tế – Bảo vệ tối ưu.\r\nGiro Syntax Mips mang đến sự thoải mái vượt trội cho những hành trình dài, kết hợp thiết kế châu Âu thanh lịch với độ bao phủ sâu hơn để bạn yên tâm chinh phục cả đường thành phố lẫn địa hình phức tạp.\r\n\r\n \r\n\r\nĐặc điểm nổi bật\r\nThiết kế mỏng, nhẹ và chắc chắn: Cấu trúc In-Mold kết hợp vỏ ngoài polycarbonate với lớp lót EPS giúp tăng độ bền và tối ưu khả năng thông gió.\r\n\r\nHệ thống điều chỉnh Roc Loc 5 Air Mips®: Tùy chỉnh vừa vặn dễ dàng, giữ nón luôn ổn định và thoải mái. Công nghệ Mips® hỗ trợ bảo vệ khỏi các lực xoay khi xảy ra va chạm lệch góc.\r\n\r\nThoáng khí vượt trội: 25 lỗ thông gió kết hợp kênh dẫn khí bên trong giúp luồng không khí luôn lưu thông, giữ đầu bạn mát mẻ suốt hành trình.\r\n\r\nĐệm Ionic+™ kháng khuẩn: Hạn chế mùi hôi, giữ nón luôn sạch sẽ và dễ chịu.\r\n\r\nDây đeo siêu nhẹ với khóa Slimline™: Đơn giản, gọn gàng và dễ điều chỉnh.','3uzxgn','56fus5','active','2025-06-23 05:45:04','2026-03-16 23:03:36',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('sc22hi','Áo Đá Bóng Nam Adidas Messi Training','ÁO ĐÁ BÓNG NAM ADIDAS MESSI TRAINING\r\nBắt nhịp phong cách đỉnh cao cùng Áo Đá Bóng Nam Adidas Messi Training – lựa chọn chuẩn chất cho tín đồ bóng đá hiện đại. Công nghệ AEROREADY giúp kiểm soát mồ hôi, giữ sự khô thoáng trong từng pha di chuyển đầy năng lượng. Form slim fit gọn gàng, logo Messi khẳng định đam mê và cá tính sân cỏ, tiếp lửa cho bạn trên mọi mặt trận tập luyện.\r\n\r\nTHÔNG SỐ\r\nDáng ôm (Slim fit)\r\nCổ tròn (Crewneck)\r\nChất liệu: 100% polyester tái chế\r\nCông nghệ kiểm soát ẩm AEROREADY\r\nLogo Messi ở ngực','sd2dby','4e177a','active','2026-01-18 18:53:27','2026-03-16 23:03:39',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('srmc4k','Đồ Bơi Một Mảnh Nữ Speedo Solid Bound Scoop','ĐỒ BƠI MỘT MẢNH NỮ SPEEDO SOLID BOUND SCOOP\r\nThể hiện phong cách thể thao cổ điển với Đồ Bơi Một Mảnh Nữ Speedo Solid Bound Scoop. Sản phẩm nổi bật với logo Speedo đặc trưng và đường cắt tối giản nhưng tinh tế, giúp bạn tự tin khoe dáng, phù hợp với mọi xu hướng bơi lội. Được may lót toàn thân giúp che phủ tối ưu, áo tắm làm từ chất liệu Soft Swim Jersey mềm mại, mang lại cảm giác thoải mái tuyệt đối và dễ dàng vận động dưới nước.\r\n\r\nTHÔNG SỐ\r\nLớp lót đầy đủ giúp che phủ và nâng cao sự tự tin.\r\nChất liệu Soft Swim Jersey mềm mại, thoáng mát, dễ chịu khi mặc.','sgd0rk','h2v6o2','active','2025-05-30 23:38:36','2026-03-16 23:03:35',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('sxaw5y','Giáp Bảo Vệ Ống Chân Nike Merc Lite - Fa22','GIÁP BẢO VỆ ỐNG CHÂN NIKE MERC LITE - FA22\r\nGiáp Bảo Vệ Ống Chân Nike Merc Lite - Fa22 bảo vệ phần chân dưới của bạn mà không làm giảm tốc độ. Thiết kế siêu mỏng kết hợp giữa lớp đệm mềm và lớp vỏ bền chắc, giúp phân tán lực tác động trên sân.\r\n\r\nTHÔNG SỐ\r\nVỏ mỏng nhẹ, bền chắc.\r\nLớp đệm mềm có lỗ thoáng khí giúp giảm chấn động hiệu quả.\r\nỐng giữ co giãn giúp giữ miếng bảo vệ cố định và sử dụng công nghệ Dri-FIT để thấm hút mồ hôi.\r\nỐng giữ: 65% polyester / 19% cao su / 16% elastane. Vỏ: 72% K resin / 28% EVA.\r\nĐạt chứng nhận NOCSAE.\r\nHướng dẫn vệ sinh: Giặt tay.','1wyf0i','962d78','active','2025-10-31 19:41:04','2026-03-16 23:03:40',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('sysl3d','Quần Dài Thể Thao Nam Adidas Manchester United Terrace Icons Track','QUẦN DÀI THỂ THAO NAM ADIDAS MANCHESTER UNITED TERRACE ICONS TRACK\r\nKhẳng định cá tính với Quần Dài Thể Thao Nam Adidas Manchester United Terrace Icons Track mang cảm hứng từ phong cách \'terrace\' đặc trưng những năm 80. Sản phẩm được thiết kế ôm dáng, chất liệu vải mềm mại mang đến cảm giác thoải mái tối đa trong mọi hoạt động. Huy hiệu Quỷ đỏ Manchester United nổi bật cùng logo Trefoil truyền thống tạo nên diện mạo đậm chất cổ điển, cuốn hút cho bất cứ tín đồ bóng đá nào.\r\n\r\nTHÔNG SỐ\r\nThiết kế ôm dáng tôn lên vóc dáng năng động, trẻ trung\r\nEo co giãn tích hợp dây rút, dễ dàng điều chỉnh cho vừa vặn hoàn hảo\r\nChất liệu polyester tái chế thân thiện môi trường, bền bỉ và nhẹ nhàng\r\nHai túi trước tiện lợi, thoải mái mang theo vật dụng cá nhân\r\nỐng quần bo gấu giữ dáng và tạo điểm nhấn hiện đại\r\nHuy hiệu Manchester United thêu tinh xảo, khẳng định đẳng cấp fan hâm mộ','yrgs2k','4e177a','active','2024-10-28 21:41:45','2026-03-16 23:03:38',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('t4ga36','Giày Đá Bóng Dành Cho Sân Cỏ Tự Nhiên Nam Nike Phantom Luna Ii Academy','GIÀY ĐÁ BÓNG DÀNH CHO SÂN CỎ TỰ NHIÊN NAM NIKE PHANTOM LUNA II ACADEMY\r\nGiày Đá Bóng Nike Phantom Luna II Academy sẽ giúp bạn tỏa sáng trên sân cỏ. Công nghệ NikeSkin giúp tăng cường cảm giác bóng, cho phép bạn điều khiển bóng dễ dàng trong mọi điều kiện thời tiết. Đế giày với cấu trúc Cyclone 360 giúp bạn di chuyển nhanh nhẹn, dễ dàng cắt bóng và tăng tốc mà không mất thăng bằng. Sự thoải mái từ lớp lưới mềm mại bao quanh cổ chân giúp bạn tự tin thi đấu hết mình.\r\n\r\nTHÔNG SỐ\r\nCông nghệ NikeSkin tăng cảm giác bóng\r\nĐế Cyclone 360 giúp bám sân tốt, hỗ trợ di chuyển linh hoạt\r\nThiết kế cổ giày mềm mại, ôm gọn cổ chân\r\nPhù hợp với sân cỏ tự nhiên\r\nCấu trúc đinh giày tối ưu cho tốc độ và sự ổn định','eqj3j1','962d78','active','2025-07-06 23:32:11','2026-03-16 23:03:40',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('t5xz6n','Quần Dài Thể Thao Nam Adidas Real Madrid Terrace Icons Track','QUẦN DÀI THỂ THAO NAM ADIDAS REAL MADRID TERRACE ICONS TRACK\r\nHòa mình vào không khí bóng đá sôi động của thập niên 80 với Quần Dài Thể Thao Nam Adidas Real Madrid Terrace Icons Track lấy cảm hứng từ thời hoàng kim Real Madrid. Thiết kế nổi bật và tối giản, quần không chỉ sở hữu phong cách huyền thoại mà còn mang lại cảm giác mềm mại, co giãn vượt trội, cùng bo chun ấm áp cho bạn thư thái đồng hành cùng hội cổ động viên trên mọi chặng đường.\r\n\r\nTHÔNG SỐ\r\nDáng ôm gọn gàng, tôn dáng hiện đại\r\nLưng thun co giãn có dây rút tiện lợi\r\nChất liệu 100% polyester tái chế thân thiện môi trường\r\nHai túi trước tiện dụng để điện thoại hoặc đồ dùng nhỏ\r\nCổ bo chun giữ ấm và chắc chắn\r\nLogo Real Madrid thêu nổi bật, khẳng định đẳng cấp','yrgs2k','4e177a','active','2025-06-30 16:24:35','2026-03-16 23:03:36',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('t6r8hd','Banh Bóng Đá Adidas Ucl Trn','BANH BÓNG ĐÁ ADIDAS UCL TRN\r\nGhi dấu sự ra đời của một ngôi sao. Phù hợp cho những động tác lặp lại trong các buổi tập bóng đá, Banh Bóng Đá Adidas Ucl Trn có bề mặt sần mô phỏng thiết kế trái bóng đấu chính thức của mùa giải. Nếu bạn quyết tâm cải thiện lối chơi, cấu trúc khâu máy và ruột bóng bằng cao su butyl sẽ khiến bạn tập luyện ngày một ham mê.\r\n\r\nTHÔNG SỐ\r\n100% TPU (tái chế)\r\nBề mặt khâu máy\r\nRuột bóng bằng cao su butyl\r\nIn logo UEFA Champions League\r\nCần bơm hơi','rm0g8a','4e177a','active','2024-11-02 08:26:06','2026-03-16 23:03:41',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('t853xq','Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Puma Future 9 Match Tt','GIÀY ĐÁ BÓNG SÂN CỎ NHÂN TẠO NAM PUMA FUTURE 9 MATCH TT\r\nDành cho mẫu cầu thủ sáng tạo, FUTURE 9 MATCH sẽ giúp bạn bùng nổ trên sân với thiết kế hiện đại, vừa vặn và hỗ trợ tối đa. Thân giày mềm mại, nhẹ nhàng kết hợp cổ dệt co giãn ôm sát cổ chân, tạo cảm giác chắc chắn mà vẫn linh hoạt. Các vùng in nổi đặc biệt trên thân giày giúp kiểm soát bóng tốt hơn ở mọi động tác. Đế giày đa đinh thấp và lớp đệm êm ái phù hợp cho cả mặt sân cỏ tự nhiên cứng lẫn cỏ nhân tạo (2G), dễ dàng vượt qua hàng phòng ngự và kiến tạo những pha bóng đỉnh cao.\r\n\r\nTHÔNG SỐ\r\nThân giày sử dụng ít nhất 30% vật liệu tái chế, góp phần bảo vệ môi trường.\r\nLưới mesh nhẹ kết hợp cổ dệt co giãn và thiết kế cổ trung giúp giày ôm chân, linh hoạt và chắc chắn.\r\nDải hỗ trợ vòm bàn chân giúp tăng cường độ bám và sự ổn định khi di chuyển.\r\nBề mặt in nổi giúp kiểm soát bóng chính xác, tối ưu mọi pha chạm bóng và dứt điểm.\r\nForm giày vừa vặn\r\nMũi giày bo tròn tăng sự thoải mái khi vận động liên tục.\r\nThiết kế dây buộc truyền thống, dễ dàng điều chỉnh theo ý muốn.\r\nĐế cao su đa đinh cùng lớp đệm êm ái, lý tưởng cho sân cỏ tự nhiên cứng và cỏ nhân tạo 2G.\r\nThân, lót, đế và lót chân sử dụng kết hợp giữa vật liệu tổng hợp và vải cao cấp, bền bỉ và thoáng khí.','eqj3j1','a8073f','active','2025-10-31 17:03:19','2026-03-16 23:03:39',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('t8smds','Quần Ngắn Nam Adidas Own The Run','QUẦN NGẮN NAM ADIDAS OWN THE RUN\r\nQuần Ngắn Chạy Bộ Nam Adidas Own The Run là người bạn đồng hành lý tưởng cho các vận động viên chạy bộ ở mọi cấp độ, bất kể bạn đang tập luyện chạy nước rút hay đơn giản là chạy những quãng đường dài. Sản phẩm sử dụng công nghệ AEROREADY tiên tiến, giúp bạn luôn khô thoáng và thoải mái trong suốt buổi chạy, từ đó tự tin chinh phục mọi thử thách trên đường đua.\r\nTHÔNG SỐ\r\nKiểu dáng: Regular fit\r\nThun lưng có dây rút\r\nVải dệt trơn 100% polyester tái chế\r\nVải thấm hút ẩm và nhanh khô\r\nCông nghệ AEROREADY\r\nTúi zip phía trước\r\nChi tiết phản quang','m40hn6','4e177a','active','2025-07-03 12:36:47','2026-03-16 23:03:38',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('t9q6fm','Áo Thun Nam Nike Lse Club Stadium F1','ÁO THUN NAM NIKE LSE CLUB STADIUM F1\r\nÁo Thun Nam Nike Lse Club Stadium F1 nổi bật với họa tiết Swoosh ấn tượng trước và sau, mang đậm phong cách bóng rổ hiện đại. Chất liệu 100% cotton mềm mại, thấm hút, đem lại cảm giác thoải mái suốt ngày dài. Phom dáng rộng rãi, dễ phối đồ, giúp bạn tự tin từ những khoảnh khắc thường ngày đến sân đấu.\r\n\r\nTHÔNG SỐ\r\nChất liệu 100% cotton mềm mại, thấm hút mồ hôi vượt trội.\r\nCổ tròn trẻ trung, dễ dàng kết hợp với nhiều kiểu trang phục.','3pxej5','962d78','active','2025-02-12 18:37:55','2026-03-16 23:03:36',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('tbduhs',' Bộ Quần Áo Bóng chuyền Nữ Beyono Grind','','ehrxii','82c21b','active','2025-03-04 04:58:11','2026-03-16 23:03:37',5,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('tcs1fo','Vớ Thể Thao Beyono Sock VTTO1','','y5tp3j','82c21b','active','2025-03-28 03:12:56','2026-03-16 23:03:40',5,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('tikcms','Kính Bơi Người Lớn Speedo Aquapulse Pro Mirror','KÍNH BƠI NGƯỜI LỚN SPEEDO AQUAPULSE PRO MIRROR (ASIA FIT)\r\nAquapulse Pro Mirror là chiếc kính biểu tượng của Speedo dành cho vận động viên bơi lội chuyên nghiệp và thể dục ba môn phối hợp. Bắt nguồn từ sự thành công của Aquapulse Max 2 Mirror, phần kính mắt đã được nâng cấp tiêu chuẩn để đạt chất lượng cao hơn. Sử dụng công nghệ tầm nhìn IQfit™ giúp hạn chế tình trạng rò rì nước khi đeo cũng như hạn chế tạo vết hằn trên mặt. Chất liệu silicone cao cấp mềm mại ôm sát đầu nhưng không gây khó chịu, ống kính tầm nhìn rộng chống mờ, bảo vệ mắt 100% khỏi tia cực tím và hạn chế tác động của ánh nắng mặt trời, cung cấp tầm nhìn ngoại vi vượt trội giúp nhìn rõ dưới nước và thoải mái bơi lội\r\n\r\nTHÔNG SỐ\r\nChất liệu: LENS: PC, vỏ: TPE, viền: Silicone, dây đeo: Silicone','7iai8b','h2v6o2','active','2025-12-24 20:50:41','2026-03-16 23:03:40',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('tnp1dx','Giày Bóng Rổ Nam Nike Jordan Luka .77 Pf','GIÀY BÓNG RỔ NAM NIKE JORDAN LUKA .77 PF\r\nNếu không trên sân bóng rổ, bạn sẽ dễ dàng bắt gặp Luka vào những chuyến đi cắm trại khám phá thiên nhiên. Đôi Giày Bóng Rổ Nam Nike Jordan Luka .77 Pf lần này lấy cảm hứng từ sở thích ấy, với thiết kế siêu bền sẵn sàng đồng hành cùng bạn trên mọi mặt sân ngoài trời. Lớp lưới chống mài mòn kết hợp đế cao su nguyên khối giúp đôi giày “chiến đấu” tốt trên mọi mặt sân bê tông, nhựa đường, tự tin cùng bạn tỏa sáng mọi lúc, mọi nơi.\r\n\r\nTHÔNG SỐ\r\nLưới siêu bền kết hợp đế cao su toàn bộ giúp chịu lực và chống hao mòn trên các mặt sân ngoài trời.\r\nĐệm giữa hai lớp cùng cắt xẻ thông minh ở gót cho bước bật nhảy êm ái, giảm chấn hiệu quả.\r\nThân giày lưới thoáng khí giữ chân khô thoáng, dễ chịu suốt trận đấu.\r\nPhiên bản PF thiết kế form rộng, phù hợp nhiều loại bàn chân người Việt.','xijocy','962d78','active','2024-09-29 11:35:20','2026-03-16 23:03:40',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('tul286','Vợt Cầu Lông Yonex Astrox 100VA Tour','Astrox 100VA Tour là một trong những siêu phẩm mới nhất mà Yonex vừa trình làng, kế thừa tinh hoa công nghệ của dòng Astrox – biểu tượng cho lối chơi tấn công với những cú đập cầu đầy uy lực và góc đánh hiểm hóc.','50r71o','7d1050','active','2025-08-09 13:03:53','2026-03-16 23:03:36',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('txyqco','Set vợt cầu lông Lining Bladex 900 Master','“Master” trong tên gọi của Lining Bladex 900 Master chứa đựng thông điệp của nhà sản xuất về một phiên bản cao cấp nhất, thiết kế đặc biệt nhất và đỉnh cao được bổ sung vào series Lining Bladex 900','50r71o','3371b3','active','2024-12-17 04:24:27','2026-03-16 23:03:42',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('tyki3k','Quần Dài Thể Thao Nam Adidas Liverpool Fc Terrace Icons Track','QUẦN DÀI THỂ THAO NAM ADIDAS LIVERPOOL FC TERRACE ICONS TRACK\r\nQuần Dài Thể Thao Nam Adidas Liverpool Fc Terrace Icons Track giúp bạn thể hiện tinh thần đồng hành cùng Liverpool FC vượt thời gian. Thiết kế lấy cảm hứng từ phong cách sân vận động những năm 80, cùng logo Trefoil và huy hiệu câu lạc bộ cổ điển độc đáo trên hai ống quần. Chất liệu vải twill cao cấp, mềm mại và bo gấu, mang đến cảm giác thoải mái và năng động cho mọi hoạt động mỗi ngày.\r\n\r\nTHÔNG SỐ\r\nLogo Trefoil và huy hiệu CLB thêu chắc chắn\r\nDáng ôm thể thao\r\nLưng quần co giãn, dây rút điều chỉnh\r\nChất liệu: 100% polyester tái chế\r\nCó túi phía trước tiện lợi\r\nPhần gấu bo ôm gọn\r\nHuy hiệu Liverpool FC cổ điển thêu tỉ mỉ','yrgs2k','4e177a','active','2025-09-13 18:38:28','2026-03-16 23:03:38',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('u1rey4','Giày Tennis Nam Nike Court Lite 4','GIÀY TENNIS NAM NIKE COURT LITE 4\r\nDù bạn cần bứt phá, đánh bóng nhẹ nhàng hay lao mình cứu bóng, Giày Tennis Nam Nike Court Lite 4 sẽ giúp bạn luôn làm chủ thế trận. Đôi giày vừa chắc chắn vừa linh hoạt - lý tưởng cho những pha bóng kéo dài, hỗ trợ bạn di chuyển nhanh chóng và chạm đến những đường bóng tưởng chừng không thể với tới.\r\n\r\nTHÔNG SỐ\r\nGia cố cao su ở mũi giày, đặc biệt phía ngón cái giúp tăng độ bền tại vùng chịu ma sát nhiều.\r\nĐế ngoài phủ cao su chịu mài mòn toàn phần cho độ bền và độ bám vượt trội.\r\nLớp phủ tổng hợp đảm bảo hỗ trợ bên hông, giữ gót chân ổn định khi di chuyển.\r\nThân giày lưới giúp thông thoáng khí, tạo cảm giác dễ chịu khi vận động.\r\nCổ giày mềm và đệm êm quanh gót mang lại sự thoải mái cho mắt cá chân.','uicjou','962d78','active','2024-11-26 06:59:30','2026-03-16 23:03:35',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('u2faoa','Vợt Pickleball Onix Recruit Starter Kit','VỢT PICKLEBALL ONIX RECRUIT STARTER KIT\r\nBộ Vợt Pickleball Onix Recruit Starter Kit là lựa chọn lý tưởng dành cho người mới bắt đầu làm quen với môn thể thao pickleball. Bộ sản phẩm hoàn chỉnh gồm 2 vợt và 2 bóng, giúp bạn dễ dàng nhập cuộc ngay lập tức, bất kể độ tuổi hay trình độ chơi.\r\n\r\nVới thiết kế bền bỉ từ gỗ basswood 6 lớp chắc chắn, bộ vợt mang đến trải nghiệm ổn định, dễ kiểm soát, giúp bạn nhanh chóng nâng cao kỹ năng và tự tin thi đấu như các vận động viên chuyên nghiệp.\r\n\r\nTHÔNG SỐ\r\nChiều dài tay cầm: 5\"/ 12.7 cm\r\nChu vi tay cầm: 4\"/ 10.16 cm\r\nĐộ dày vợt: 0.375\"/ 0.95 cm\r\nBộ sản phẩm gồm 2 vợt và 2 bóng, sẵn sàng chơi ngay sau khi mở hộp.','lsg423','esp763','active','2025-03-12 17:33:05','2026-03-16 23:03:43',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ub7kk8','Banh Bóng Đá Nike Mercurial Fade','BANH BÓNG ĐÁ NIKE MERCURIAL FADE\r\nBóng Đá Nike Mercurial Fade là lựa chọn lý tưởng để bạn tỏa sáng và ghi bàn thắng quyết định trong các trận đấu. Với vỏ bóng được may bằng công nghệ máy may chắc chắn và ruột cao su bền bỉ, Nike Mercurial Fade mang đến sự bền lâu và khả năng chịu mài mòn cao. Thiết kế nổi bật giúp bóng giữ được hình dạng và hiệu suất tối ưu qua thời gian, giúp bạn tự tin hơn trong mỗi pha bóng. Đây chính là công cụ hoàn hảo để nâng cao phong độ và chiến thắng trong mọi trận đấu.\r\n\r\nTHÔNG SỐ\r\nThiết kế 12 panel: Cung cấp quỹ đạo bay bóng chính xác.\r\nVỏ may bằng máy: Tối ưu hóa hình dạng, cảm giác và độ bền.\r\nBầu khí cao su: Giúp duy trì áp suất và hình dạng.\r\nThành phần: 60% Cao su / 15% Polyurethane / 13% Polyester / 12% Ethylene Vinyl Acetate (EVA).','rm0g8a','962d78','active','2026-02-04 11:01:38','2026-03-16 23:03:43',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ubri1n','Áo Polo Nam Adidas Fab','ÁO POLO NAM ADIDAS FAB\r\nGiữ vững sự tập trung trong từng trận đấu với Áo Polo Nam Adidas Fab. Sản phẩm được làm từ chất liệu mềm mại, nhẹ và tích hợp công nghệ AEROREADY thấm hút mồ hôi vượt trội, giúp bạn luôn thoải mái sau từng pha bóng. Nổi bật trên ngực áo là logo 3 sọc mang đến điểm nhấn thể thao đầy phong cách.\r\n\r\nLàm từ 100% chất liệu tái chế, sản phẩm này đại diện cho một trong số rất nhiều các giải pháp của adidas hướng tới chấm dứt rác thải nhựa.\r\n\r\nTHÔNG SỐ\r\nKiểu dáng Regular Fit\r\nThiết kế cổ polo ba nút\r\n100% polyester (tái chế)\r\nCông nghệ AEROREADY','00f3pn','4e177a','active','2025-10-25 08:02:03','2026-03-16 23:03:39',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ufj8be','Vợt cầu lông Lining Axforce 90 Horse New Year 2026','Lining Axforce 90 Horse 2026 là cây vợt thuộc phiên bản giới hạn mới được ra mắt nhân dịp Tết Bính Ngọ 2026. Lấy cảm hứng từ lối chơi của VĐV hàng đầu Loh Kean Yew, cây vợt này mang đến sự tối ưu về tốc độ và sức mạnh','50r71o','3371b3','active','2025-09-23 09:52:56','2026-03-16 23:03:43',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('uhqpkt','Quần Ngắn Thể Thao Nam Adidas Messi','QUẦN NGẮN THỂ THAO NAM ADIDAS MESSI\r\nBạn là người hâm mộ Lionel Messi? Quần Ngắn Thể Thao Nam Adidas Messi sẽ giúp bạn thể hiện phong cách thể thao ngay cả khi thư giãn. Chất liệu nỉ cao cấp kết hợp với cạp quần co giãn có dây rút, mang lại sự thoải mái tối đa mọi lúc mọi nơi. Logo Messi nổi bật cùng biểu tượng Trefoil bên gấu quần tạo điểm nhấn cá tính, giúp bạn tự tin thể hiện đam mê bóng đá của mình.\r\n\r\nTHÔNG SỐ\r\nPhom dáng vừa vặn, phù hợp với nhiều dáng người\r\nCạp chun co giãn kèm dây rút dễ dàng điều chỉnh\r\nChất liệu 70% cotton, 30% polyester tái chế, mềm mại và thân thiện với môi trường\r\nTúi trước tiện lợi để đựng vật dụng cá nhân\r\nLogo Messi nổi bật, khẳng định phong cách','yrgs2k','4e177a','active','2025-01-30 23:56:00','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('umn08x','Giày Bóng Rổ Unisex Under Armour Curry Spawn Flotro','GIÀY BÓNG RỔ UNISEX UNDER ARMOUR CURRY SPAWN FLOTRO\r\nStephen Curry chia sẻ: \"Mọi thứ tôi gắn tên mình đều phải tốt - nó phải giúp bạn chơi hết mình và phải hỗ trợ sứ mệnh của chúng tôi để thay đổi cuộc chơi cho tốt đẹp hơn.\" Giày Bóng Rổ Unisex Under Armour Curry Spawn Flotro hiện thực hóa chính xác triết lý đó.\r\nĐược thiết kế với sự hợp tác của nhà vô địch NBA - Stephen Curry, Curry Spawn Flotro là đôi giày bóng rổ đỉnh cao, lý tưởng cho các cầu thủ ở mọi cấp độ.\r\n\r\nTHÔNG SỐ\r\nKiểu buộc dây: Dây buộc tiêu chuẩn\r\nThân giày đa lớp: Lưới và màng TPU\r\nLớp gia cố bên hông: Hỗ trợ các chuyển động mạnh\r\nCổ giày: Bọt mềm mại, ôm sát cổ chân\r\nLót giày: Bọt mềm mại, tăng cường sự thoải mái\r\nĐệm: Công nghệ UA Flow siêu nhẹ, êm ái\r\nĐế ngoài: UA Flow bền bỉ, linh hoạt','xijocy','1791f2','active','2025-06-08 10:16:12','2026-03-16 23:03:42',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('uqelle','Giày Đá Bóng Dành Cho Sân Cỏ Tự Nhiên Nam Adidas F50 Messi League','GIÀY ĐÁ BÓNG DÀNH CHO SÂN CỎ TỰ NHIÊN NAM ADIDAS F50 MESSI LEAGUE\r\nKết hợp cảm hứng từ phong cách Messi huyền thoại cùng thiết kế hiện đại, giày đá bóng Adidas F50 Messi League mang đến cảm giác nhẹ nhàng, linh hoạt giúp bạn tự tin bứt phá tốc độ trên sân cỏ tự nhiên. Thân giày HybridTouch mềm mại, ôm form, hỗ trợ cảm giác bóng tối ưu. Lưỡi giày linh hoạt tích hợp gia cố chắc chắn, luôn fit chân kể cả khi di chuyển nhanh. Công nghệ Sprintplate 360 lấy cảm hứng F50 nổi tiếng tăng khả năng tăng tốc, phản xạ linh hoạt quanh sân. Đinh giày liền, bám chắc tạo độ ổn định, kiểm soát trận đấu trong từng pha bóng. Logo adidas và Messi khẳng định phong cách cực chất, sẵn sàng chinh phục mọi thử thách.\r\n\r\nTHÔNG SỐ\r\nForm giày tiêu chuẩn (Regular)\r\nBuộc dây linh hoạt\r\nThân giày tổng hợp và vải dệt thoáng khí, bền bỉ\r\nLót trong vải êm ái\r\nĐế ngoài tổng hợp\r\nCông nghệ Sprintplate 360\r\nĐế đinh đính liền, không thể tháo rời','eqj3j1','4e177a','active','2026-02-01 08:12:38','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ur7z6q','Giày Tennis Unisex Asics Blade Ff 2','GIÀY TENNIS UNISEX ASICS BLADE FF 2\r\nGiày Tennis Unisex Asics Blade Ff 2 là người bạn đồng hành tuyệt vời dành cho mọi vận động viên yêu thích tốc độ và sự linh hoạt. Được thiết kế siêu nhẹ, đôi giày này giúp bạn di chuyển nhanh nhẹn, linh hoạt trong từng bước chân. Phần gót giày được nâng cao, giúp đặt bàn chân ở tư thế sẵn sàng để bứt tốc về phía trước. Đế giày với công nghệ PRECISION SOLE™ và các rãnh linh hoạt X GUIDANCE™ không chỉ đảm bảo độ bám vượt trội mà còn hỗ trợ tối đa các chuyển động đa hướng, giúp bạn tự tin chinh phục mọi thử thách trên sân.\r\n\r\nTHÔNG SỐ\r\nThiết kế phủ lớp film không đường may, nâng cao độ ôm chân và linh hoạt.\r\nCông nghệ PRECISION SOLE™ mang đến sự cân bằng hoàn hảo giữa linh hoạt, nhẹ và bám chắc.\r\nLớp lót giày sản xuất bằng công nghệ nhuộm thân thiện, giúp giảm tới 33% lượng nước và 45% lượng khí thải CO₂.\r\nCông nghệ FLYTEFOAM™ kết hợp độ rộng gót 15mm, mang lại độ êm nhẹ, hỗ trợ sẵn sàng bứt tốc.\r\nCông nghệ X-GUIDANCE™ hỗ trợ tối ưu độ linh hoạt và chuyển động đa hướng.','uicjou','3aa1e6','active','2024-12-21 20:03:00','2026-03-16 23:03:36',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('usa3fz','Joola Symmetry Pickleball Net','Lưới Pickleball đối xứng JOOLA rất phù hợp cho những ai cần sự ổn định và tính linh hoạt khi chơi. Lắp đặt lưới diễn ra nhanh chóng, chỉ mất dưới năm phút. Hệ thống căng giúp đảm bảo chiều cao chuẩn ở cả hai bên và giữa lưới.\r\n\r\nBạn không cần lo ngại về việc thiếu phụ kiện hay khó khăn trong đọc nhãn vì cột hỗ trợ được thiết kế từ một sợi dây đàn hồi duy nhất. Dù sân có trong nhà hay ngoài trời, lưới và cột đều bền chắc, chịu được va chạm khi chơi.\r\n\r\nTận hưởng những pha diễn ra thú vị mà không cần lo lắng về việc lưới bị đổ do gió. Việc tháo dỡ cũng dễ dàng và nhanh chóng, kèm theo một túi đựng tiện lợi để chứa mọi thứ.','gfwht4','0lifzq','active','2026-01-16 23:31:51','2026-03-16 23:03:43',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('uuxiv4','Chân Váy Nữ Nike Dri-Fit Victory','CHÂN VÁY NỮ NIKE DRI-FIT VICTORY\r\nChân Váy Nữ Nike Dri-Fit Victory được thiết kế với chất vải mềm mại, co giãn tuyệt đối và siêu nhanh khô, giúp bạn tự tin tập trung vào từng cú đánh. Quần shorts tích hợp bên trong có túi tiện ích giúp bạn mang theo những vật dụng cần thiết và luôn thoải mái trong mọi tư thế vận động.\r\n\r\nTHÔNG SỐ\r\nCông nghệ Nike Dri-FIT giúp thấm hút mồ hôi hiệu quả, giữ cơ thể luôn khô ráo và dễ chịu.\r\nTúi tiện dụng ở cả hai bên quần trong chứa vừa hầu hết các loại điện thoại.\r\nChất liệu cao cấp co giãn, bền đẹp, tôn dáng năng động.\r\nTích hợp quần shorts mang lại sự tự tin và thuận tiện khi di chuyển.','cf5q51','962d78','active','2025-05-19 07:06:54','2026-03-16 23:03:34',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('uwsil5','Quần Ngắn Nam Under Armour Statement','QUẦN NGẮN NAM UNDER ARMOUR STATEMENT\r\n\"Mọi sản phẩm có tên tôi đều phải tốt—phải giúp bạn chơi tốt hơn và là một phần trong sứ mệnh thay đổi cuộc chơi của chúng tôi.\" – Stephen Curry, một trong những cầu thủ bóng rổ xuất sắc nhất lịch sử NBA. Sản phẩm hợp tác mang tên Curry - Quần Ngắn Nam Under Armour Statement với chất vải bền và thoáng khí, hứa hẹn cho bạn trải nghiệm khác biệt!\r\n\r\nTHÔNG SỐ\r\nVải dệt bền và thoáng khí\r\nChất liệu hút mồ hôi và khô nhanh chóng\r\nĐai quần bọc elastic với dây rút bên ngoài\r\nTúi tay mở','j1jpkb','1791f2','active','2025-04-10 23:53:19','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('v4txu2','Mũ Bảo Hiểm Xe Đua Agilis MIPS','Giro Agilis MIPS – Mũ Bảo Hiểm Xe Đạp Đường Trường\r\nGiro Agilis MIPS mang đến sự kết hợp hoàn hảo giữa thiết kế thoáng khí và bảo vệ tối ưu cho người đi xe đường trường. Hệ thống Roc Loc 5 MIPS đảm bảo vừa vặn và an toàn, giúp bảo vệ đầu hiệu quả mà vẫn nhẹ nhàng.\r\n\r\n \r\n\r\nTính năng nổi bật\r\nThoáng khí tối ưu – 32 lỗ gió kết hợp rãnh bên trong giúp không khí lưu thông tốt.\r\nHệ thống Roc Loc 5 MIPS – Điều chỉnh vừa vặn, tăng cường bảo vệ đầu khỏi va chạm xoáy.\r\nVỏ Hardbody cứng cáp – Polycarbonate với lớp EPS In-mold bền chắc và nhẹ.\r\nTấm lót Coolfit kháng khuẩn – Giữ đầu luôn thoải mái và sạch sẽ.\r\nDây đai Slimline siêu nhẹ – Khóa nhỏ gọn, dễ thao tác và chắc chắn.','3uzxgn','56fus5','active','2024-11-03 10:19:44','2026-03-16 23:03:39',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('v5v18m','Bóng Joola Primo 100 quả','Bóng JOOLA Primo là sự lựa chọn tuyệt vời cho các giải đấu và hoạt động giải trí. Những quả bóng pickleball ngoài trời này đã được USAP công nhận, có kích thước 74mm và trọng lượng 26 gram. Thiết kế cân bằng của những quả bóng pickleball giúp giảm thiểu tình trạng lắc lư và nâng cao khả năng sử dụng với máy đánh pickleball.\r\n\r\nBộ sản phẩm gồm 100 quả bóng JOOLA Primo được kèm theo thùng chứa tiện lợi.','gfwht4','0lifzq','active','2024-12-04 09:43:47','2026-03-16 23:03:40',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('vac68y','Giày Tennis Nữ Nike Vapor Lite 3 Hard Court','GIÀY TENNIS NỮ NIKE VAPOR LITE 3 HARD COURT\r\nDòng Vapor Lite giờ đây còn nhẹ hơn bao giờ hết với phiên bản Giày Tennis Nữ Nike Vapor Lite 3 Hard Court! Nhờ vào hợp chất cao su mới ở phần đế, Vapor Lite 3 giúp bạn dễ dàng giảm tốc, đổi hướng và tăng tốc trở lại mà không hề bị nặng chân hay mất kiểm soát, mang lại cảm giác linh hoạt tối đa cho từng bước di chuyển trên sân.\r\n\r\nTHÔNG SỐ\r\nĐầu mũi làm từ cao su mới nâng cao độ bền ở vùng chịu mài mòn nhiều.\r\nLưới kỹ thuật siêu bền cho cảm giác thoáng khí và êm ái hơn lưới thông thường.\r\nThiết kế tối ưu chuyên dụng cho mặt sân cứng.\r\nĐế giữa bằng mút mềm hỗ trợ và êm ái cho bàn chân.','uicjou','962d78','active','2025-12-21 00:22:58','2026-03-16 23:03:42',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('vfha7e','Vợt Pickleball JOOLA Hyperion Pro V Ben Johns Bolt 16Mm','VỢT PICKLEBALL JOOLA HYPERION PRO V BEN JOHNS BOLT 16MM\r\nĐược thiết kế dành riêng cho những người chơi yêu thích tốc độ ra tay, tầm với vượt trội và khả năng phản xạ nhanh, Ben Johns Hyperion Pro V sở hữu kiểu dáng khí động học nổi bật cùng thân vợt thuôn dài đặc trưng của JOOLA. Cây vợt này giúp bạn luôn chủ động tấn công tại lưới và kiểm soát tốt hơn trên khắp mặt sân, nhờ thiết kế đầu vợt tối ưu hóa lực cắt không khí, mang đến trải nghiệm chơi đỉnh cao cho mọi tay vợt.\r\n\r\nTHÔNG SỐ\r\nMặt vợt sợi carbon nhám giúp tăng độ xoáy và kiểm soát bóng tối ưu.\r\nLõi vợt dày 16mm/14mm đảm bảo độ ổn định và cảm giác chắc tay khi đánh.\r\nĐạt chứng nhận UPA-A và USAP, phù hợp thi đấu chuyên nghiệp.\r\nThiết kế vợt thuôn dài cho tầm với rộng hơn và sức mạnh vượt trội.\r\nChiều dài vợt 42cm giúp mở rộng phạm vi đánh.\r\nBề ngang 19cm tối ưu sự linh hoạt khi di chuyển.\r\nCán vợt Feel-Tec bền bỉ, tạo cảm giác cầm nắm êm ái và chắc chắn.\r\nĐộ dài cán 14cm, chu vi 10,8cm/10,5cm phù hợp nhiều cỡ tay.','lsg423','0lifzq','active','2025-11-12 20:10:57','2026-03-16 23:03:43',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('vko14b','Giày Pickleball Nam Adidas Courtflash','GIÀY PICKLEBALL NAM ADIDAS COURTFLASH\r\nThể hiện phong độ đỉnh cao trên sân pickleball với đGiày Pickleball Nam Adidas Courtflash! Phần mũi được gia cố Adituff giúp chống mài mòn khi di chuyển, kết hợp cùng lớp lưới nhẹ ôm sát giúp bạn nhanh nhẹn, chủ động trong mọi pha bóng. Đế ngoài Adiwear chắc chắn tăng độ bám, dễ dàng thực hiện những bước di chuyển linh hoạt trên mọi mặt sân. Đặc biệt, giày được làm từ ít nhất 20% vật liệu tái chế, góp phần bảo vệ môi trường và chung tay giảm thiểu lượng rác thải.\r\n\r\nTHÔNG SỐ\r\nForm dáng tiêu chuẩn, tạo cảm giác vừa vặn tự nhiên.\r\nThiết kế buộc dây chắc chắn, dễ dàng điều chỉnh độ rộng.\r\nThân giày lưới thoáng khí, nhẹ nhàng giúp di chuyển linh hoạt.\r\nĐế ngoài Adiwear siêu bền, bám tốt trên sân cứng.\r\nMũi giày Adituff tăng khả năng chống mài mòn, bảo vệ chân hiệu quả.\r\nSử dụng ít nhất 20% vật liệu tái chế, thân thiện môi trường.','uicjou','4e177a','active','2024-11-17 00:30:00','2026-03-16 23:03:37',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('vl0g0c','Banh Bóng Rổ Spalding Vba Logo Outdoor','BANH BÓNG RỔ SPALDING VBA LOGO OUTDOOR\r\n\r\nNhững cú úp rổ ngoạn mục, những đường chuyền tinh tế, tất cả đều nằm trong tầm kiểm soát với Banh Bóng Rổ Spalding VBA Logo Outdoor. Trái bóng được thiết kế dành riêng cho các sân chơi ngoài trời, là người bạn đồng hành đáng tin cậy cho các tín đồ bóng rổ đường phố. Spalding, thương hiệu hàng đầu thế giới về bóng rổ, đã tạo nên một sản phẩm chất lượng đỉnh cao với độ bền bỉ, lực bám hoàn hảo và cảm giác bóng tuyệt vời, giúp bạn chinh phục mọi thử thách trên sân.\r\n \r\n\r\nTHÔNG SỐ\r\nKích thước: No-7\r\nĐược thiết kế bền bỉ để chơi ngoài trời\r\nLogo VBA bắt mắt tạo điểm nhấn thương hiệu\r\nĐộ bám và kiểm soát vượt trội để nâng cao hiệu suất\r\nĐược chế tạo để chịu được các điều kiện khắc nghiệt ngoài trời\r\nLựa chọn lý tưởng cho những người chơi muốn nâng cao kỹ năng chơi trên sân ngoài trời','wwayj1','q18zwp','active','2024-09-28 00:20:22','2026-03-16 23:03:42',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('vmpcrs','Giày bóng chuyền Beyono Limit V1','','m65tw5','82c21b','active','2025-02-08 06:25:39','2026-03-16 23:03:35',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('vsh13c','Banh Bóng Rổ Spalding Varsity Tf 150','BANH BÓNG RỔ UNISEX SPALDING VARSITY TF 150\r\nBanh bóng rổ Spalding TF-150 được chế tạo chuyên biệt với thiết kế kẹp nâng giúp người chơi cảm nhận và kiểm soát bóng tốt hơn. Sử dụng chất liệu cao su bền bỉ trên nắp cao su chắc chắn, là quả bóng lý tưởng để chơi ngoài trời.\r\n\r\nTHÔNG SỐ\r\nSử dụng chất liệu cao su bền bi\r\nPhù hợp khi sử dụng chơi ngoài trời','wwayj1','q18zwp','active','2025-11-20 03:32:46','2026-03-16 23:03:43',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('vu5isk','Giày Chạy Bộ Nam Adidas Adizero Boston 12','GIÀY CHẠY BỘ NAM ADIDAS ADIZERO BOSTON 12\r\nBoston Marathon là một giải đua danh tiếng và cũng là một mục tiêu của các vận động viên chạy bộ. Adidas đã truyền cảm hứng đó vào Giày Chạy Bộ Nam Adidas Adizero Boston 12 với thiết kế dành cho đường chạy cự ly trung bình tới cự ly dài. Đôi giày này mang đến cho giờ tập cảm giác hệt như trên đường đua thật nhờ cảm giác bùng nổ đến từ các thanh Energyrod 2.0 bằng sợi thủy tinh giúp hạn chế tiêu hao năng lượng. Giày có cấu tạo hỗ trợ tốc độ mà không kém phần bền bỉ. Thiết kế đế giữa kết hợp đệm Lightstrike Pro siêu nhẹ và phiên bản mới của đệm Lightstrike 2.0 EVA bền chắc.\r\n\r\nTHÔNG SỐ\r\nTrọng lượng: 260g\r\nKiểu dáng vừa vặn, thoải mái (Regular fit)\r\nCó dây giày\r\nThân giày bằng vải lưới siêu nhẹ\r\nLớp lót bằng vải dệt\r\nCác thanh ENERGYROD 2.0 hạn chế tiêu hao năng lượng\r\nLớp đệm Lightstrike Pro\r\nChênh lệch độ cao đế giữa: 7 mm (gót giày: 38 mm / mũi giày: 31 mm)\r\nĐế ngoài Continental™ Rubber\r\nThân giày có chứa tối thiểu 50% thành phần tái chế','lskyuc','4e177a','active','2025-08-12 14:00:34','2026-03-16 23:03:39',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('vxzsfc','Mũ Bơi Trẻ Em Speedo Printed Character','MŨ BƠI TRẺ EM SPEEDO PRINTED CHARACTER\r\nNhững vận động viên bơi lội trẻ tuổi chắc chắn sẽ yêu thích in chú rái cá biển Canada Aria đáng yêu của chúng tôi. Với thiết kế co giãn, đây sẽ là một vật dụng tuyệt vời cho các buổi học bơi và các buổi vui chơi dưới nước để bảo vệ tóc con bạn khỏi clo.\r\n\r\nTHÔNG SỐ\r\nPhù hợp cho các buổi học bơi\r\nThiết kế nhân vật đáng yêu, vui nhộn\r\nKhả năng bảo vệ tóc khỏi clo\r\nKiểu dáng thoải mái và dễ phối đồ','b38g5m','h2v6o2','active','2025-03-21 22:44:26','2026-03-16 23:03:43',5,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('w35ith','Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Mizuno α Iii Elite As','GIÀY ĐÁ BÓNG SÂN CỎ NHÂN TẠO NAM MIZUNO Α III ELITE AS\r\nDành riêng cho những cầu thủ nhanh nhất trên sân cỏ, Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Mizuno α Iii Elite As thế hệ mới giúp bạn bứt tốc mạnh mẽ nhờ thiết kế ôm chân vượt trội. Công nghệ Engineered Fit Last NEO kết hợp với thân giày dệt liền cùng lưỡi gà tích hợp mang đến cảm giác mềm mại, dễ chịu và cực kỳ vừa vặn. Đế ngoài thiết kế gai tam giác tối ưu đà lao về phía trước, cùng lớp đệm gót MIZUNO ENERZY tăng khả năng đàn hồi và hấp thụ lực tối ưu. Lót giày MIZUNO ENERZY xp SOCKLINER tạo sự êm ái và trả lại năng lượng vượt trội mà vẫn giữ trọng lượng siêu nhẹ.\r\n\r\nTHÔNG SỐ\r\nThân trên dệt liền mạch với lưỡi gà ôm sát bàn chân, tăng độ êm ái và chắc chắn.\r\nCông nghệ may chính xác trên chất liệu nhẹ, giúp khóa chân tốt và vừa vặn hoàn hảo.\r\nĐế ngoài AS bám sân mạnh mẽ và bền bỉ trong thời gian dài.\r\nĐế giữa MIZUNO ENERZY toàn bộ chiều dài mang đến cảm giác đàn hồi, giảm sốc tối ưu.\r\nLót giày MIZUNO ENERZY xp siêu nhẹ, mềm mại, trả lại lực tức thì khi di chuyển.\r\nThiết kế trọng lượng nhẹ, lý tưởng cho những cú bứt tốc và di chuyển linh hoạt.\r\nCảm giác chân trần tự nhiên, linh hoạt, dễ dàng kiểm soát bóng.\r\nGiày thân thiện môi trường với hơn 90% chất liệu tái chế ở lót và dây giày.\r\nLý tưởng cho mẫu cầu thủ tốc độ','eqj3j1','69f937','active','2026-02-17 22:27:58','2026-03-16 23:03:39',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('w37hg7','Áo Polo Nam Nike Court Advantage','ÁO POLO NAM NIKE COURT ADVANTAGE\r\nÁo Polo Nam Nike Court Advantage kiểu dáng slim-fit mang đến cho bạn sự tự tin trên sân với chất liệu co giãn 4 chiều mềm mại. Thiết kế vai cải tiến chuyên biệt cho môn tennis giúp cử động linh hoạt, hạn chế tối đa cảm giác vướng víu, cho bạn hoàn toàn tập trung vào từng cú đánh.\r\n\r\nTHÔNG SỐ\r\nCông nghệ Nike Dri-FIT giúp thấm hút mồ hôi nhanh, giữ bạn luôn khô ráo và thoải mái.\r\nChất liệu vải co giãn, thoáng khí nhẹ tênh, hạn chế bám dính vào cơ thể.\r\nĐường may vai cải tiến cho cảm giác chuyển động tự nhiên, linh hoạt tối ưu khi đánh bóng.\r\nCổ áo có nút tăng độ lịch lãm, giữ phom dáng chuyên nghiệp.\r\nGấu áo phía sau dài hơn, che phủ tốt hơn khi vận động.\r\nLogo NikeCourt nổi bật trên ngực, khẳng định phong cách thể thao thời thượng.\r\nThành phần: 89% polyester, 11% elastane; có thể giặt máy dễ dàng.','00f3pn','962d78','active','2024-10-17 10:40:16','2026-03-16 23:03:35',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('w87d9z','Giày cầu lông Yonex Comfort Z3','Phiên bản Yonex Comfort Z3 Men Đen Cam mang vẻ ngoài mạnh mẽ và hiện đại, toát lên phong cách thể thao chuyên nghiệp. Tông đen chủ đạo tạo cảm giác vững chắc, sạch sẽ, trong khi viền cam nổi bật ở đế giúp đôi giày thêm phần năng động và cuốn hút trên sân. Đây là phối màu vừa tinh tế vừa nổi bật, phù hợp với người chơi thích sự đơn giản nhưng vẫn cá tính.','ayirn2','7d1050','active','2025-03-05 05:01:59','2026-03-16 23:03:35',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('wc0srj','Giày bóng chuyền Beyono Eagle 8 - Version II','','m65tw5','82c21b','active','2025-04-02 04:04:03','2026-03-16 23:03:38',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('wdklxg','Vợt Tennis Wilson Pro Staff Precision 100','Vợt Tennis Wilson Pro Staff Precision 100\r\nLý tưởng cho những người chơi tennis giải trí muốn nâng cao trình độ, Pro Staff Precision 100 mang đến sự kết hợp giữa cảm giác thoải mái, độ kiểm soát và độ ổn định:\r\n\r\nKhung graphite mờ với công nghệ BLX: Giúp giảm rung, mang lại cảm giác đánh êm ái hơn.\r\nHệ thống phân bổ trọng lượng quanh khung (Perimeter Weighting System): Tăng độ ổn định xoắn, giúp cây vợt cân bằng hơn.\r\nĐầu vợt cỡ trung (midsize head): Mang lại cảm giác bóng tốt hơn và khả năng kiểm soát vượt trội.\r\nĐã được căng dây sẵn: Sẵn sàng sử dụng ngay khi mua.\r\nTay cầm Cushion Aire có lỗ thoáng khí: Đảm bảo cảm giác cầm nắm êm ái và chắc chắn trong suốt trận đấu.','p0d6db','p3c68s','active','2026-03-16 12:27:57','2026-03-16 23:03:43',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('we1ix2','Áo Polo Nam Adidas Club Tennis 3-Stripes','ÁO POLO NAM ADIDAS CLUB TENNIS 3-STRIPES\r\nÁo Polo Nam Adidas Club Tennis 3-Stripes thiết kế FreeLift giải phóng vai, nổi bật cùng 3 sọc cá tính. Khám phá ngay phong cách thể thao năng động!\r\n\r\nTHÔNG SỐ\r\nDáng regular fit\r\nCổ polo hai nút\r\nChất liệu: 100% polyester (recycled)\r\nThiết kế FreeLift linh hoạt, hỗ trợ vận động\r\nLưới thoáng khí dưới cánh tay','00f3pn','4e177a','active','2025-12-05 12:43:15','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ww9c66','Quần Bó Thể Thao Nữ Under Armour Launch Elite Print Ankle','QUẦN BÓ THỂ THAO NỮ UNDER ARMOUR LAUNCH ELITE PRINT ANKLE\r\nVừa vặn hoàn hảo, nâng đỡ tối ưu! Quần Bó Thể Thao Nữ Under Armour Launch Elite Print Ankle được thiết kế với chất liệu mềm mại, co giãn và thoáng khí, giúp bạn luôn thoải mái trong mỗi bước chạy. Công nghệ hút ẩm và khô nhanh giúp duy trì sự khô ráo, kết hợp với chi tiết phản quang hỗ trợ vận động trong điều kiện thiếu sáng.\r\n\r\nTHÔNG SỐ\r\nChất liệu co giãn 4 chiều, ôm sát mà không gây khó chịu\r\nCông nghệ hút ẩm, khô nhanh, giúp luôn khô thoáng\r\nLỗ thoáng khí laser, tăng cường độ thoáng ở những vùng cần thiết\r\nKhông đường may bên trong đùi, hạn chế ma sát, ngăn ngừa kích ứng\r\nTúi lưng chống nước, giữ điện thoại an toàn, không rung lắc\r\nCạp cao ôm chắc, có túi hai bên và dây rút trong, giữ cố định khi vận động\r\nCông nghệ kiểm soát mùi, giảm thiểu mùi khó chịu\r\nChi tiết phản quang, hỗ trợ chạy trong điều kiện ánh sáng yếu\r\nForm dáng: Fitted – Ôm sát nhưng vẫn thoải mái\r\nĐộ dài ống: 29 inch\r\nChất liệu: 75% Polyester / 25% Elastane','m40hn6','1791f2','active','2025-05-12 13:58:57','2026-03-16 23:03:35',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('wx7ary','Cước căng vợt cầu lông Yonex Exbolt 68','Cước căng vợt cầu lông Yonex Exbolt 68 là mẫu cước cao cấp đến từ thương hiệu thể thao hàng đầu Nhật Bản. Đây là lựa chọn hoàn hảo cho người chơi cầu lông ở mọi trình độ đang tìm kiếm sản phẩm mang lại hiệu suất vượt trội về độ bền, trợ lực và kiểm soát.','a08ffr','7d1050','active','2025-12-21 11:39:35','2026-03-16 23:03:40',5,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('wzq70p','Quần áo bóng chuyền Nam Beyono King II','','ehrxii','82c21b','active','2024-11-27 04:10:19','2026-03-16 23:03:38',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('x0282u','Quần Ngắn Thể Thao Nam Adidas Entrada26','QUẦN NGẮN THỂ THAO NAM ADIDAS ENTRADA26\r\nKhám phá ngay Quần Ngắn Thể Thao Nam Adidas Entrada26 - lựa chọn lý tưởng dành cho tín đồ bóng đá! Sản phẩm thiết kế vừa vặn, phù hợp với nhiều cấp độ người chơi, giúp bạn tự tin thể hiện phong cách thể thao năng động bất cứ lúc nào. Công nghệ Climacool giúp loại bỏ mồ hôi, giữ cho bạn luôn khô ráo và tập trung tối đa trong mọi trận đấu. Chất vải interlock co giãn mang lại cảm giác êm ái, đảm bảo thoải mái khi vận động mà vẫn giữ được nét trẻ trung, hiện đại. Dây thắt lưng bản giữa cùng dây rút dễ điều chỉnh ôm vừa vặn, tăng cường sự linh hoạt. Huy hiệu adidas thêu tinh tế tạo điểm nhấn đậm chất thương hiệu, hoàn thiện vẻ ngoài thể thao, cá tính.\r\n\r\nTHÔNG SỐ\r\nThiết kế vừa vặn năng động, phù hợp nhiều dáng người.\r\nDây rút điều chỉnh linh hoạt, ôm sát cơ thể thoải mái.\r\nChất liệu 100% polyester tái chế, thân thiện môi trường.\r\nCông nghệ CLIMACOOL thoáng mát, khô ráo suốt trận đấu.\r\nHuy hiệu adidas Badge of Sport thêu nổi bật, đậm chất thương hiệu.','yrgs2k','4e177a','active','2025-10-17 02:48:35','2026-03-16 23:03:35',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('xfxglr','Vợt Pickleball Onix Maverick','VỢT PICKLEBALL ONIX MAVERICK\r\nVợt Pickleball Onix Z3 (V2) là mẫu vợt mới nhất thuộc dòng Z Series của ONIX. Hứa hẹn sẽ trở thành một trong những lựa chọn được yêu thích nhờ hiệu suất cân bằng, mặt vợt composite và lõi polypropylene. Đây là cây vợt lý tưởng dành cho người mới bắt đầu muốn tìm kiếm một sản phẩm hiệu năng cao, trong khoảng trọng lượng tiêu chuẩn từ 213 đến 232 gram (7.5–8.2 oz).\r\n\r\nVợt có thiết kế mặt rộng (widebody) với lõi dày 14mm, giúp tạo cảm giác chắc chắn và ổn định khi đánh bóng. Mỗi cây vợt Z3 đều có viền bảo vệ cạnh (edge guard) và đạt chuẩn thi đấu của USA Pickleball, cho phép sử dụng trong các giải đấu chính thức.\r\n\r\nTHÔNG SỐ\r\nChiều dài vợt: 15.5\"/ 39.37 cm\r\nChiều rộng mặt vợt: 8.125\"/ 20.64 cm\r\nChiều dài tay cầm: 5\"/ 12.7 cm\r\nChu vi tay cầm: 4.25\"/ 10.8 cm\r\nTrọng lượng: 7.5–8.2 oz/ 213–232 gram\r\nChất liệu mặt vợt: Composite\r\nLõi vợt: Polypropylene\r\nKiểu dáng vợt: Wide Body (mặt vợt rộng)\r\nKiểu tay cầm: Tennis\r\nViền bảo vệ cạnh vợt: Có\r\nĐạt tiêu chuẩn USAPA: Có (hợp lệ thi đấu chính thức)\r\nĐộ dày vợt: 0.5\"/ 12.7 mm','lsg423','esp763','active','2025-08-30 20:18:54','2026-03-16 23:03:43',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('xx10ng','Joola Pro Pickleball Net (S)','JOOLA Pro Pickleball Net S là lưới pickleball bán cố định, chịu lực nặng, lý tưởng cho các câu lạc bộ vợt và sân sau. Khung và chân thép lớn, sơn tĩnh điện màu đen, 60mm cho phép lưới chơi tương tự như lưới pickleball âm đất. Hiệu ứng này được nhân đôi với hệ thống căng cáp thép khổ lớn. Sử dụng tay quay, hệ thống giúp nhanh chóng và dễ dàng đạt được chiều cao quy định 36” ở hai bên trong khi dây đai ở giữa đảm bảo phần giữa đạt đến mốc 34”. Dải vinyl trên cùng duy trì độ bền nhưng cũng mang lại khả năng chơi mà người chơi pickleball mong đợi tại các giải đấu và câu lạc bộ hàng đầu. Các miếng đệm cao su bảo vệ bề mặt sân dưới mỗi chân. Nếu bạn đang tìm kiếm một lưới pickleball di động, hãy xem JOOLA Pro Pickleball Net C cho phiên bản có bánh xe.','gfwht4','0lifzq','active','2025-07-14 05:10:25','2026-03-16 23:03:42',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('y1o8p1','Giày cầu lông Yonex 88 Dial 3 2025','Giày cầu lông Yonex 88 Dial 3 2025 chính hãng. Thiết kế núm xoay BOA tiện lợi, phối màu đen xanh chuối ấn tượng, hỗ trợ tốc độ và sự ổn định tối đa.','ayirn2','7d1050','active','2025-09-12 15:56:40','2026-03-16 23:03:38',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('y38eoc','Áo Đá Bóng Nam Puma Manchester City Fc Replica Sân Nhà 25/26','ÁO ĐÁ BÓNG NAM PUMA MANCHESTER CITY FC REPLICA SÂN NHÀ 25/26\r\nThể hiện bản lĩnh khác biệt như Man City với Áo Đá Bóng Nam Puma Manchester City Fc Replica Sân Nhà 25/26. Lần đầu tiên trong lịch sử CLB, chiếc áo sân nhà sở hữu thiết kế sash chéo ấn tượng cùng màu xanh truyền thống, mang dấu ấn tương lai và tôn vinh những ngày vàng son của đội bóng. Chất liệu dryCELL thấm hút mồ hôi cực tốt, giúp bạn luôn khô ráo và dễ chịu khi hoạt động mạnh. Thiết kế ôm vừa vặn, tay ngắn, chi tiết viền cong hai bên sườn tôn dáng thể thao, cùng logo PUMA và huy hiệu Manchester City sắc nét, sẵn sàng cho bất kỳ trận đấu nào.\r\n\r\nTHÔNG SỐ\r\nChất liệu dryCELL thoáng mát, hút ẩm tốt\r\nLà sản phẩm tái chế 95% từ chương trình RE:FIBRE\r\nDáng regular fit, tay ngắn\r\nĐường viền cong bên hông và dưới tay\r\nCổ tròn năng động\r\nLogo PUMA bên phải ngực\r\nHuy hiệu Manchester City bên trái ngực','sd2dby','a8073f','active','2025-07-25 20:51:32','2026-03-16 23:03:39',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('yaqxmk','Vợt Tennis Wilson Six One Tennis Racket','Vợt Tennis Wilson Six One Tennis Racket\r\nNâng tầm trận đấu của bạn với vợt tennis Six One – một lựa chọn mới trong dòng Six, được thiết kế hoàn hảo cho những người chơi đang tìm kiếm sự kết hợp giữa sức mạnh, độ kiểm soát và cảm giác bóng.\r\nĐặc điểm nổi bật:\r\n\r\nTrọng lượng nhẹ hơn so với mẫu Six LV, giúp vợt dễ điều khiển hơn và thân thiện với cánh tay, giảm áp lực khi chơi lâu.\r\nKhả năng tạo lực tốt: Cho phép bạn tăng tốc độ bóng mà vẫn duy trì độ chính xác.\r\nMật độ dây dày (string pattern kín hơn): Tăng khả năng tạo xoáy mà không làm ảnh hưởng đến kỹ thuật đánh.\r\nCushion Aire Grip: Tay cầm êm ái, tối đa sự thoải mái khi cầm nắm.\r\nVợt đã được căng sẵn dây, sẵn sàng để sử dụng ngay.\r\n\r\nSix One là sự lựa chọn lý tưởng cho người chơi trình độ trung cấp đến nâng cao, muốn cải thiện hiệu suất mà không hy sinh cảm giác và sự linh hoạt trong từng cú đánh.','p0d6db','p3c68s','active','2025-12-31 17:17:58','2026-03-16 23:03:43',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('yc4kv8','Quần Dài Nam Adidas Own The Run Aeroready','QUẦN DÀI NAM ADIDAS OWN THE RUN AEROREADY\r\nTự tin di chuyển trên đường bằng, đường điền kinh và cả đường mòn với Quần Dài Nam Adidas Own The Run Aeroready đa năng! Vải lưới kết hợp công nghệ AEROREADY giúp bạn luôn khô ráo suốt buổi chạy. Các khóa kéo ở cổ chân giúp bạn dễ dàng mang/tháo quần, đặc biệt khi kết hợp cùng quần shorts bên trong. Các túi đều có khóa an toàn, cho bạn buổi chạy hoàn toàn tập trung.\r\n\r\nSản phẩm này làm từ tối thiểu 70% chất liệu tái chế. Bằng cách tái sử dụng các chất liệu đã được tạo ra, chúng tôi góp phần giảm thiểu lãng phí và hạn chế phụ thuộc vào các nguồn tài nguyên hữu hạn, cũng như giảm phát thải từ các sản phẩm sản xuất.\r\n\r\nTHÔNG SỐ\r\nDáng regular fit\r\nCạp chun có dây rút\r\nVải lưới làm từ 86% polyester tái chế, 14% elastane\r\nCông nghệ AEROREADY siêu khô thoáng\r\nCạp cao vừa\r\nKhóa kéo ở cổ chân','m40hn6','4e177a','active','2025-01-29 01:26:20','2026-03-16 23:03:36',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('yefsn8','Túi Đựng Kính Bơi Thể Thao Nike Swim','TÚI ĐỰNG KÍNH BƠI THỂ THAO NIKE SWIM 0\r\nGiữ kính bơi của bạn được bảo quản với một chiếc hộp chống nước, linh hoạt, được thiết kế với các lỗ thông khí để đảm bảo nước có thể thoát ra. Silicone mềm mại giúp bảo vệ ống kính khỏi trầy xước, trong khi các tấm hỗ trợ tăng cường cấu trúc và độ bền.\r\n\r\nTHÔNG SỐ\r\nVật liệu chống nước và linh hoạt giúp giữ kính bơi của bạn an toàn.\r\nSilicone mềm không gây dị ứng giúp bảo vệ ống kính khỏi trầy xước.\r\nCác lỗ thông khí cho phép kính bơi \"thở\" và thoát nước.\r\nCác tấm hỗ trợ tăng cường cấu trúc và độ bền.','3myvj5','962d78','active','2025-11-26 20:07:16','2026-03-16 23:03:42',5,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ymnxoi','Mũ Lưỡi Trai Nửa Đầu Nữ Under Armour Iso-Chill Launch ','MŨ LƯỠI TRAI NỬA ĐẦU NỮ UNDER ARMOUR ISO-CHILL LAUNCH\r\nMũ Lưỡi Trai Nửa Đầu Nữ Under Armour Iso-Chill Launch mang lại sự thoải mái tối đa cho các vận động viên chạy bộ, với thiết kế nhẹ nhàng và tính năng làm mát vượt trội. Mũ được trang bị dải thấm mồ hôi Iso-Chill giúp giảm nhiệt độ cơ thể, đồng thời các lỗ thoáng khí trên vải giúp duy trì sự thông thoáng, khô ráo cho bạn suốt buổi tập.\r\n\r\nTHÔNG SỐ\r\nVải woven bền, nhẹ, có các lỗ thoáng khí và tấm lưới giúp tối ưu độ thoáng.\r\nDải thấm mồ hôi Iso-Chill làm mát da đầu, mang lại cảm giác mát mẻ.\r\nThiết kế thắt lưng thấp và dễ điều chỉnh, tránh tóc bị vướng, với lớp co giãn bên dưới.\r\nLogo phản quang giúp tăng khả năng nhìn thấy trong điều kiện ánh sáng yếu.\r\nChất liệu: 100% Polyester','j5up22','1791f2','active','2024-09-29 13:49:47','2026-03-16 23:03:43',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ynguk7','Quấn Cán Vợt Yonex','','a08ffr','7d1050','active','2024-10-24 14:09:20','2026-03-16 23:03:40',5,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ynydcq','Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Adidas Predator League Fold-Over Tongue Turf','GIÀY ĐÁ BÓNG SÂN CỎ NHÂN TẠO NAM ADIDAS PREDATOR LEAGUE FOLD-OVER TONGUE TURF\r\nKhai phá tối đa tiềm năng của bạn trên sân cỏ với Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Adidas Predator League Fold-Over Tongue Turf! Đôi giày này kết hợp lưới hiện đại và công nghệ kiểm soát bóng tối ưu, mang lại sự tự tin khi đối mặt với cầu môn. Điểm nhấn với lưỡi gà gập đặc trưng - tạo bề mặt sút bóng mượt mà, hỗ trợ bạn thực hiện những cú dứt điểm chính xác. Lớp phủ giúp kiểm soát đường bóng, đảm bảo bạn luôn đưa bóng tới đích dễ dàng. Công nghệ Nanostrike cho cảm giác ôm chân vừa vặn, nhẹ nhàng và tăng độ bám sân vượt trội. Đế giữa PowerSpine đảm bảo độ ổn định, tăng sức mạnh cho mỗi cú sút. Với adidas, bạn không chỉ chơi bóng mà còn chinh phục cuộc chơi!\r\n\r\nTHÔNG SỐ\r\nForm vừa vặn thoải mái, phù hợp cho mọi cầu thủ\r\nThiết kế dây buộc chắc chắn, dễ điều chỉnh\r\nThân giày kết hợp chất liệu tổng hợp và lưới, tối ưu độ nhẹ và mềm mại\r\nLót trong êm ái, thoáng khí suốt trận đấu\r\nĐế cao su bám sân cực tốt, chống trơn trượt\r\nCông nghệ Nanostrike tăng độ nhẹ nhàng và linh hoạt\r\nĐế giữa PowerSpine giúp ổn định bàn chân và tăng lực sút','eqj3j1','4e177a','active','2026-03-11 04:57:58','2026-03-16 23:03:36',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('ytog9d','Áo Thun Nam Nike Jordan Brand Authentic Short Sleeve Crew','ÁO THUN NAM NIKE JORDAN BRAND AUTHENTIC SHORT SLEEVE CREW\r\nÁo Thun Nam Nike Jordan Brand Authentic Short Sleeve Crew mang phong cách thể thao đậm chất Jordan, thiết kế đơn giản nhưng nổi bật. Chất liệu cotton mềm mại, thoáng mát tạo cảm giác dễ chịu khi tập luyện hay đi dạo phố.\r\n\r\nTHÔNG SỐ\r\nChất liệu: 100% cotton\r\nDễ dàng giặt máy\r\nThiết kế tay ngắn năng động\r\nPhong cách Jordan cá tính','3pxej5','962d78','active','2025-02-20 19:26:14','2026-03-16 23:03:42',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('yyfbbs','Mũ Bảo Hiểm Xe Địa Hình Radix MIPS','Giro Radix – Mũ Bảo Hiểm Xe Đạp Địa Hình Cao Cấp\r\nNón bảo hiểm Giro Radix Mips được thiết kế góc cạnh, bền chắc, phù hợp cho các cung đường địa hình và touring. Với trọng lượng siêu nhẹ cùng hệ thống thoáng khí tối ưu, Radix Mips mang đến cảm giác thoải mái cả ngày và bảo vệ an toàn tối đa.\r\nTính năng nổi bật\r\nThiết kế góc cạnh và chắc chắn – Phù hợp cho xe địa hình, cross-country và touring.\r\nTrọng lượng siêu nhẹ – Mang đến cảm giác thoải mái khi đội cả ngày.\r\nHệ thống thoáng khí tối ưu – 25 lỗ thông gió cùng rãnh bên trong giúp mát mẻ.\r\nHệ thống Roc Loc 5 MIPS – Điều chỉnh vừa vặn, tăng cường bảo vệ đầu khỏi va chạm xoáy..\r\nMiếng lưỡi trai P.O.V – 15 tùy chỉnh vị trí, bảo vệ mắt khỏi ánh sáng mặt trời.\r\nKết cấu In-Mold – Vỏ polycarbonate với lớp foam EPS, bảo vệ an toàn và nhẹ nhàng.\r\nĐệm lót Coolfit – Kháng khuẩn, nhanh khô, nâng cao trải nghiệm thoải mái.','3uzxgn','56fus5','active','2025-05-09 17:05:24','2026-03-16 23:03:39',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('yygm6r','Vợt Cầu Lông Yonex Nanoflare 700 Pro','Vợt cầu lông Yonex Nanoflare 700 Pro là cây vợt phân khúc cao cấp, thu hút mọi sự chú ý của lông thủ khi Yonex cho ra mắt bộ tứ sản phẩm.','50r71o','7d1050','active','2025-06-23 10:15:15','2026-03-16 23:03:41',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('z4qn78','Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Nike Tiempo Maestro Academy','GIÀY ĐÁ BÓNG SÂN CỎ NHÂN TẠO NAM NIKE TIEMPO MAESTRO ACADEMY\r\nHãy làm chủ từng pha bóng với Giày Đá Bóng Sân Cỏ Nhân Tạo Nam Nike Tiempo Maestro Academy – lựa chọn hoàn hảo cho những ai yêu thích cảm giác bóng chân thực và kiểm soát tối ưu. Thiết kế FlyTouch leather mềm mại giúp bạn tự tin rê dắt, chuyền và dứt điểm trên mọi mặt sân, dễ dàng xuyên phá mọi hàng thủ.\r\n\r\nTHÔNG SỐ\r\nThân giày FlyTouch siêu nhẹ, giữ cảm giác bóng ổn định dù trời mưa hay nắng.\r\nDa mềm đặc biệt ôm sát chân, vừa vặn tự nhiên, tối ưu sự êm ái mà không bị dão theo thời gian.\r\nĐế cao su được tối ưu hóa độ bám, giúp di chuyển linh hoạt trên mặt sân cỏ nhân tạo.\r\nPhù hợp cho sân cỏ nhân tạo ngắn, đáp ứng đa dạng nhu cầu sử dụng.\r\nLót giày êm ái giúp giảm áp lực, giữ chân luôn dễ chịu khi thi đấu dài lâu.\r\nƯu điểm nổi bật: tối đa khả năng kiểm soát bóng.\r\nForm tự nhiên, ôm vừa vặn cho mọi kiểu chân.\r\nĐược thiết kế riêng cho bề mặt sân cỏ nhân tạo.\r\nPhiên bản Academy – chất lượng vượt trội dành cho người chơi đam mê.','eqj3j1','962d78','active','2025-12-14 21:29:49','2026-03-16 23:03:38',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('z5sksu','Áo Thun Nam Under Armour Logo Trend','ÁO THUN UNDER ARMOUR NAM LOGO TREND\r\n\"Mọi sản phẩm mang tên tôi đều phải tốt - phải giúp bạn chơi tốt hơn\" - Stephen Curry, một trong những cầu thủ xuất sắc nhất lịch sử MBA. Chính vì thế, Áo Thun Under Armour Nam Logo Trend sản phẩm hợp tác với Stephen Curry - mang đến cho bạn sự thoải mái vượt trội, với chất liệu pha cotton siêu mềm mại.\r\n\r\nTHÔNG SỐ\r\nChất liệu vải pha cotton mềm mại mang lại sự thoải mái suốt cả ngày\r\nCổ áo bo gân\r\n60% Cotton/40% Polyester','3pxej5','1791f2','active','2025-01-11 08:37:54','2026-03-16 23:03:41',10,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('z7888y','Áo Đá Bóng Nam Adidas Sân Nhà Arsenal 25/26','ÁO ĐÁ BÓNG NAM ADIDAS SÂN NHÀ ARSENAL 25/26\r\nChiếc áo đấu sân nhà Arsenal 2024/25 mang đậm dấu ấn cổ điển với thân áo đỏ, tay áo trắng quen thuộc, kết hợp họa tiết chữ \"A\" Gothic lấy cảm hứng từ huy hiệu lịch sử của CLB. Chất liệu mềm mại cùng công nghệ AEROREADY giúp thấm hút mồ hôi, mang đến cảm giác thoải mái suốt cả trận đấu.\r\n\r\nTHÔNG SỐ\r\nDáng slim fit\r\nCổ tròn\r\n100% polyester (tái chế)\r\nAEROREADY\r\nHuy hiệu Arsenal khâu nổi','sd2dby','4e177a','active','2025-04-27 23:00:28','2026-03-16 23:03:37',25,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('z861y9','Giày Bóng Rổ Nam Under Armour Curry 4 Retro','GIÀY BÓNG RỔ NAM UNDER ARMOUR CURRY 4 RETRO - VÀNG\r\nGiày Bóng Rổ Nam Under Armour Curry 4 Retro - Sự lựa chọn hoàn hảo cho những người đam mê bóng rổ, yêu thích phong cách huyền thoại và muốn sở hữu một đôi giày hỗ trợ hiệu quả, thoải mái, mang đậm dấu ấn lịch sử. Hãy cùng Under Armour tái hiện cảm giác vô địch, chinh phục mọi thử thách trên sân đấu!\r\nTHÔNG SỐ\r\n\r\nTrọng lượng: 12 oz. (340g)\r\nThân giày với lớp đệm EVA, sợi dệt và lớp phủ tổng hợp\r\nVỏ bọc bên trong bằng vải Knit ôm sát cổ chân và bàn chân trước, mang lại cảm giác thoải mái, ổn định trong mọi tình huống\r\nĐế giày Speed Plate cung cấp sự ổn định cho các chuyển động\r\nĐệm giữa EVA đàn hồi tốt, hấp thụ lực hiệu quả, bảo vệ đôi chân, giảm chấn thương\r\nHọa tiết vân đế hình chữ X được thiết kế đặc biệt, tạo độ bám dính','xijocy','1791f2','active','2025-11-30 03:56:36','2026-03-16 23:03:40',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('za9a94','Găng Tay Thủ Môn Adidas Copa Club','GĂNG TAY THỦ MÔN ADIDAS COPA CLUB\r\nGiữ vững khung thành với cảm giác thoải mái tuyệt đối. Đôi găng tay thủ môn adidas Copa Club này có phần mu bàn tay linh hoạt, cho phép bạn cử động tự nhiên, và đai quấn cổ tay nửa vòng co giãn, giúp găng tay ôm sát tay bạn. Chất liệu latex Soft Grip ở phần lòng bàn tay mang lại độ bám bóng tuyệt vời, giúp bạn bắt bóng dễ dàng và tự tin. Phần ngón tay có kiểu ngón positive rộng rãi cho trải nghiệm không chút phân tâm.\r\n\r\nTHÔNG SỐ\r\nKiểu ngón positive\r\nChất liệu chính: Lớp laminate làm từ 65% polyester tái chế, 35% polyurethane\r\nLòng bàn tay: Latex Soft Grip\r\nĐai quấn cổ tay nửa vòng','u8jlr1','4e177a','active','2025-08-28 16:19:48','2026-03-16 23:03:39',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('zjzca3','Áo Đá Bóng Nam Adidas Manchester United Sân Nhà 25/26','ÁO ĐÁ BÓNG NAM ADIDAS MANCHESTER UNITED SÂN NHÀ 25/26\r\nÁo Đá Bóng Nam Adidas Manchester United Sân Nhà 25/26 phiên bản mới mang đến phong cách trường tồn cùng thời gian, lấy cảm hứng từ sân vận động Old Trafford lừng danh. Với hoa văn trừu tượng mô phỏng hình ảnh tại “Nhà hát của những giấc mơ” in trên tay áo, cùng logo câu lạc bộ nổi bật, mẫu áo này là lựa chọn hoàn hảo giúp bạn thể hiện tình yêu bền chặt với Quỷ đỏ. Công nghệ AEROREADY thấm hút mồ hôi giữ cho bạn luôn khô thoáng và dễ chịu, bất kể là hòa mình vào bầu không khí cuồng nhiệt trên sân nhà hay dõi theo đội bóng thân yêu từ xa.\r\n\r\nTHÔNG SỐ\r\nThiết kế ôm dáng thời trang, tôn vinh vóc dáng người mặc\r\nCổ tim lịch lãm, dễ phối nhiều phong cách\r\n100% polyester tái chế, thân thiện môi trường và bền bỉ\r\nCông nghệ AEROREADY giúp kiểm soát mồ hôi, luôn khô ráo\r\nHuy hiệu Manchester United dệt nổi đẳng cấp và sắc nét\r\nTông màu đỏ đặc trưng, thể hiện tinh thần Quỷ đỏ mạnh mẽ','sd2dby','4e177a','active','2025-10-22 15:15:39','2026-03-16 23:03:40',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('zlc3ih','Giày Bóng Chuyền Nam Asics METARISE 2 ','\nGiày METARISE™ 2 được thiết kế để giúp các vận động viên đánh biên và đối chuyền nhảy cao hơn.\n\nĐế giữa của giày có thiết kế mũi cong cao và tấm nhựa gia cố bằng sợi carbon, giúp tạo nền tảng cho những cú nhảy cao và mạnh mẽ hơn.\n\nLớp đệm FF BLAST™ PLUS ECO được tích hợp trong đế giữa để tạo độ nảy và đệm êm ái hơn, mang lại cảm giác nhảy đầy năng lượng và tiếp đất nhẹ nhàng.\n\nChúng tôi cũng cải tiến phần thân giày để hỗ trợ mắt cá chân tốt hơn. Cấu trúc MONO-SOCK™ giúp giữ chặt vùng mắt cá và gót chân, mang lại sự ổn định trong khi vẫn di chuyển theo chuyển động tự nhiên của bàn chân.\n\nXuất xứ: Vietnam\n\nThành phần: 88% SYN LEATHER 12% SYN FIBER\n\nHướng dẫn sử dụng: giặt tay & phơi tránh nắng gắt\n\nThông tin cảnh báo: Không dùng bàn chải cứng, không dùng hóa chất tẩy rửa','m65tw5','3aa1e6','active','2025-01-11 03:27:47','2026-03-16 23:03:35',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('zp5l14','Áo Thun Nam Under Armour Curry Playable 1','ÁO THUN NAM UNDER ARMOUR CURRY PLAYABLE 1\r\nÁo Thun Nam Under Armour Curry Playable 1 không chỉ mang phong cách thể thao ấn tượng mà còn hỗ trợ sứ mệnh của Stephen Curry trong việc thay đổi cuộc chơi. Chất liệu vải cotton pha siêu mềm, mang lại cảm giác thoải mái suốt cả ngày, đồng thời vẫn giữ được độ bền vượt trội. Công nghệ co giãn 4 chiều, giúp áo linh hoạt theo từng chuyển động, đảm bảo sự thoải mái tối đa. Cổ áo bo gân chắc chắn, giúp áo luôn giữ form dù vận động liên tục. Với thiết kế đơn giản nhưng mạnh mẽ, đây là chiếc áo lý tưởng cho mọi hoạt động thể thao hoặc mặc hàng ngày.\r\n\r\nTHÔNG SỐ\r\nVải cotton pha siêu mềm, mang lại cảm giác thoải mái suốt cả ngày\r\nCông nghệ co giãn 4 chiều, giúp di chuyển linh hoạt mà không bị hạn chế\r\nKhả năng thấm hút & khô nhanh, giữ cơ thể luôn thoáng mát\r\nCổ áo gân bền bỉ, giúp giữ form lâu dài dù vận động nhiều\r\nThiết kế Curry đặc biệt, thể hiện tinh thần thể thao và đam mê cháy bỏng\r\nPhù hợp cho tập luyện, dạo phố, chơi bóng rổ và mặc hàng ngày','3pxej5','1791f2','active','2025-03-15 04:55:41','2026-03-16 23:03:43',15,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('zs3c90','Áo Đạp Xe Tay Ngắn 99 SS Jersey','','4c7anp','czsd09','active','2025-02-17 18:56:47','2026-03-16 23:03:42',20,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('zsx2we','Quần Ngắn Nam Under Armour Statement','QUẦN NGẮN NAM UNDER ARMOUR STATEMENT\r\n\"Mọi sản phẩm mang tên tôi đều phải tốt - phải giúp bạn chơi tốt hơn và thay đổi cuộc chơi theo hướng tích cực\" - Stephen Curry, một trong những cầu thủ xuất sắc nhất lịch sử NBA. Mang tinh thần ấy, Quần Ngắn Nam Under Armour Statement có chất liệu vải dệt bền bỉ, nhưng vẫn thấm hút mồ hôi và thoáng khí - cho bạn tự tin trong mọi hoạt động.\r\n\r\nTHÔNG SỐ\r\nChất liệu vải dệt bền bỉ và thoáng khí, thấm hút mồ hôi và khô rất nhanh\r\nCạp chun với dây rút bên ngoài\r\nTúi hai bên tiện lợi\r\nĐộ dài (từ đáy quần đến gấu quần): 7\"\"/ ~17,8 cm\r\nTúi: Có\r\n100% Polyester','j1jpkb','1791f2','active','2025-03-23 08:06:20','2026-03-16 23:03:41',30,'2026-03-01 00:00:00','2026-12-31 23:59:59'),('zuctcy',' Túi Đựng Đồ Thể Thao Đa Năng Beyono Multi-Sport Bag','','y5tp3j','82c21b','active','2026-01-20 11:58:01','2026-03-16 23:03:37',20,'2026-03-01 00:00:00','2026-12-31 23:59:59');
